async def is_immune(m, key, channel=None):
    """
    Vérifie si un membre est immunisé contre une protection.
    Les rôles/utilisateurs immunisés ont un accès TOTAL sauf pour:
    - anti_phishing (jamais ignoré - sécurité critique)
    - anti_compromised (jamais ignoré - détection de hack)
    """
    
    # Protections CRITIQUES - JAMAIS ignorées même pour les immunisés
    # Ces protections protègent contre les comptes hackés
    critical_protections = ['anti_phishing', 'anti_compromised', 'anti_scam']
    
    if key in critical_protections:
        return False  # Personne n'est immunisé contre le phishing
    
    # Owner du serveur = toujours immunisé pour tout le reste
    if m.id == m.guild.owner_id:
        return True
    
    # Admins sont immunisés contre tout (sauf critique)
    if m.guild_permissions.administrator:
        return True
    
    # Vérifier immunité personnalisée (rôles/utilisateurs/salons)
    try:
        async with get_db() as db:
            # Utilisateurs immunisés
            async with db.execute('SELECT user_id FROM immune_users WHERE guild_id=?', (m.guild.id,)) as c:
                immune_users = [r[0] for r in await c.fetchall()]
            
            # Rôles immunisés
            async with db.execute('SELECT role_id FROM immune_roles WHERE guild_id=?', (m.guild.id,)) as c:
                immune_roles = [r[0] for r in await c.fetchall()]
            
            # Salons immunisés
            if channel:
                async with db.execute('SELECT channel_id FROM immune_channels WHERE guild_id=?', (m.guild.id,)) as c:
                    immune_channels = [r[0] for r in await c.fetchall()]
                if channel.id in immune_channels:
                    return True
        
        # Vérifier si l'utilisateur est immunisé
        is_user_immune = m.id in immune_users
        is_role_immune = any(role.id in immune_roles for role in m.roles)
        
        if is_user_immune or is_role_immune:
            return True  # Immunisé = accès total (sauf protections critiques)
            
    except Exception as ex:
        print(f"[IMMUNE ERROR] {ex}")
    
    return False


async def is_channel_immune(guild_id, channel_id):
    """Vérifie si un salon est immunisé"""
    try:
        async with get_db() as db:
            async with db.execute('SELECT channel_id FROM immune_channels WHERE guild_id=? AND channel_id=?', (guild_id, channel_id)) as c:
                return await c.fetchone() is not None
    except:
        return False

async def is_ticket_channel(channel):
    """
    Vérifie si un salon est un ticket.
    Les tickets sont immunisés contre toutes les protections SAUF anti-phishing et anti-scam.
    """
    try:
        # Vérifier dans la base de données des tickets
        async with get_db() as db:
            async with db.execute(
                'SELECT id FROM tickets WHERE channel_id=? AND status="open"',
                (channel.id,)
            ) as c:
                if await c.fetchone():
                    return True

        # Vérifier aussi par le nom du salon (backup)
        channel_name = channel.name.lower()
        if channel_name.startswith('ticket-') or channel_name.startswith('🎫'):
            return True

    except:
        pass

    return False


# ═══════════════════════════════════════════════════════════════════════════════
#  Phase 41.2 — FILTRE CENTRAL "CHATTY CHANNEL"
#  Garantit qu'un event auto ne se lance JAMAIS dans :
#  - un ticket (privé d'un autre membre)
#  - un salon d'annonce (lecture seule pour @everyone)
#  - un thread / forum / vocal / stage
#  - un salon où @everyone ne peut PAS voir ou écrire
#  - le salon arena d'un event en cours
# ═══════════════════════════════════════════════════════════════════════════════


# Blacklist de noms : si le nom contient un de ces mots, le salon est exclu
_CHATTY_BLACKLIST_KEYWORDS = (
    'ticket', 'mod-', 'mod_', 'modo', 'staff', 'admin', 'log', 'logs',
    'rules', 'règles', 'regles', 'welcome', 'bienvenue', 'goodbye',
    'annonces', 'announce', 'announcement', 'rules', 'rolereact',
    'config', 'configuration', 'private', 'privé', 'priv',
    'audit', 'webhook',
)


async def _is_chatty_channel(channel, *, allow_announce: bool = False) -> bool:
    """Garantit qu'un salon est OK pour poster un event PUBLIC.

    Conditions strictes (TOUTES doivent être vraies) :
    1. TextChannel pur (refuse Thread, Voice, Stage, Forum, Category)
    2. PAS un announcement channel (sauf si allow_announce=True)
    3. PAS NSFW (on n'envoie pas de mystery box dans #18+)
    4. PAS un ticket (vérif DB tickets + nom)
    5. PAS un salon staff/log/admin/rules/welcome (blacklist de noms)
    6. @everyone peut view_channel ET send_messages (refuse read-only)
    7. Le bot peut send_messages ET embed_links
    8. PAS le salon arena d'un event en cours
    """
    if not channel:
        return False

    # 1. Type strict : TextChannel uniquement
    if not isinstance(channel, discord.TextChannel):
        return False
    # Double-check : refus explicite des Threads
    if isinstance(channel, discord.Thread):
        return False

    # 2. Announcement
    try:
        if channel.is_news() and not allow_announce:
            return False
    except Exception:
        pass

    # 3. NSFW out (events publics doivent rester safe-for-everyone)
    try:
        if channel.is_nsfw():
            return False
    except Exception:
        pass

    # 4. Ticket (DB + nom)
    try:
        if await is_ticket_channel(channel):
            return False
    except Exception:
        pass

    # 5. Blacklist par nom
    name_low = (channel.name or '').lower()
    for kw in _CHATTY_BLACKLIST_KEYWORDS:
        if kw in name_low:
            return False

    # 6. & 7. Permissions
    if not channel.guild or not channel.guild.me:
        return False
    perms_bot = channel.permissions_for(channel.guild.me)
    if not (perms_bot.send_messages and perms_bot.embed_links):
        return False
    perms_default = channel.permissions_for(channel.guild.default_role)
    if not perms_default.view_channel:
        return False
    if not perms_default.send_messages:
        return False

    # 8. Arena d'un event en cours
    try:
        cache = _active_events_cache.get(channel.guild.id) if '_active_events_cache' in globals() else None
        if cache and cache.get('arena_channel_id') == channel.id:
            return False
    except Exception:
        pass

    return True


async def _filter_chatty_channels(channels, *, allow_announce: bool = False) -> list:
    """Filtre une liste de salons en ne gardant que ceux où on peut poster un event."""
    out = []
    for ch in channels:
        try:
            if await _is_chatty_channel(ch, allow_announce=allow_announce):
                out.append(ch)
        except Exception:
            continue
    return out

