#  🎪 PHASE 30 — SYSTÈME D'ÉVÉNEMENTS COMMUNAUTAIRES
#
#  Permet à l'owner de déclencher (auto ou manuel) des Boss Raids :
#  - Tous les salons sont MASQUÉS (overwrite view_channel=False sur @everyone)
#  - Une arène temporaire est créée
#  - Les membres attaquent le boss en cliquant ⚔️ Attaquer
#  - Récompenses : coins + équipement aléatoire (gear)
#  - À la fin, tous les salons sont RESTAURÉS dans leur état exact d'avant
#  - SÉCURITÉ : badwords/anti-spam/everyone restent actifs pendant l'event
#  - Owner et admins voient toujours tous les salons (jamais affectés)
# ═══════════════════════════════════════════════════════════════════════════════


# ── État runtime des événements (en plus de la DB) ──
# Cache rapide : { guild_id: {event_id, arena_channel_id, arena_message_id} }
_active_events_cache: dict[int, dict] = {}
# Rate-limit des attaques : { (guild_id, user_id): last_ts }
_attack_cooldown: dict[tuple[int, int], float] = {}
# Phase 31 : historique attaques récentes par event (pour combos)
# { event_id: [(timestamp, user_id), ...] } — purgé > 10s
_recent_attacks_log: dict[int, list[tuple]] = {}
# Phase 31 : compteurs in-memory pour combos par event
_event_combo_count: dict[int, int] = {}
# Phase 31 : crit streaks par (guild, user)
_crit_streaks: dict[tuple[int, int], int] = {}


def _is_event_active_time(c: dict) -> bool:
    """Phase 35 : retourne True si on est dans la fenêtre horaire active (TZ configurée).

    Par défaut : 10h-23h Europe/Paris.
    Pendant la nuit, aucun event auto n'est lancé (les gens dorment).
    """
    try:
        start_h = int(c.get('event_active_hours_start', 10) or 10)
        end_h = int(c.get('event_active_hours_end', 23) or 23)
        tz_name = c.get('event_timezone', 'Europe/Paris') or 'Europe/Paris'

        # Fallback si zoneinfo indispo : utiliser UTC + offset estimé
        if ZoneInfo is None:
            hour = datetime.now(timezone.utc).hour
            # Approximation : France = UTC+1 ou UTC+2 selon saison ; on prend +2 (été)
            hour = (hour + 2) % 24
        else:
            try:
                tz = ZoneInfo(tz_name)
                hour = datetime.now(tz).hour
            except Exception:
                hour = datetime.now(timezone.utc).hour

        # Plage normale : start <= hour < end
        if start_h <= end_h:
            return start_h <= hour < end_h
        else:
            # Plage qui traverse minuit (ex: 22h-6h)
            return hour >= start_h or hour < end_h
    except Exception as ex:
        print(f"[_is_event_active_time] {ex}")
        # En cas d'erreur, on autorise (fail-open) pour ne pas casser le système
        return True


async def _is_event_active_hour(guild_id: int) -> bool:
    """Phase 151 : wrapper async qui prend guild_id, charge cfg + appelle
    _is_event_active_time. Utilisé par npc_chatter, conv_starter, etc."""
    try:
        c = await cfg(guild_id)
        return _is_event_active_time(c)
    except Exception as ex:
        print(f"[_is_event_active_hour] {ex}")
        return True  # fail-open


async def _get_or_create_inventory(guild_id: int, user_id: int) -> dict:
    """Retourne l'inventaire d'un joueur (en crée un par défaut si absent).

    Phase 102 : ajout des slots Helmet/Boots/Accessory/Trinket.
    Try/except sur la SELECT étendue pour fallback graceful si ALTER TABLE
    n'a pas encore migré (premier boot après deploy).
    """
    async with get_db() as db:
        # Tenter SELECT avec les nouveaux slots ; fallback sur l'ancien schema
        try:
            async with db.execute(
                'SELECT hp, max_hp, weapon_json, armor_json, kills, total_damage, '
                'helmet_json, boots_json, accessory_json, trinket_json '
                'FROM player_inventory WHERE guild_id=? AND user_id=?',
                (guild_id, user_id),
            ) as cur:
                row = await cur.fetchone()
            if row:
                return {
                    'hp': row[0], 'max_hp': row[1],
                    'weapon': json.loads(row[2]) if row[2] else {},
                    'armor': json.loads(row[3]) if row[3] else {},
                    'kills': row[4], 'total_damage': row[5],
                    'helmet': json.loads(row[6]) if row[6] else {},
                    'boots': json.loads(row[7]) if row[7] else {},
                    'accessory': json.loads(row[8]) if row[8] else {},
                    'trinket': json.loads(row[9]) if row[9] else {},
                }
        except Exception:
            # Fallback : ALTER TABLE pas encore appliquée → utiliser ancien schema
            async with db.execute(
                'SELECT hp, max_hp, weapon_json, armor_json, kills, total_damage '
                'FROM player_inventory WHERE guild_id=? AND user_id=?',
                (guild_id, user_id),
            ) as cur:
                row = await cur.fetchone()
            if row:
                return {
                    'hp': row[0], 'max_hp': row[1],
                    'weapon': json.loads(row[2]) if row[2] else {},
                    'armor': json.loads(row[3]) if row[3] else {},
                    'kills': row[4], 'total_damage': row[5],
                    'helmet': {}, 'boots': {}, 'accessory': {}, 'trinket': {},
                }
        # Création par défaut
        await db.execute(
            'INSERT INTO player_inventory(guild_id, user_id, hp, max_hp, weapon_json, armor_json) VALUES(?,?,?,?,?,?)',
            (guild_id, user_id, 100, 100, '{}', '{}'),
        )
        await db.commit()
    return {
        'hp': 100, 'max_hp': 100, 'weapon': {}, 'armor': {},
        'kills': 0, 'total_damage': 0,
        'helmet': {}, 'boots': {}, 'accessory': {}, 'trinket': {},
    }


async def _log_loot(
    guild_id: int, user_id: int, item: dict, source: str = "unknown",
) -> None:
    """Phase 105 : log un drop de loot dans loot_history.

    `source` = nom de l'event qui a généré le drop (mystery_box, treasure_hunt,
    boss_raid, world_boss, etc.).
    """
    if not item or not item.get('name'):
        return
    try:
        enchant = item.get('enchant') or {}
        async with get_db() as db:
            await db.execute(
                'INSERT INTO loot_history(guild_id, user_id, item_name, item_emoji, '
                'item_slot, rarity, atk, def, crit, enchant_name, source) '
                'VALUES(?,?,?,?,?,?,?,?,?,?,?)',
                (
                    guild_id, user_id,
                    str(item.get('name', '?'))[:100],
                    str(item.get('emoji', ''))[:10],
                    str(item.get('slot', ''))[:20],
                    str(item.get('rarity', 'commune'))[:20],
                    int(item.get('atk', 0) or 0),
                    int(item.get('def', 0) or 0),
                    int(item.get('crit', 0) or 0),
                    str(enchant.get('name', '') if enchant else '')[:50],
                    str(source)[:30],
                ),
            )
            await db.commit()
    except Exception as ex:
        print(f"[_log_loot {source}] {ex}")


async def _save_inventory(guild_id: int, user_id: int, inv: dict):
    """Phase 102 : persiste aussi les 4 nouveaux slots.
    Try/except pour fallback si colonnes pas encore ajoutées."""
    async with get_db() as db:
        try:
            await db.execute(
                'UPDATE player_inventory SET '
                'hp=?, max_hp=?, weapon_json=?, armor_json=?, kills=?, total_damage=?, '
                'helmet_json=?, boots_json=?, accessory_json=?, trinket_json=?, '
                'updated_at=CURRENT_TIMESTAMP '
                'WHERE guild_id=? AND user_id=?',
                (
                    int(inv.get('hp', 100)), int(inv.get('max_hp', 100)),
                    json.dumps(inv.get('weapon', {})), json.dumps(inv.get('armor', {})),
                    int(inv.get('kills', 0)), int(inv.get('total_damage', 0)),
                    json.dumps(inv.get('helmet', {})), json.dumps(inv.get('boots', {})),
                    json.dumps(inv.get('accessory', {})), json.dumps(inv.get('trinket', {})),
                    guild_id, user_id,
                ),
            )
        except Exception:
            # Fallback : nouvelles colonnes pas dispo (ALTER TABLE pas appliquée)
            await db.execute(
                'UPDATE player_inventory SET hp=?, max_hp=?, weapon_json=?, armor_json=?, '
                'kills=?, total_damage=?, updated_at=CURRENT_TIMESTAMP '
                'WHERE guild_id=? AND user_id=?',
                (
                    int(inv.get('hp', 100)), int(inv.get('max_hp', 100)),
                    json.dumps(inv.get('weapon', {})), json.dumps(inv.get('armor', {})),
                    int(inv.get('kills', 0)), int(inv.get('total_damage', 0)),
                    guild_id, user_id,
                ),
            )
        await db.commit()


