# ═══════════════════════════════════════════════════════════════════════════════
#  Phase 39 — SMART PING SYSTEM (2 tiers opt-in)
#  Solution au problème du chicken-and-egg : les membres ont besoin de pings
#  pour voir les events, mais ne s'inscrivent pas s'ils ne savent pas.
# ═══════════════════════════════════════════════════════════════════════════════


async def _ensure_notify_role(guild, tier: str) -> Optional[discord.Role]:
    """Récupère ou crée le rôle de notification pour ce tier.

    tier : 'important' (boss raids only) ou 'all' (tous les events)
    """
    try:
        c = await cfg(guild.id)
        key = f'notify_role_{tier}_id'
        role_id = int(c.get(key, 0) or 0)
        if role_id:
            role = guild.get_role(role_id)
            if role:
                return role
            # Role configuré mais supprimé → reset et recréer
            await db_set(guild.id, key, 0)

        # Créer le rôle
        if tier == 'important':
            role_name = "🔔 Événements Important"
            color = 0xE74C3C
            reason = "Auto-créé par /notify (Phase 39 - notifications importantes)"
        else:
            role_name = "📢 Tous les Événements"
            color = 0x3498DB
            reason = "Auto-créé par /notify (Phase 39 - notifications complètes)"

        # Chercher d'abord si un rôle avec ce nom existe déjà
        existing = discord.utils.get(guild.roles, name=role_name)
        if existing:
            await db_set(guild.id, key, existing.id)
            return existing

        try:
            role = await guild.create_role(
                name=role_name,
                color=discord.Color(color),
                mentionable=True,
                hoist=False,
                reason=reason,
            )
            await db_set(guild.id, key, role.id)
            return role
        except discord.Forbidden:
            print(f"[_ensure_notify_role {tier}] perm refusée")
            return None
        except Exception as ex:
            print(f"[_ensure_notify_role {tier}] {ex}")
            return None
    except Exception as ex:
        print(f"[_ensure_notify_role outer] {ex}")
        return None


async def _get_event_mention(guild, event_type: str) -> str:
    """Phase 39 : retourne la string de mention appropriée pour ce type d'event.

    event_type : 'boss_raid' / 'treasure_hunt' / 'quiz' / 'mystery_box'
    Pour boss_raid : ping @Important + @All
    Pour autres : ping @All uniquement
    """
    try:
        mentions = []
        c = await cfg(guild.id)
        all_role_id = int(c.get('notify_role_all_id', 0) or 0)
        important_role_id = int(c.get('notify_role_important_id', 0) or 0)

        if event_type == 'boss_raid':
            # Big event → ping les 2 tiers
            if important_role_id:
                role = guild.get_role(important_role_id)
                if role:
                    mentions.append(role.mention)
            if all_role_id:
                role = guild.get_role(all_role_id)
                if role:
                    mentions.append(role.mention)
        else:
            # Light event → ping seulement le tier "all"
            if all_role_id:
                role = guild.get_role(all_role_id)
                if role:
                    mentions.append(role.mention)

        return " ".join(mentions) if mentions else ""
    except Exception as ex:
        print(f"[_get_event_mention] {ex}")
        return ""


# ═══════════════════════════════════════════════════════════════════════════════
#  Phase 40 — CIBLAGE WAKE-UP INDIVIDUEL
#  Les gros events mentionnent personnellement les membres dormants (inactifs
#  3-30 jours), même s'ils ne sont pas dans /notify. Anti-spam : max 1 mention
#  publique par membre par 48h. Les actifs (< 24h) sont JAMAIS pingués.
# ═══════════════════════════════════════════════════════════════════════════════


async def _get_wakeup_candidates(guild, max_count: int = 15) -> list[discord.Member]:
    """Phase 40 : retourne les membres dormants à réveiller en priorité.

    Critères :
    - Inactif depuis 3 jours mais moins de 30 jours (probabilité de revenir)
    - Pas mentionné publiquement dans les dernières 48h
    - N'est pas un bot
    - Est encore membre du serveur
    """
    try:
        async with get_db() as db:
            # On prend tous les membres avec activité connue
            async with db.execute(
                'SELECT user_id, last_message FROM activity_tracking '
                'WHERE guild_id=? AND last_message IS NOT NULL '
                'ORDER BY last_message DESC LIMIT 500',
                (guild.id,),
            ) as cur:
                rows = await cur.fetchall()

            # Charger les last_mentioned pour le cooldown 48h
            async with db.execute(
                'SELECT user_id, last_mentioned_at FROM wakeup_log WHERE guild_id=?',
                (guild.id,),
            ) as cur:
                wakeup_rows = {r[0]: r[1] for r in await cur.fetchall()}

        candidates_with_score = []
        now_dt = datetime.now(timezone.utc)
        cooldown_48h_cutoff = now_dt - timedelta(hours=48)

        for user_id, last_msg in rows:
            try:
                # Catégoriser
                cat = events2026.categorize_member_activity(last_msg)

                # On veut DORMANT principalement, et un peu d'ASLEEP
                if cat not in ('dormant', 'asleep'):
                    continue

                # Cooldown : pas mentionné dans les 48h
                last_ping = wakeup_rows.get(user_id)
                if last_ping:
                    try:
                        last_ping_dt = (
                            datetime.fromisoformat(last_ping)
                            if 'T' in str(last_ping)
                            else datetime.strptime(last_ping, '%Y-%m-%d %H:%M:%S').replace(tzinfo=timezone.utc)
                        )
                        if last_ping_dt > cooldown_48h_cutoff:
                            continue  # mentionné récemment, on attend
                    except Exception:
                        pass

                member = guild.get_member(user_id)
                if not member or member.bot:
                    continue

                # Score : dormant en priorité, puis asleep
                # Plus l'inactivité est récente (3-7j), plus le score est haut
                # (ils ont le plus de chances de revenir)
                try:
                    last_dt = (
                        datetime.fromisoformat(last_msg)
                        if 'T' in str(last_msg)
                        else datetime.strptime(last_msg, '%Y-%m-%d %H:%M:%S').replace(tzinfo=timezone.utc)
                    )
                    days_inactive = (now_dt - last_dt).days
                    # Score décroissant avec l'inactivité
                    # 3j → 20, 7j → 15, 14j → 10, 30j → 5
                    if days_inactive < 7:
                        score = 20
                    elif days_inactive < 14:
                        score = 15
                    elif days_inactive < 30:
                        score = 10
                    else:
                        score = 5
                except Exception:
                    score = 5

                candidates_with_score.append((member, score))
            except Exception:
                continue

        # Tirage pondéré
        if not candidates_with_score:
            return []

        # On prend les top N en mélangeant un peu (pas toujours les mêmes)
        total_w = sum(s for _, s in candidates_with_score)
        chosen = []
        remaining = list(candidates_with_score)
        for _ in range(min(max_count, len(remaining))):
            if not remaining:
                break
            current_total = sum(s for _, s in remaining)
            if current_total <= 0:
                break
            r = random.uniform(0, current_total)
            acc = 0
            for idx, (m, s) in enumerate(remaining):
                acc += s
                if r <= acc:
                    chosen.append(m)
                    remaining.pop(idx)
                    break

        return chosen
    except Exception as ex:
        print(f"[_get_wakeup_candidates] {ex}")
        return []


async def _log_wakeup_mentions(guild_id: int, member_ids: list[int]):
    """Phase 40 : enregistre que ces membres viennent d'être mentionnés."""
    if not member_ids:
        return
    try:
        async with get_db() as db:
            for uid in member_ids:
                await db.execute(
                    'INSERT INTO wakeup_log(guild_id, user_id, last_mentioned_at, mention_count) '
                    'VALUES(?,?,CURRENT_TIMESTAMP,1) '
                    'ON CONFLICT(guild_id, user_id) DO UPDATE SET '
                    'last_mentioned_at=CURRENT_TIMESTAMP, mention_count=mention_count+1',
                    (guild_id, uid),
                )
            await db.commit()
    except Exception as ex:
        print(f"[_log_wakeup_mentions] {ex}")


async def _build_wakeup_mention_line(guild, max_count: int = 3) -> str:
    """Phase 40 : construit la ligne de mentions wake-up à inclure dans un event.

    ⚠️ TOS Discord : interdiction du mass-mention. On cap STRICTEMENT à 3 max
    par défaut pour rester en règle avec l'anti-mass-mention de Discord.
    Cooldown 48h par membre via wakeup_log.

    Retourne "" si aucun candidat (pas de wake-up nécessaire).
    """
    # Hard cap : jamais plus de 3 mentions individuelles dans 1 message
    safe_max = min(max_count, 3)
    candidates = await _get_wakeup_candidates(guild, max_count=safe_max)
    if not candidates:
        return ""
    # Logger pour le cooldown 48h
    await _log_wakeup_mentions(guild.id, [m.id for m in candidates])
    mentions = " ".join(m.mention for m in candidates)
    return f"\n\n🔔 **On t'attend !** {mentions}"


# ═══════════════════════════════════════════════════════════════════════════════
#  Phase 40.1 — ECHO DISCRET DANS LES SALONS ACTIFS
#  Pour atteindre les ACTIFS qui n'ont pas le rôle notif sans les ping (TOS safe)
# ═══════════════════════════════════════════════════════════════════════════════


async def _get_top_active_channels(guild, limit: int = 3) -> list:
    """Renvoie les N salons texte les plus actifs des dernières 24h.

    Utilisé pour poster un echo discret (sans mention) d'un event en cours.
    Permet aux actifs qui discutent dans ces salons de voir l'event arriver.

    Phase 41.2 : filtre strict — JAMAIS tickets, annonces, RO, threads.
    """
    if not guild or not guild.me:
        return []
    try:
        cutoff = (datetime.now(timezone.utc) - timedelta(hours=24)).isoformat()
        async with get_db() as db:
            async with db.execute(
                "SELECT channel_id, COUNT(*) AS msgs FROM member_activity "
                "WHERE guild_id=? AND activity_type='message' AND created_at > ? "
                "GROUP BY channel_id ORDER BY msgs DESC LIMIT ?",
                (guild.id, cutoff, limit * 5),  # marge généreuse pour filtrer
            ) as cur:
                rows = await cur.fetchall()
        out = []
        for ch_id, _msgs in rows:
            ch = guild.get_channel(int(ch_id))
            # Filtre central Phase 41.2 (tickets, annonces, RO, threads OUT)
            if not await _is_chatty_channel(ch):
                continue
            # Skip aussi les salons systèmes par nom (defense en profondeur)
            if any(kw in (ch.name or '').lower() for kw in ('rules', 'règles', 'welcome', 'bienvenue', 'annonces', 'announcement')):
                continue
            out.append(ch)
            if len(out) >= limit:
                break
        return out
    except Exception as ex:
        print(f"[_get_top_active_channels] {ex}")
        return []


async def _post_event_echo(guild, arena_channel, event_kind: str, exclude_channel_ids: set = None) -> None:
    """Phase 40.1 : poste un echo DISCRET (sans mention) dans les 2 salons les
    plus actifs pour informer les actifs qu'un event vient de se lancer.

    ⚠️ AUCUN @mention dans ces messages — TOS safe, juste un lien clickable.
    Auto-delete après 30 min pour ne pas polluer.
    """
    try:
        excl = exclude_channel_ids or set()
        if arena_channel:
            excl.add(arena_channel.id)
        channels = await _get_top_active_channels(guild, limit=2)
        # Filtrer
        channels = [c for c in channels if c.id not in excl]
        if not channels:
            return

        kind_labels = {
            'boss_raid': ('⚔️', 'Un **Boss Raid** vient de commencer !'),
            'treasure_hunt': ('💎', 'Une **Chasse au Trésor** vient de démarrer !'),
            'quiz': ('🎓', 'Un **Quiz communautaire** vient de démarrer !'),
        }
        emoji, label = kind_labels.get(event_kind, ('🚨', "Un **événement** vient de commencer !"))
        arena_link = f"<#{arena_channel.id}>" if arena_channel else "le salon dédié"

        content = (
            f"{emoji} {label}\n"
            f"➡️ Rejoins-nous dans {arena_link} pour participer !\n"
            f"_Ce message disparaît dans 30 min._"
        )
        for ch in channels:
            try:
                echo_msg = await ch.send(
                    content=content,
                    allowed_mentions=discord.AllowedMentions.none(),
                    delete_after=1800,  # 30 min
                )
                # Phase 56 : register pour cleanup garanti même si bot crash
                try:
                    await _register_for_cleanup(echo_msg, 1800, f'event_echo_{event_kind}')
                except Exception:
                    pass
            except discord.Forbidden:
                continue
            except Exception as ex:
                print(f"[event echo ch={ch.id}] {ex}")
                continue
    except Exception as ex:
        print(f"[_post_event_echo] {ex}")


