# ═══════════════════════════════════════════════════════════════════════════════
#  Phase 36 — ÉVÉNEMENTS LÉGERS (Mystery Box dans salon actif)
#
#  Ces events NE MASQUENT PAS les salons. Ils s'ajoutent simplement dans
#  un salon actif et créent un micro-moment d'interaction. Tout le monde
#  peut participer. Auto-delete 5 min après pour ne pas polluer.
# ═══════════════════════════════════════════════════════════════════════════════

# Cache : message_id du mystery box → {box_data, claimed_by, claimed_at}
_mystery_boxes: dict[int, dict] = {}

# Phase 38 : refcount des salons temporairement dé-masqués pendant un raid
# (guild_id, channel_id) → count
# Permet de garder visible un salon pendant qu'un light event y est actif,
# puis le re-masquer automatiquement quand l'event finit.
_light_event_visible: dict[tuple[int, int], int] = {}


async def _temporarily_unmask_channel(guild, channel_id: int) -> bool:
    """Phase 38 : pendant un raid actif, restaure les perms @everyone d'origine
    d'un salon (depuis le snapshot DB) pour qu'un light event y soit visible.

    Retourne True si l'unmask a été appliqué, False sinon (pas de raid actif
    ou snapshot introuvable).
    """
    try:
        cache = _active_events_cache.get(guild.id, {})
        event_id = cache.get('event_id')
        if not event_id:
            return False  # pas de raid actif

        key = (guild.id, int(channel_id))
        # Refcount : si déjà unmasked, juste incrémenter
        _light_event_visible[key] = _light_event_visible.get(key, 0) + 1
        if _light_event_visible[key] > 1:
            return True  # déjà visible, refcount only

        async with get_db() as db:
            async with db.execute(
                'SELECT had_overwrite, allow_value, deny_value FROM event_channel_snapshots '
                'WHERE event_id=? AND channel_id=?',
                (event_id, channel_id),
            ) as cur:
                row = await cur.fetchone()
        if not row:
            # Pas de snapshot → on tente quand même de unmask en supprimant view_channel=False
            ch = guild.get_channel(int(channel_id))
            if ch:
                try:
                    overw = ch.overwrites_for(guild.default_role)
                    overw.view_channel = None  # neutre
                    await ch.set_permissions(guild.default_role, overwrite=overw,
                                              reason=f"Light event temp unmask (no snapshot)")
                    return True
                except Exception:
                    pass
            return False

        had_overwrite, allow_v, deny_v = row
        ch = guild.get_channel(int(channel_id))
        if not ch:
            return False

        try:
            if had_overwrite:
                perm = discord.PermissionOverwrite.from_pair(
                    discord.Permissions(int(allow_v)),
                    discord.Permissions(int(deny_v)),
                )
                await ch.set_permissions(guild.default_role, overwrite=perm,
                                          reason=f"Light event temp unmask")
            else:
                await ch.set_permissions(guild.default_role, overwrite=None,
                                          reason=f"Light event temp unmask")
            return True
        except discord.Forbidden:
            return False
        except Exception as ex:
            print(f"[_temporarily_unmask_channel] {ex}")
            return False
    except Exception as ex:
        print(f"[_temporarily_unmask_channel outer] {ex}")
        return False


async def _re_mask_channel_after_light_event(guild, channel_id: int):
    """Phase 38 : après qu'un light event finit, re-applique view_channel=False
    sur @everyone si un raid est toujours actif ET si le refcount tombe à 0.
    """
    try:
        key = (guild.id, int(channel_id))
        current = _light_event_visible.get(key, 0)
        if current <= 0:
            return  # rien à faire
        _light_event_visible[key] = current - 1
        if _light_event_visible[key] > 0:
            return  # encore des events actifs dans ce salon

        # Refcount à 0 → cleanup et re-mask
        _light_event_visible.pop(key, None)

        cache = _active_events_cache.get(guild.id, {})
        if not cache.get('event_id'):
            return  # pas de raid actif, pas besoin de re-masquer

        ch = guild.get_channel(int(channel_id))
        if not ch:
            return

        # Vérifier qu'on ne touche pas un salon spécial du raid (arène, voice zones)
        arena_id = int(cache.get('arena_channel_id', 0) or 0)
        if int(channel_id) == arena_id:
            return
        voice_zones = cache.get('voice_zones', {}) or {}
        if int(channel_id) in [int(v) for v in voice_zones.values()]:
            return

        try:
            overw = ch.overwrites_for(guild.default_role)
            overw.view_channel = False
            await ch.set_permissions(guild.default_role, overwrite=overw,
                                      reason=f"Light event ended — re-mask during raid")
        except discord.Forbidden:
            pass
        except Exception as ex:
            print(f"[_re_mask_channel_after_light_event] {ex}")
    except Exception as ex:
        print(f"[_re_mask_channel_after_light_event outer] {ex}")


class MysteryBoxView(View):
    """Bouton pour ouvrir une mystery box — premier arrivé gagne le gros lot,
    les suivants gagnent une consolation. Persistant via custom_id STABLE.

    Phase 77 : custom_id stable "mbox_open" + lookup box par i.message.id
    → bot.add_view(MysteryBoxView()) au boot capte tous les clics globalement,
    pattern identique à FlashTreasureView (Phase 76).
    """

    def __init__(self):
        super().__init__(timeout=None)
        b = Button(
            label="📦 Ouvrir la boîte !",
            style=discord.ButtonStyle.success,
            custom_id="mbox_open",
        )
        b.callback = self._on_open
        self.add_item(b)

    async def _on_open(self, i: discord.Interaction):
        # ACK immédiat
        try:
            await i.response.defer(ephemeral=True)
        except discord.InteractionResponded:
            pass
        except Exception:
            pass

        try:
            if not i.message:
                return await i.followup.send("❌ Contexte invalide.", ephemeral=True)
            # Phase 77 : lookup par i.message.id (custom_id stable)
            box = _mystery_boxes.get(i.message.id)
            if not box:
                return await i.followup.send("❌ Cette boîte n'est plus disponible.", ephemeral=True)
            if i.user.bot:
                return await i.followup.send("🤖 Les bots ne peuvent pas ouvrir.", ephemeral=True)

            already_opened = box.get('opened_by', [])
            if i.user.id in already_opened:
                return await i.followup.send("⚠️ Tu as déjà ouvert cette boîte.", ephemeral=True)

            is_first = len(already_opened) == 0
            already_opened.append(i.user.id)
            box['opened_by'] = already_opened

            # Récompenses
            if is_first:
                # Premier = full loot
                coins = int(box.get('coins', 100))
                gear = box.get('gear')
                reward_msg = f"🎉 **Tu es le premier !** Tu remportes le contenu complet :\n+`{coins}` 🪙"
                if gear:
                    inv = await _get_or_create_inventory(i.guild.id, i.user.id)
                    slot = gear.get('slot', 'weapon')
                    cur_g = inv.get(slot, {}) or {}
                    rank_order = events2026.RARITY_ORDER
                    # Phase 105 : log dans loot_history (peu importe si équipé ou pas)
                    try:
                        await _log_loot(i.guild.id, i.user.id, gear, source='mystery_box')
                    except Exception:
                        pass
                    if rank_order.get(gear.get('rarity', 'commune'), 0) >= rank_order.get(cur_g.get('rarity', 'commune'), 0):
                        # Phase 105 : préserver enchant + crit + tous les champs étendus
                        new_item = {
                            'name': gear['name'], 'rarity': gear['rarity'],
                            'emoji': gear.get('emoji', ''),
                            'atk': gear.get('atk', 0), 'def': gear.get('def', 0),
                        }
                        if gear.get('crit'):
                            new_item['crit'] = gear['crit']
                        if gear.get('enchant'):
                            new_item['enchant'] = gear['enchant']
                        inv[slot] = new_item
                        await _save_inventory(i.guild.id, i.user.id, inv)
                        ench_str = f" ✨ {gear['enchant']['emoji']}" if gear.get('enchant') else ""
                        reward_msg += f"\n+ {events2026.RARITY_EMOJIS.get(gear['rarity'], '')} **{gear['emoji']} {gear['name']}**{ench_str} ({gear['rarity']}) — équipé !"
                    else:
                        ench_str = f" ✨ {gear['enchant']['emoji']}" if gear.get('enchant') else ""
                        reward_msg += f"\n+ {events2026.RARITY_EMOJIS.get(gear['rarity'], '')} **{gear['emoji']} {gear['name']}**{ench_str} ({gear['rarity']})"
            else:
                # Les suivants : petite consolation (10% du loot)
                coins = max(10, int(box.get('coins', 100) * 0.1))
                reward_msg = (
                    f"🎁 La boîte a déjà été ouverte ! Mais le serveur te fait quand même un cadeau.\n"
                    f"+`{coins}` 🪙"
                )

            try:
                await add_coins(i.guild.id, i.user.id, coins)
            except Exception:
                pass

            # Phase 144 : roll drop saisonnier sur mystery box (10% chance)
            seasonal_drop = None
            try:
                seasonal_drop = season_module.maybe_drop_seasonal(extra_chance=0.07)
                if seasonal_drop:
                    await season_module.log_drop_claim(
                        i.guild.id, i.user.id, seasonal_drop
                    )
                    season_em = season_module.current_season().get("emoji", "🌸")
                    reward_msg += (
                        f"\n{season_em} **Drop saison :** "
                        f"{seasonal_drop['emoji']} **{seasonal_drop['name']}** "
                        f"_({seasonal_drop.get('rarity', 'rare')})_"
                    )
            except Exception as ex:
                print(f"[mystery_box seasonal_drop] {ex}")

            # Phase 150.2 : track style collector + saga contribution
            try:
                await profile_module.track_action(
                    i.guild.id, i.user.id, "mystery_open", weight=2,
                )
                await saga_module.add_contribution(
                    i.guild.id, i.user.id, 2,
                )
            except Exception as ex:
                print(f"[mystery_box profile/saga] {ex}")

            await i.followup.send(reward_msg, ephemeral=True)

            # Phase 146 : boutons de suivi
            try:
                fview = followup_module.build_followup_view(
                    i.user.id, "treasure"
                )
                if fview is not None:
                    await i.followup.send(
                        content="_💡 Continue ton aventure :_",
                        view=fview,
                        ephemeral=True,
                    )
            except Exception as ex:
                print(f"[mystery_box followup_view] {ex}")

            # Phase 77 : désactiver après 5 ouvertures via reconstruction LayoutView V2
            # (self est la view globale — on construit un layout disabled spécifique au msg)
            if len(already_opened) >= 5:
                try:
                    disabled_btn = Button(
                        label=f"📦 Boîte vide ({len(already_opened)} ouvertures)",
                        style=discord.ButtonStyle.secondary,
                        custom_id="mbox_done",
                        disabled=True,
                    )
                    box_name = box.get('box_name', 'Boîte mystère')
                    box_emoji = box.get('box_emoji', '📦')
                    box_color = box.get('box_color', 0x95A5A6)

                    class _MysteryDoneLayout(LayoutView):
                        def __init__(self):
                            super().__init__(timeout=None)
                            items = [
                                v2_title(f"{box_emoji} {box_name}"),
                                v2_subtitle("Tous les cadeaux ont été distribués"),
                                v2_divider(),
                            ]
                            items.append(_section_with_button(
                                "✅ Boîte terminée",
                                f"{len(already_opened)} membres ont ouvert cette boîte.",
                                disabled_btn,
                            ))
                            self.add_item(v2_container(*items, color=box_color))

                    await i.message.edit(view=_MysteryDoneLayout())
                except Exception:
                    pass
        except Exception as ex:
            print(f"[MysteryBoxView _on_open] {ex}")
            try:
                await i.followup.send(f"❌ Erreur : `{ex}`", ephemeral=True)
            except Exception:
                pass


async def _drop_mystery_box(guild) -> bool:
    """Drop une mystery box dans un salon actif aléatoire.

    Phase 41.2 : filtre strict — JAMAIS dans un ticket / annonce / RO / thread.
    Phase 69 : ANTI-SPAM SAME TYPE — si une mystery box est DÉJÀ active dans
    cette guild, on n'en spawne pas une 2e (éviter doublons dans le chat).
    """
    try:
        # Phase 69 : check anti-doublon même type
        # Si une mystery box est encore dans _mystery_boxes pour CETTE guild → skip
        for active_msg_id, box_data in list(_mystery_boxes.items()):
            try:
                # Vérifier que la box est dans cette guild via fetch
                # Optim : on stocke guild_id dans box_data au prochain spawn (voir below)
                if box_data.get('guild_id') == guild.id:
                    print(f"[mystery_box anti-doublon] guild={guild.id} skip (box {active_msg_id} déjà active)")
                    return False
            except Exception:
                continue

        # Trouver les salons actifs récents (jusqu'à 15 candidats)
        async with get_db() as db:
            async with db.execute(
                'SELECT channel_id, MAX(created_at) as last_active FROM member_activity '
                'WHERE guild_id=? AND activity_type=\'message\' '
                'AND datetime(created_at) > datetime("now", "-2 hours") '
                'GROUP BY channel_id ORDER BY last_active DESC LIMIT 15',
                (guild.id,),
            ) as cur:
                rows = await cur.fetchall()
        if not rows:
            return False

        # Phase 41.2 : filtrer via _is_chatty_channel (tickets/annonces/RO out)
        candidates = []
        for row in rows:
            try:
                ch = guild.get_channel(int(row[0]))
                if ch and await _is_chatty_channel(ch):
                    candidates.append(ch)
            except Exception:
                continue
        if not candidates:
            return False

        # Tirer un salon CHATTY parmi les actifs
        ch = random.choice(candidates)

        # Générer la box
        box = events2026.random_mystery_box()

        # Phase 94 AMPLIFY : Jackpot Mythique 1/100 → ×5 reward + rendu spécial
        is_jackpot = random.random() < 0.01  # 1% chance
        if is_jackpot:
            box['coins'] = int(box.get('coins', 100)) * 5
            box['emoji'] = '🌌'
            box['name'] = 'Boîte MYTHIQUE du Cosmos'
            box['color'] = 0xFFD700  # gold
            # Upgrade gear si présent
            if box.get('gear'):
                box['gear']['rarity'] = 'mythique'

        # Phase 38 : si un raid est actif, dé-masquer temporairement ce salon
        unmasked = await _temporarily_unmask_channel(guild, ch.id)

        # Phase 77 + Phase 88 fix : LayoutView V2 — button INDÉPENDANT + delegate.
        # Phase 86 extrayait depuis MysteryBoxView → double-parenting → SEND échouait.
        LIFETIME = 300  # 5 min
        box_emoji = box.get('emoji', '📦')
        box_name = box['name']
        box_color = box.get('color', 0x95A5A6)
        # Phase 94 : rarity tier visible (basé sur coins range)
        _box_coins_val = int(box.get('coins', 100))
        if is_jackpot:
            rarity_label = "🌌 **MYTHIQUE** — ×5 multiplier !"
        elif _box_coins_val >= 500:
            rarity_label = "⭐ **Légendaire**"
        elif _box_coins_val >= 250:
            rarity_label = "💜 **Épique**"
        elif _box_coins_val >= 150:
            rarity_label = "💎 **Rare**"
        else:
            rarity_label = "📦 Commune"
        try:
            class _MysteryLayout(LayoutView):
                def __init__(self):
                    super().__init__(timeout=None)
                    title_prefix = "🌌 ✨ MYTHIQUE ✨ " if is_jackpot else ""
                    items = [
                        v2_title(f"{title_prefix}{box_emoji} {box_name}"),
                        v2_subtitle(
                            "🎰 ÉVÉNEMENT 1 SUR 100 — Loot massif !" if is_jackpot
                            else "Quelqu'un a laissé tomber un cadeau dans ce salon..."
                        ),
                        v2_divider(),
                        v2_body(f"**Rareté :** {rarity_label}"),
                    ]
                    # Phase 88 : button indépendant avec callback délégué
                    open_btn = Button(
                        label="🌌 OUVRIR LA MYTHIQUE !" if is_jackpot else "📦 Ouvrir la boîte !",
                        style=discord.ButtonStyle.success if is_jackpot else discord.ButtonStyle.success,
                        custom_id="mbox_open",
                    )
                    open_btn.callback = _v2_delegate_to(MysteryBoxView, '_on_open')
                    items.append(_section_with_button(
                        "⚡ Premier ouvreur = jackpot complet",
                        "Les suivants : petite consolation\nFenêtre : **5 minutes**",
                        open_btn,
                    ))
                    self.add_item(v2_container(*items, color=box_color))

            # Phase 39 : ping le rôle "all" si configuré
            ping_str = await _get_event_mention(guild, 'mystery_box')
            send_content = ping_str if ping_str else None
            msg = await ch.send(
                content=send_content,
                view=_MysteryLayout(),
                allowed_mentions=discord.AllowedMentions(roles=True, users=False, everyone=False),
                delete_after=LIFETIME,
            )
            # Phase 69 : register persistent — survit au reboot
            try:
                await _register_for_cleanup(msg, LIFETIME, 'mystery_box')
            except Exception:
                pass
        except Exception as ex:
            print(f"[MysteryBox send V2] {ex}")
            # En cas d'erreur, on déférence l'unmask
            if unmasked:
                await _re_mask_channel_after_light_event(guild, ch.id)
            return False

        # Phase 77 : pas de rebuild custom_id (déjà stable "mbox_open")
        # MysteryBoxView est enregistrée globalement au boot.
        _mystery_boxes[msg.id] = {
            'box_name': box['name'],
            'box_emoji': box_emoji,
            'box_color': box_color,
            'coins': box['coins'],
            'gear': box.get('gear'),
            'opened_by': [],
            'guild_id': guild.id,  # Phase 69 : anti-doublon check
            'channel_id': ch.id,   # Phase 89 : stale cleanup
        }

        # Auto-cleanup state dict après 5 min (le message est supprimé par delete_after)
        async def _cleanup_state():
            await asyncio.sleep(LIFETIME + 5)
            try:
                _mystery_boxes.pop(msg.id, None)
            except Exception:
                pass
            if unmasked:
                try:
                    await _re_mask_channel_after_light_event(guild, ch.id)
                except Exception:
                    pass
        asyncio.create_task(_cleanup_state())

        try: await _track_event_engagement(guild.id, 'mystery_box', 'start')
        except Exception: pass
        print(f"[MYSTERY BOX] guild={guild.id} dropped in #{ch.name}{' (temp unmask)' if unmasked else ''}")
        return True
    except Exception as ex:
        print(f"[_drop_mystery_box] {ex}")
        return False


@tasks.loop(minutes=25)
async def light_events_dispatcher():
    """Phase 36 — lance des événements légers (mystery box) toutes les ~25 min
    dans les serveurs actifs avec event_enabled=True."""
    try:
        for guild in bot.guilds:
            try:
                c = await cfg(guild.id)
                if not c.get('event_enabled', False):
                    continue
                if not _is_event_active_time(c):
                    continue
                # 50% chance de drop à chaque tick (50% de chance toutes les 25min = ~1/50min)
                if random.random() > 0.5:
                    continue
                await _drop_mystery_box(guild)
            except Exception as ex:
                print(f"[light_events_dispatcher guild={guild.id}] {ex}")
    except Exception as ex:
        print(f"[light_events_dispatcher] {ex}")


@light_events_dispatcher.before_loop
async def _light_events_wait():
    await bot.wait_until_ready()


@tasks.loop(minutes=2)
async def event_timeout_checker():
    """Vérifie toutes les 2 min si un event a dépassé sa durée → end.

    Phase 91 HOTFIX : marque ended=1 par event_id SPÉCIFIQUE au lieu d'appeler
    _end_active_event(guild) qui kill le LATEST event (ORDER BY id DESC LIMIT 1)
    → bug : tuait les nouveaux events spawnés pendant qu'un vieux était timed-out.
    """
    try:
        now_iso = datetime.now(timezone.utc).isoformat()
        async with get_db() as db:
            async with db.execute(
                'SELECT id, guild_id FROM events WHERE ended=0 AND ends_at IS NOT NULL AND ends_at < ?',
                (now_iso,),
            ) as cur:
                rows = await cur.fetchall()
        for event_id, guild_id in rows:
            try:
                # Phase 91 : UPDATE direct par event_id (pas _end_active_event qui kill latest)
                async with get_db() as db:
                    await db.execute(
                        'UPDATE events SET ended=1 WHERE id=?', (event_id,),
                    )
                    await db.commit()
                print(f"[event_timeout_checker] event {event_id} timed out → ended")
            except Exception as ex:
                print(f"[event_timeout_checker row={event_id}] {ex}")
    except Exception as ex:
        print(f"[event_timeout_checker] {ex}")


# ─── Phase 109 : Auction Settler ─────────────────────────────────────────
# Loop qui termine les enchères expirées :
# - Transfère l'item au top_bidder (ou rend au seller si pas de bid)
# - Crédite le seller (prix - commission 5%)
# - Marque l'enchère comme 'completed' / 'unsold'

AUCTION_COMMISSION_PCT = 5  # 5% prélevé sur la vente


@tasks.loop(minutes=1)
async def auction_settler_task():
    """Phase 109 : termine les enchères expirées toutes les minutes."""
    try:
        import time as _time
        now_ts = int(_time.time())
        async with get_db() as db:
            async with db.execute(
                "SELECT id, guild_id, seller_id, slot, item_json, current_bid, "
                "top_bidder_id, bids_count "
                "FROM auctions WHERE status='active' AND ends_at <= ?",
                (now_ts,),
            ) as cur:
                rows = await cur.fetchall()

        for row in rows:
            ah_id, gid, seller_id, slot, item_json, current_bid, top_bidder_id, bids_count = row
            try:
                item = json.loads(item_json) if item_json else {}
            except Exception:
                item = {}

            try:
                if top_bidder_id and bids_count > 0:
                    # VENDU → top_bidder reçoit l'item, seller reçoit (prix - commission)
                    commission = max(1, int(current_bid * AUCTION_COMMISSION_PCT / 100))
                    seller_revenue = current_bid - commission

                    # Crédite le seller
                    await add_coins(gid, seller_id, seller_revenue)
                    # Donne l'item au top_bidder
                    buyer_inv = await _get_or_create_inventory(gid, top_bidder_id)
                    target_slot = slot if slot in events2026.EQUIPMENT_SLOTS else "weapon"
                    # Phase 112 : si le slot est occupé, on prévient le buyer en DM
                    old_item = buyer_inv.get(target_slot) or {}
                    overwritten = bool(old_item and old_item.get("name"))
                    buyer_inv[target_slot] = item
                    await _save_inventory(gid, top_bidder_id, buyer_inv)

                    async with get_db() as db:
                        await db.execute(
                            "UPDATE auctions SET status='completed' WHERE id=?",
                            (ah_id,),
                        )
                        await db.commit()
                    print(
                        f"[auction_settler] #{ah_id} VENDU à {top_bidder_id} pour {current_bid} "
                        f"(commission {commission}, seller gain {seller_revenue})"
                    )

                    # Phase 113 : incr counters seller + buyer
                    try:
                        await _incr_phase113_counter(gid, seller_id, "auctions_sold")
                        await _incr_phase113_counter(gid, top_bidder_id, "auctions_won")
                        guild_obj = bot.get_guild(gid)
                        if guild_obj:
                            await _check_phase113_badges(guild_obj, seller_id)
                            await _check_phase113_badges(guild_obj, top_bidder_id)
                    except Exception as ex:
                        print(f"[auction badge check] {ex}")

                    # Phase 112 : DM au buyer (gain + warning si écrasement)
                    try:
                        guild = bot.get_guild(gid)
                        if guild:
                            buyer = guild.get_member(top_bidder_id)
                            if buyer:
                                item_name = (item or {}).get("name", "?")
                                item_emoji = (item or {}).get("emoji", "📦")
                                msg = (
                                    f"🎉 **Tu as remporté l'enchère #{ah_id} !**\n"
                                    f"Tu reçois : {item_emoji} **{item_name}** dans ton slot `{target_slot}`.\n"
                                    f"_Coût : `{current_bid:,}` 🪙_"
                                )
                                if overwritten:
                                    old_emoji = old_item.get("emoji", "⚪")
                                    old_name = old_item.get("name", "?")
                                    msg += (
                                        f"\n\n⚠️ **Ton ancien {old_emoji} {old_name}** "
                                        f"a été remplacé. _(Garde un slot vide la prochaine fois "
                                        f"pour éviter ça !)_"
                                    )
                                try:
                                    await buyer.send(msg)
                                except Exception:
                                    pass
                            # Notif seller aussi
                            seller_m = guild.get_member(seller_id)
                            if seller_m:
                                try:
                                    await seller_m.send(
                                        f"💰 **Ton enchère #{ah_id} est vendue !**\n"
                                        f"Tu reçois : `{seller_revenue:,}` 🪙 "
                                        f"_(commission `{commission:,}` 🪙 retirée)_"
                                    )
                                except Exception:
                                    pass
                    except Exception:
                        pass
                else:
                    # INVENDU → rend l'item au seller
                    seller_inv = await _get_or_create_inventory(gid, seller_id)
                    target_slot = slot if slot in events2026.EQUIPMENT_SLOTS else "weapon"
                    # Si seller a déjà un item dans ce slot, on n'écrase pas (anti-perte)
                    if not seller_inv.get(target_slot) or not seller_inv[target_slot].get("name"):
                        seller_inv[target_slot] = item
                        await _save_inventory(gid, seller_id, seller_inv)
                    else:
                        # On le met dans le premier slot vide
                        for s in events2026.EQUIPMENT_SLOTS:
                            if not seller_inv.get(s) or not (seller_inv.get(s) or {}).get("name"):
                                seller_inv[s] = item
                                await _save_inventory(gid, seller_id, seller_inv)
                                break

                    async with get_db() as db:
                        await db.execute(
                            "UPDATE auctions SET status='unsold' WHERE id=?",
                            (ah_id,),
                        )
                        await db.commit()
                    print(f"[auction_settler] #{ah_id} INVENDU → rendu au seller {seller_id}")

                    # Phase 112 : DM seller pour notif unsold
                    try:
                        guild = bot.get_guild(gid)
                        if guild:
                            seller_m = guild.get_member(seller_id)
                            if seller_m:
                                item_name = (item or {}).get("name", "?")
                                item_emoji = (item or {}).get("emoji", "📦")
                                try:
                                    await seller_m.send(
                                        f"😔 **Ton enchère #{ah_id} n'a pas trouvé preneur.**\n"
                                        f"{item_emoji} **{item_name}** t'a été rendu.\n"
                                        f"_Essaie à un prix plus bas la prochaine fois._"
                                    )
                                except Exception:
                                    pass
                    except Exception:
                        pass
            except Exception as ex:
                print(f"[auction_settler row={ah_id}] {ex}")
    except Exception as ex:
        print(f"[auction_settler] {ex}")


@auction_settler_task.before_loop
async def _auction_settler_wait():
    await bot.wait_until_ready()


# ─── Phase 111 : Hub Live Events Tile — refresh dynamique ────────────────
#
# Une seconde "tuile" est postée dans le salon du hub (juste après le hub
# pinned). Elle affiche les events actifs en temps réel : Boss Raid, World
# Boss, Treasure Hunt, Quiz, Voice Chaos, etc. La loop edit le message
# toutes les minutes UNIQUEMENT si le contenu a changé (anti-spam edit log).

# Cache : guild_id → last_signature
_hub_live_events_sig_cache: dict = {}


async def _collect_live_events(guild_id: int) -> list:
    """Phase 111 : retourne une liste de tuples (label, emoji, line) pour
    tous les events actifs du serveur."""
    lines = []
    try:
        # Events boss raid / treasure / quiz (table `events`)
        async with get_db() as db:
            async with db.execute(
                "SELECT event_type, boss_json, started_at, ends_at "
                "FROM events WHERE guild_id=? AND ended=0 ORDER BY id DESC LIMIT 5",
                (guild_id,),
            ) as cur:
                rows = await cur.fetchall()
        for event_type, boss_json, started_at, ends_at in rows:
            label_map = {
                "boss": "👹 Boss Raid",
                "treasure": "💎 Chasse au trésor",
                "quiz": "❓ Quiz",
                "boss_raid": "👹 Boss Raid",
            }
            label = label_map.get(event_type, f"🎯 {event_type}")
            # Boss spécifique
            extra = ""
            if event_type in ("boss", "boss_raid") and boss_json:
                try:
                    boss = json.loads(boss_json)
                    name = boss.get("name", "?")
                    chp = int(boss.get("current_hp", 0) or 0)
                    mhp = int(boss.get("max_hp", 1) or 1)
                    extra = f" · **{name}** {chp}/{mhp} HP"
                except Exception:
                    pass
            lines.append(f"{label}{extra}")
    except Exception:
        pass

    # World boss hebdo
    try:
        async with get_db() as db:
            async with db.execute(
                "SELECT boss_id, hp, max_hp FROM world_bosses "
                "WHERE guild_id=? AND ended=0 ORDER BY id DESC LIMIT 1",
                (guild_id,),
            ) as cur:
                row = await cur.fetchone()
        if row:
            boss_id, hp, mhp = row
            hp = int(hp or 0)
            mhp = int(mhp or 1)
            name = boss_id or "?"
            lines.append(f"🌍 **World Boss** · {name} {hp}/{mhp} HP")
    except Exception:
        pass

    # Voice chaos (récent : appliqué dans les dernières 30 min)
    try:
        async with get_db() as db:
            async with db.execute(
                "SELECT action_id, voice_channel_id FROM voice_chaos_log "
                "WHERE guild_id=? AND reverted=0 "
                "AND applied_at > datetime('now', '-30 minutes') "
                "ORDER BY id DESC LIMIT 1",
                (guild_id,),
            ) as cur:
                row = await cur.fetchone()
        if row:
            action, vch = row
            lines.append(f"🎭 **Voice Chaos** actif · action `{action}`")
    except Exception:
        pass

    # Daily riddle
    try:
        today = datetime.now(timezone.utc).strftime("%Y-%m-%d")
        async with get_db() as db:
            async with db.execute(
                "SELECT first_winner_id FROM daily_riddles_log "
                "WHERE guild_id=? AND day=?",
                (guild_id, today),
            ) as cur:
                row = await cur.fetchone()
        if row is not None:
            first_winner_id = row[0]
            if not first_winner_id:
                lines.append("🧩 **Énigme du jour** disponible — premier arrivé = jackpot !")
    except Exception:
        pass

    # Flash treasure
    try:
        async with get_db() as db:
            async with db.execute(
                "SELECT id FROM flash_treasures WHERE guild_id=? AND ended=0 "
                "ORDER BY id DESC LIMIT 1",
                (guild_id,),
            ) as cur:
                row = await cur.fetchone()
        if row:
            lines.append("💰 **Flash Treasure** spawn actif")
    except Exception:
        pass

    # Auctions actives (Phase 109)
    try:
        async with get_db() as db:
            async with db.execute(
                "SELECT COUNT(*) FROM auctions WHERE guild_id=? AND status='active'",
                (guild_id,),
            ) as cur:
                row = await cur.fetchone()
        if row and row[0]:
            count = int(row[0])
            lines.append(f"🔨 **{count} enchère(s) Maison des enchères** en cours")
    except Exception:
        pass

    return lines


class HubLiveEventsLayoutV2(LayoutView):
    """Phase 111 : panel Live Events, refreshable, posté juste après le hub.

    Pas de boutons interactifs (juste de l'info). Custom_ids stables not needed.
    """

    def __init__(self, event_lines: list, last_updated_ts: int):
        super().__init__(timeout=None)
        items = []
        items.append(v2_title("📡  EVENTS EN COURS"))
        items.append(v2_subtitle(
            f"Actualisé <t:{last_updated_ts}:R>  ·  refresh auto chaque minute"
        ))
        items.append(v2_divider())
        if event_lines:
            items.append(v2_body("**╔═══ 🔥  ACTIF MAINTENANT  ═══╗**"))
            items.append(v2_body("\n".join(f"• {line}" for line in event_lines)))
        else:
            items.append(v2_body(
                "**╔═══ 😴  SILENCE…  ═══╗**\n"
                "_Aucun event en cours pour le moment._\n"
                "_Reste actif — un boss/chasse/quiz peut spawn à tout moment !_"
            ))
        items.append(v2_divider())
        items.append(v2_body(
            "_💡 Utilise les boutons du panneau du dessus pour participer dès qu'un event apparaît._"
        ))
        self.add_item(v2_container(*items, color=0xE74C3C if event_lines else 0x95A5A6))


@tasks.loop(minutes=1)
async def hub_live_events_refresh_task():
    """Phase 111 : refresh la tuile Live Events de chaque guild dont le hub
    est installé. Anti-spam : edit seulement si la signature a changé."""
    try:
        import time as _time
        for guild in bot.guilds:
            try:
                cfg_d = await db_get(guild.id)
                hub_ch_id = int(cfg_d.get("hub_channel", 0) or 0)
                if not hub_ch_id:
                    continue
                channel = guild.get_channel(hub_ch_id)
                if not channel:
                    continue

                # Collecter les events actifs
                lines = await _collect_live_events(guild.id)
                sig = "|".join(lines) if lines else "_empty_"

                # Anti-spam edit : si la signature n'a pas changé, on skip
                if _hub_live_events_sig_cache.get(guild.id) == sig:
                    continue

                live_msg_id = int(cfg_d.get("hub_live_events_msg_id", 0) or 0)
                now_ts = int(_time.time())
                view = HubLiveEventsLayoutV2(lines, now_ts)

                if live_msg_id:
                    # Edit existing
                    try:
                        msg = await channel.fetch_message(live_msg_id)
                        await msg.edit(view=view)
                        _hub_live_events_sig_cache[guild.id] = sig
                    except (discord.NotFound, discord.Forbidden):
                        # Re-poste
                        try:
                            msg = await channel.send(view=view)
                            await db_set(guild.id, "hub_live_events_msg_id", msg.id)
                            _hub_live_events_sig_cache[guild.id] = sig
                        except Exception as ex:
                            print(f"[hub_live_events guild={guild.id} resend] {ex}")
                    except Exception as ex:
                        print(f"[hub_live_events guild={guild.id} edit] {ex}")
                else:
                    # Premier post
                    try:
                        msg = await channel.send(view=view)
                        await db_set(guild.id, "hub_live_events_msg_id", msg.id)
                        _hub_live_events_sig_cache[guild.id] = sig
                    except Exception as ex:
                        print(f"[hub_live_events guild={guild.id} first post] {ex}")
            except Exception as ex:
                print(f"[hub_live_events_refresh_task guild={guild.id}] {ex}")
    except Exception as ex:
        print(f"[hub_live_events_refresh_task] {ex}")


@hub_live_events_refresh_task.before_loop
async def _hub_live_events_refresh_wait():
    await bot.wait_until_ready()


# ═══════════════════════════════════════════════════════════════════════════════
#  Phase 89 — STALE EVENT CLEANUP
#  Détecte les events dont le message a été supprimé manuellement (souris user)
#  et nettoie l'état du bot. Sinon l'anti-doublon Phase 69 bloque les nouveaux
#  spawns indéfiniment ("plus aucun event n'apparaît").
# ═══════════════════════════════════════════════════════════════════════════════
@tasks.loop(minutes=3)
async def stale_event_cleanup():
    """Phase 89 : pour chaque event actif (DB + in-memory), tente de fetch le
    message. Si NotFound → suppression manuelle détectée → cleanup state.

    Couverture :
    - DB events (Boss Raid + Treasure + Quiz) → arena_message_id
    - DB world_bosses → arena_message_id
    - DB flash_treasures → message_id
    - _mystery_boxes dict (in-mem) → msg.id + channel_id
    - _gn_event_state dict (in-mem) → msg.id + channel_id
    """
    try:
        # ─── 1. DB events (Boss Raid + Treasure + Quiz) ────────────────────
        try:
            async with get_db() as db:
                async with db.execute(
                    'SELECT id, guild_id, arena_channel_id, arena_message_id, event_type '
                    'FROM events WHERE ended=0 AND arena_message_id IS NOT NULL'
                ) as cur:
                    rows = await cur.fetchall()
            for event_id, guild_id, ch_id, msg_id, etype in rows:
                try:
                    guild = bot.get_guild(int(guild_id))
                    if not guild:
                        async with get_db() as db:
                            await db.execute('UPDATE events SET ended=1 WHERE id=?', (event_id,))
                            await db.commit()
                        continue
                    ch = guild.get_channel(int(ch_id)) if ch_id else None
                    if not ch:
                        async with get_db() as db:
                            await db.execute('UPDATE events SET ended=1 WHERE id=?', (event_id,))
                            await db.commit()
                        continue
                    try:
                        await ch.fetch_message(int(msg_id))
                    except discord.NotFound:
                        # Phase 91 HOTFIX : UPDATE direct par event_id.
                        # NE PAS appeler _end_active_event(guild) qui kill le
                        # LATEST event (ORDER BY id DESC LIMIT 1) — donc tue
                        # le NOUVEAU event qui vient de spawn !
                        print(f"[stale_cleanup] event {event_id} ({etype}) msg supprimé → mark ended")
                        async with get_db() as db:
                            await db.execute(
                                'UPDATE events SET ended=1 WHERE id=?', (event_id,),
                            )
                            await db.commit()
                    except discord.Forbidden:
                        pass  # Pas la perm de fetch → laisser tel quel
                    except Exception:
                        pass
                except Exception as ex:
                    print(f"[stale_cleanup events row={event_id}] {ex}")
        except Exception as ex:
            print(f"[stale_cleanup events block] {ex}")

        # ─── 2. DB world_bosses ────────────────────────────────────────────
        try:
            async with get_db() as db:
                async with db.execute(
                    'SELECT id, guild_id, arena_channel_id, arena_message_id '
                    'FROM world_bosses WHERE ended=0 AND arena_message_id IS NOT NULL'
                ) as cur:
                    rows = await cur.fetchall()
            for wb_id, guild_id, ch_id, msg_id in rows:
                try:
                    guild = bot.get_guild(int(guild_id))
                    if not guild:
                        async with get_db() as db:
                            await db.execute('UPDATE world_bosses SET ended=1 WHERE id=?', (wb_id,))
                            await db.commit()
                        continue
                    ch = guild.get_channel(int(ch_id)) if ch_id else None
                    if not ch:
                        async with get_db() as db:
                            await db.execute('UPDATE world_bosses SET ended=1 WHERE id=?', (wb_id,))
                            await db.commit()
                        continue
                    try:
                        await ch.fetch_message(int(msg_id))
                    except discord.NotFound:
                        # Phase 91 HOTFIX : UPDATE direct (skip _end_world_boss
                        # qui distribuerait des rewards pour un event abandonné).
                        print(f"[stale_cleanup] world_boss {wb_id} msg supprimé → mark ended")
                        async with get_db() as db:
                            await db.execute(
                                'UPDATE world_bosses SET ended=1 WHERE id=?', (wb_id,),
                            )
                            await db.commit()
                    except discord.Forbidden:
                        pass
                    except Exception:
                        pass
                except Exception as ex:
                    print(f"[stale_cleanup wb row={wb_id}] {ex}")
        except Exception as ex:
            print(f"[stale_cleanup wb block] {ex}")

        # ─── 3. DB flash_treasures ─────────────────────────────────────────
        try:
            async with get_db() as db:
                async with db.execute(
                    'SELECT id, guild_id, channel_id, message_id '
                    'FROM flash_treasures WHERE ended=0'
                ) as cur:
                    rows = await cur.fetchall()
            for ft_id, guild_id, ch_id, msg_id in rows:
                try:
                    guild = bot.get_guild(int(guild_id))
                    if not guild:
                        async with get_db() as db:
                            await db.execute(
                                'UPDATE flash_treasures SET ended=1 WHERE id=?', (ft_id,),
                            )
                            await db.commit()
                        continue
                    ch = guild.get_channel(int(ch_id)) if ch_id else None
                    if not ch:
                        async with get_db() as db:
                            await db.execute(
                                'UPDATE flash_treasures SET ended=1 WHERE id=?', (ft_id,),
                            )
                            await db.commit()
                        continue
                    try:
                        await ch.fetch_message(int(msg_id))
                    except discord.NotFound:
                        print(f"[stale_cleanup] flash_treasure {ft_id} msg supprimé → end")
                        async with get_db() as db:
                            await db.execute(
                                'UPDATE flash_treasures SET ended=1 WHERE id=?', (ft_id,),
                            )
                            await db.commit()
                    except discord.Forbidden:
                        pass
                    except Exception:
                        pass
                except Exception as ex:
                    print(f"[stale_cleanup ft row={ft_id}] {ex}")
        except Exception as ex:
            print(f"[stale_cleanup ft block] {ex}")

        # ─── 4. _mystery_boxes dict (in-memory) ───────────────────────────
        try:
            for msg_id in list(_mystery_boxes.keys()):
                try:
                    box = _mystery_boxes.get(msg_id)
                    if not box:
                        continue
                    guild_id = box.get('guild_id')
                    ch_id = box.get('channel_id')
                    if not guild_id:
                        _mystery_boxes.pop(msg_id, None)
                        continue
                    guild = bot.get_guild(int(guild_id))
                    if not guild:
                        _mystery_boxes.pop(msg_id, None)
                        continue
                    ch = guild.get_channel(int(ch_id)) if ch_id else None
                    if not ch:
                        _mystery_boxes.pop(msg_id, None)
                        continue
                    try:
                        await ch.fetch_message(int(msg_id))
                    except discord.NotFound:
                        print(f"[stale_cleanup] mystery_box msg={msg_id} supprimé → pop")
                        _mystery_boxes.pop(msg_id, None)
                    except discord.Forbidden:
                        pass
                    except Exception:
                        pass
                except Exception as ex:
                    print(f"[stale_cleanup mbox msg={msg_id}] {ex}")
        except Exception as ex:
            print(f"[stale_cleanup mbox block] {ex}")

        # ─── 5. _gn_event_state dict (in-memory) ──────────────────────────
        try:
            for msg_id in list(_gn_event_state.keys()):
                try:
                    state = _gn_event_state.get(msg_id)
                    if not state:
                        continue
                    ch_id = state.get('channel_id') or 0
                    if not ch_id:
                        # Pas de channel_id stocké → impossible de vérifier
                        # On laisse tel quel (les game night events ont leur propre cleanup)
                        continue
                    channel = None
                    for g in bot.guilds:
                        c = g.get_channel(int(ch_id))
                        if c:
                            channel = c
                            break
                    if not channel:
                        _gn_event_state.pop(msg_id, None)
                        continue
                    try:
                        await channel.fetch_message(int(msg_id))
                    except discord.NotFound:
                        print(f"[stale_cleanup] gn_event msg={msg_id} supprimé → pop")
                        _gn_event_state.pop(msg_id, None)
                    except discord.Forbidden:
                        pass
                    except Exception:
                        pass
                except Exception as ex:
                    print(f"[stale_cleanup gn msg={msg_id}] {ex}")
        except Exception as ex:
            print(f"[stale_cleanup gn block] {ex}")

    except Exception as ex:
        print(f"[stale_event_cleanup] {ex}")


@stale_event_cleanup.before_loop
async def _stale_event_cleanup_wait():
    await bot.wait_until_ready()


@tasks.loop(hours=1)
async def event_auto_scheduler():
    """Vérifie chaque heure si un event auto doit être lancé."""
    try:
        for guild in bot.guilds:
            try:
                c = await cfg(guild.id)
                if not c.get('event_enabled', False):
                    continue
                # Phase 35 : pas d'event pendant la nuit (par défaut 10h-23h FR)
                if not _is_event_active_time(c):
                    continue
                interval_h = int(c.get('event_auto_interval_hours', 6) or 6)
                if interval_h <= 0:
                    continue  # manuel uniquement

                last_run = c.get('event_last_run', '')
                if last_run:
                    try:
                        last_dt = datetime.fromisoformat(last_run)
                        if (datetime.now(timezone.utc) - last_dt).total_seconds() < interval_h * 3600:
                            continue
                    except Exception:
                        pass

                # Vérifier qu'aucun event n'est en cours
                async with get_db() as db:
                    async with db.execute('SELECT id FROM events WHERE guild_id=? AND ended=0', (guild.id,)) as cur:
                        if await cur.fetchone():
                            continue

                # Lancer (type aléatoire parmi ceux activés) !
                enabled_types = []
                if bool(c.get('event_type_boss_enabled', True)):
                    enabled_types.append('boss_raid')
                if bool(c.get('event_type_treasure_enabled', True)):
                    enabled_types.append('treasure_hunt')
                if bool(c.get('event_type_quiz_enabled', True)):
                    enabled_types.append('quiz')
                if not enabled_types:
                    continue
                import random as _r
                chosen_type = _r.choice(enabled_types)
                result = await _start_any_event(guild, bot.user.id, chosen_type, manual=False)
                if result.get('ok'):
                    print(f"[EVENT AUTO] guild={guild.id} type={chosen_type} déclenché")
            except Exception as ex:
                print(f"[event_auto_scheduler guild={guild.id}] {ex}")
    except Exception as ex:
        print(f"[event_auto_scheduler] {ex}")


@event_timeout_checker.before_loop
async def _evt_timeout_wait():
    await bot.wait_until_ready()


@event_auto_scheduler.before_loop
async def _evt_auto_wait():
    await bot.wait_until_ready()


# ─────────────────────────── RESTAURATION AU BOOT ───────────────────────────

async def restore_active_events():
    """Au boot du bot : restore les views (boss/treasure/quiz) des events actifs."""
    try:
        async with get_db() as db:
            async with db.execute('SELECT id, event_type FROM events WHERE ended=0') as cur:
                rows = await cur.fetchall()
        for event_id, event_type in rows:
            try:
                if event_type == 'boss_raid' or not event_type:
                    bot.add_view(BossAttackView(int(event_id)))
                # Treasure / Quiz : les views sont attachées à des messages spécifiques
                # qui contiennent leur custom_id. Au reboot, on ne peut pas restaurer
                # les boutons sans relancer le spawner / runner. Solution : on les ignore
                # (le timeout_checker terminera l'event).
            except Exception as ex:
                print(f"[restore_active_events event_id={event_id}] {ex}")
        if rows:
            print(f"[EVENTS] {len(rows)} événement(s) actif(s) restauré(s)")
    except Exception as ex:
        print(f"[restore_active_events] {ex}")


async def restore_active_personal_events():
    """Au boot : restore les PersonalEventOpenView persistantes pour les events non-claim."""
    try:
        async with get_db() as db:
            async with db.execute(
                'SELECT id FROM personal_events_log WHERE claimed=0 '
                'AND datetime(created_at) > datetime("now", "-7 days")',
            ) as cur:
                rows = await cur.fetchall()
        count = 0
        for (log_id,) in rows:
            try:
                v = PersonalEventOpenView(int(log_id))
                bot.add_view(v)
                count += 1
            except Exception as ex:
                print(f"[restore_active_personal_events log_id={log_id}] {ex}")
        if count:
            print(f"[PERSONAL EVENTS] {count} event(s) personnel(s) restauré(s)")
    except Exception as ex:
        print(f"[restore_active_personal_events] {ex}")


