# Helpers module-level (utilisés par V1 ActionConfigPanel ET V2 ActionConfigPanelV2 / ProtDetailV2)
_PROT_ACTION_KEYS = {
    'anti_phishing': 'phishing_action',
    'anti_scam': 'scam_action',
    'anti_compromised': 'compromised_action',
    'anti_qrcode': 'qrcode_action',
    'anti_spam': 'spam_action',
    'anti_mass_mention': 'mention_action',
    'anti_link': 'link_action',
    'anti_invite': 'invite_action',
    'anti_image': 'image_action',
    'anti_badwords': 'badwords_action',
    'anti_caps': 'caps_action',
}
_PROT_DURATION_KEYS = {
    'anti_phishing': 'phishing_mute_duration',
    'anti_scam': 'scam_mute_duration',
    'anti_compromised': 'compromised_mute_duration',
    'anti_qrcode': 'qrcode_mute_duration',
    'anti_spam': 'spam_mute_duration',
    'anti_mass_mention': 'mention_mute_duration',
    'anti_link': 'link_mute_duration',
    'anti_invite': 'invite_mute_duration',
    'anti_image': 'image_mute_duration',
    'anti_badwords': 'badwords_mute_duration',
    'anti_caps': 'caps_mute_duration',
}
_PROT_DEFAULT_ACTIONS = {
    'anti_phishing': 'delete', 'anti_scam': 'mute',
    'anti_compromised': 'mute', 'anti_qrcode': 'mute',
    'anti_spam': 'mute', 'anti_mass_mention': 'mute',
    'anti_link': 'delete', 'anti_invite': 'delete',
    'anti_image': 'delete', 'anti_badwords': 'delete',
    'anti_caps': 'delete',
}
_PROT_DEFAULT_DURATIONS = {
    'anti_phishing': 60, 'anti_scam': 60,
    'anti_compromised': 60, 'anti_qrcode': 30,
    'anti_spam': 10, 'anti_mass_mention': 10,
    'anti_link': 5, 'anti_invite': 5,
    'anti_image': 5, 'anti_badwords': 5,
    'anti_caps': 5,
}


def get_prot_action_key(key):
    return _PROT_ACTION_KEYS.get(key, f'{key.replace("anti_", "")}_action')


def get_prot_duration_key(key):
    return _PROT_DURATION_KEYS.get(key, f'{key.replace("anti_", "")}_mute_duration')


def get_prot_default_action(key):
    return _PROT_DEFAULT_ACTIONS.get(key, 'delete')


def get_prot_default_duration(key):
    return _PROT_DEFAULT_DURATIONS.get(key, 5)


class ActionConfigPanel(View):
    def __init__(self, u, g, key):
        super().__init__(timeout=600)
        self.u = u
        self.g = g
        self.key = key

    def _get_action_key(self):
        return get_prot_action_key(self.key)

    def _get_duration_key(self):
        return get_prot_duration_key(self.key)

    def _get_default_action(self):
        return get_prot_default_action(self.key)

    def _get_default_duration(self):
        return get_prot_default_duration(self.key)

    async def embed(self):
        c = await cfg(self.g.id)
        ak = self._get_action_key()
        dk = self._get_duration_key()
        current_action = c.get(ak, self._get_default_action())
        current_dur = c.get(dk, self._get_default_duration())

        action_emoji = {'delete': '🗑️', 'mute': '🔇', 'kick': '👢', 'ban': '🔨'}.get(current_action, '⚡')
        name = self.key.replace('anti_', '').replace('_', ' ').title()
        e = discord.Embed(title=f"⚡ Sanction pour {name}", color=C.BLUE)
        e.description = (
            f"**Action actuelle:** {action_emoji} `{current_action.upper()}`\n"
            f"**Durée du mute:** `{current_dur}` minutes\n"
            f"━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n"
            f"Choisissez l'action à effectuer lors d'une violation :"
        )

        e.add_field(name="🗑️ Supprimer", value="Supprime le message uniquement", inline=True)
        e.add_field(name="🔇 Mute", value="Rend muet + supprime", inline=True)
        e.add_field(name="👢 Kick", value="Expulse du serveur", inline=True)
        e.add_field(name="🔨 Ban", value="Bannit définitivement", inline=True)

        return e

    @discord.ui.button(label="🗑️ Supprimer", style=discord.ButtonStyle.success, row=0)
    async def delete_only(self, i, b):
        await self._set(i, 'delete')

    @discord.ui.button(label="🔇 Mute", style=discord.ButtonStyle.primary, row=0)
    async def mute(self, i, b):
        await self._set(i, 'mute')

    @discord.ui.button(label="👢 Kick", style=discord.ButtonStyle.secondary, row=0)
    async def kick(self, i, b):
        await self._set(i, 'kick')

    @discord.ui.button(label="🔨 Ban", style=discord.ButtonStyle.danger, row=0)
    async def ban(self, i, b):
        await self._set(i, 'ban')

    @discord.ui.button(label="⏱️ Durée Mute", style=discord.ButtonStyle.primary, row=1)
    async def set_duration(self, i, b):
        await i.response.send_modal(DurationConfigModal(self.g, self.u, self.key))

    async def _set(self, i, act):
        ak = self._get_action_key()
        await db_set(self.g.id, ak, act)
        prot = next(p for p in PROTS if p[0] == self.key)
        v = ProtDetailV2(self.u, self.g, prot)
        await v.render_to(i, edit=True)

    @discord.ui.button(label="◀️ Retour", style=discord.ButtonStyle.secondary, row=1)
    async def back(self, i, b):
        prot = next(p for p in PROTS if p[0] == self.key)
        v = ProtDetailV2(self.u, self.g, prot)
        await v.render_to(i, edit=True)

class ActionConfigPanelV2(LayoutView):
    """Configuration de la sanction d'une protection en V2."""

    def __init__(self, u, g, key):
        super().__init__(timeout=600)
        self.u = u
        self.g = g
        self.key = key

    async def interaction_check(self, i):
        return i.user.id == self.u.id

    def _get_action_key(self):
        return get_prot_action_key(self.key)

    def _get_duration_key(self):
        return get_prot_duration_key(self.key)

    def _get_default_action(self):
        return get_prot_default_action(self.key)

    def _get_default_duration(self):
        return get_prot_default_duration(self.key)

    async def render_to(self, interaction: discord.Interaction, *, edit: bool = True):
        c = await cfg(self.g.id)
        ak = self._get_action_key()
        dk = self._get_duration_key()
        current_action = c.get(ak, self._get_default_action())
        current_dur = c.get(dk, self._get_default_duration())

        name = self.key.replace('anti_', '').replace('_', ' ').title()

        # Phase 7 : radio button style propre
        def _btn(action, label, danger_style=False):
            is_current = (current_action == action)
            return Button(
                label=label,
                style=(
                    discord.ButtonStyle.success if is_current
                    else (discord.ButtonStyle.danger if danger_style else discord.ButtonStyle.secondary)
                ),
                custom_id=f"acpv2_{self.key}_{action}",
            )

        def _row(action, emoji, label, desc):
            dot = "🔘" if current_action == action else "⚪"
            return f"{dot} {emoji} **{label}** · {desc}"

        self.clear_items()
        b_delete = _btn('delete', "🗑️ Supprimer")
        b_delete.callback = lambda i: self._set(i, 'delete')
        b_mute = _btn('mute', "🔇 Mute")
        b_mute.callback = lambda i: self._set(i, 'mute')
        b_kick = _btn('kick', "👢 Kick")
        b_kick.callback = lambda i: self._set(i, 'kick')
        b_ban = _btn('ban', "🔨 Ban", danger_style=True)
        b_ban.callback = lambda i: self._set(i, 'ban')
        b_dur = Button(label=f"⏱️ Durée mute · {current_dur} min", style=discord.ButtonStyle.primary, custom_id=f"acpv2_{self.key}_dur")
        b_dur.callback = self._cb_duration
        b_back = Button(label="◀️ Retour", style=discord.ButtonStyle.secondary, custom_id=f"acpv2_{self.key}_back")
        b_back.callback = self._cb_back

        items: list = [
            v2_title(f"⚡ Sanction · {name}"),
            v2_subtitle(f"Action actuelle · `{current_action.upper()}`"),
            v2_divider(),
            v2_body(
                _row('delete', '🗑️', 'Supprimer', 'message seulement') + "\n"
                + _row('mute', '🔇', 'Mute', 'muet + supprime') + "\n"
                + _row('kick', '👢', 'Kick', 'expulse du serveur') + "\n"
                + _row('ban', '🔨', 'Ban', 'bannissement définitif')
            ),
            v2_divider(),
            discord.ui.ActionRow(b_delete, b_mute, b_kick, b_ban),
            discord.ui.ActionRow(b_dur, b_back),
        ]

        self.add_item(v2_container(*items, color=Palette.INFO))

        if edit:
            await interaction.response.edit_message(content=None, view=self, embed=None, attachments=[])
        else:
            await interaction.response.send_message(view=self, ephemeral=True)

    async def _set(self, i, act):
        ak = self._get_action_key()
        await db_set(self.g.id, ak, act)
        # On reste sur la même page (pour voir le changement)
        await ActionConfigPanelV2(self.u, self.g, self.key).render_to(i, edit=True)

    async def _cb_duration(self, i):
        await i.response.send_modal(DurationConfigModal(self.g, self.u, self.key))

    async def _cb_back(self, i):
        prot = next(p for p in PROTS if p[0] == self.key)
        v = ProtDetailV2(self.u, self.g, prot)
        await v.render_to(i, edit=True)


