# ─────────────────────────────── ROBLOX UGC ───────────────────────────────

class AdsRobloxPanelV2(LayoutView):
    """Roblox UGC en V2 (créateurs + groupes)."""

    def __init__(self, u, g):
        super().__init__(timeout=600)
        self.u = u
        self.g = g

    async def interaction_check(self, i):
        return i.user.id == self.u.id

    async def render_to(self, interaction: discord.Interaction, *, edit: bool = True):
        c = await cfg(self.g.id)
        rblx_ch = self.g.get_channel(c.get('ads_roblox_channel', 0))
        feeds = c.get('ads_roblox_feeds', [])

        def dot(x):
            return f"🔘 {x.mention}" if x else "⚪ _non défini_"

        # Phase 9 : séparer users et groups, max 4 chacun
        users_lines = []
        groups_lines = []
        for f in feeds:
            if isinstance(f, dict):
                if f.get('type') == 'group':
                    groups_lines.append(f"• `{f.get('group_name', '?')}`")
                else:
                    users_lines.append(f"• `{f.get('username', '?')}`")

        users_block = "\n".join(users_lines[:4]) if users_lines else "_aucun_"
        if len(users_lines) > 4:
            users_block += f"\n_… +{len(users_lines) - 4}_"
        groups_block = "\n".join(groups_lines[:4]) if groups_lines else "_aucun_"
        if len(groups_lines) > 4:
            groups_block += f"\n_… +{len(groups_lines) - 4}_"

        # Boutons
        self.clear_items()
        b_chan = Button(label="📍 Salon", style=discord.ButtonStyle.primary, custom_id="adsv2_rblx_chan")
        b_chan.callback = self._cb_chan
        b_user = Button(label="👤 + Créateur", style=discord.ButtonStyle.success, custom_id="adsv2_rblx_user")
        b_user.callback = self._cb_user
        b_group = Button(label="👥 + Groupe", style=discord.ButtonStyle.success, custom_id="adsv2_rblx_group")
        b_group.callback = self._cb_group
        b_remove = Button(
            label="🗑️ Retirer",
            style=discord.ButtonStyle.danger,
            disabled=(not feeds),
            custom_id="adsv2_rblx_remove",
        )
        b_remove.callback = self._cb_remove
        b_back = Button(label="◀️ Retour", style=discord.ButtonStyle.secondary, custom_id="adsv2_rblx_back")
        b_back.callback = self._cb_back

        items: list = [
            v2_title("🟢  Roblox UGC"),
            v2_subtitle(f"`{len(users_lines)}` créateur(s) · `{len(groups_lines)}` groupe(s)"),
            v2_divider(),
            v2_body(f"📍 **Salon** · {dot(rblx_ch)}"),
            v2_divider(),
            v2_body(
                f"**👤 Créateurs**\n{users_block}\n\n"
                f"**👥 Groupes**\n{groups_block}"
            ),
            v2_divider(),
            discord.ui.ActionRow(b_chan, b_user, b_group, b_remove, b_back),
        ]

        self.add_item(v2_container(*items, color=discord.Color(0x00A86B)))

        if edit:
            await interaction.response.edit_message(content=None, view=self, embed=None, attachments=[])
        else:
            await interaction.response.send_message(view=self, ephemeral=True)

    async def _cb_chan(self, i):
        # Phase 3.0j : V2 native picker
        v = V2AdsChannelPicker(
            self.u, self.g, 'ads_roblox_channel', 'roblox',
            title="📍 Salon Roblox UGC",
            description="Où publier les nouvelles créations UGC.",
            color=0x00A86B,
        )
        await v.render_to(i, edit=True)

    async def _cb_user(self, i):
        await i.response.send_modal(AdsRobloxAddUserModal(self.g, self.u))

    async def _cb_group(self, i):
        await i.response.send_modal(AdsRobloxAddGroupModal(self.g, self.u))

    async def _cb_remove(self, i):
        c = await cfg(self.g.id)
        feeds = c.get('ads_roblox_feeds', [])
        if not feeds:
            return await i.response.send_message("❌ Aucun feed à supprimer", ephemeral=True)
        opts = []
        for idx, f in enumerate(feeds[:25]):
            if isinstance(f, dict):
                if f.get('type') == 'group':
                    label = f"👥 {f.get('group_name', '?')}"[:25]
                else:
                    label = f"👤 {f.get('username', '?')}"[:25]
            else:
                label = str(f)[:25]
            opts.append(discord.SelectOption(label=label, value=str(idx)))
        v = AdsFeedRemoveView(self.u, self.g, opts, 'ads_roblox_feeds', 'roblox')
        await i.response.edit_message(
            embed=discord.Embed(title="🗑️ Supprimer un feed Roblox", color=0xE74C3C),
            view=v,
            attachments=[],
        )

    async def _cb_back(self, i):
        v = AdsPanelV2(self.u, self.g)
        await v.render_to(i, edit=True)


class AdsRobloxPanel(View):
    def __init__(self, u, g):
        super().__init__(timeout=600)
        self.u = u
        self.g = g
    
    async def embed(self):
        c = await cfg(self.g.id)
        e = discord.Embed(title="🟢 Roblox UGC - Créations", color=0x00A86B)
        
        rblx_ch = self.g.get_channel(c.get('ads_roblox_channel', 0))
        rblx_feeds = c.get('ads_roblox_feeds', [])
        
        e.description = "Recevez automatiquement les nouvelles créations UGC de vos créateurs et groupes Roblox préférés!"
        
        e.add_field(name="📍 Salon de publication", value=rblx_ch.mention if rblx_ch else "❌ Non configuré", inline=False)
        
        if rblx_feeds:
            # Séparer utilisateurs et groupes
            users_txt = ""
            groups_txt = ""
            user_count = 0
            group_count = 0
            
            for f in rblx_feeds:
                if isinstance(f, dict):
                    feed_type = f.get('type', 'user')  # 'user' par défaut pour rétrocompatibilité
                    
                    if feed_type == 'group':
                        name = f.get('group_name', '?')
                        feed_id = f.get('group_id', '?')
                        groups_txt += f"• `{name}` (ID: {feed_id})\n"
                        group_count += 1
                    else:
                        name = f.get('username', '?')
                        feed_id = f.get('user_id', '?')
                        users_txt += f"• `{name}` (ID: {feed_id})\n"
                        user_count += 1
            
            if users_txt:
                e.add_field(name=f"👤 Créateurs suivis ({user_count})", value=users_txt[:1024], inline=False)
            
            if groups_txt:
                e.add_field(name=f"👥 Groupes suivis ({group_count})", value=groups_txt[:1024], inline=False)
            
            if not users_txt and not groups_txt:
                e.add_field(name="📋 Feeds configurés", value="*Aucun feed valide*", inline=False)
        else:
            e.add_field(name="📋 Feeds suivis", value="*Aucun créateur ou groupe configuré*", inline=False)
        
        e.set_footer(text="💡 Les nouvelles créations UGC sont vérifiées toutes les 10 minutes")
        return e
    
    @discord.ui.button(label="📍 Salon", style=discord.ButtonStyle.primary, row=0)
    async def set_channel(self, i, b):
        v = PaginatedAdsChannelSelect(self.u, self.g, 'ads_roblox_channel', 'roblox')
        await i.response.edit_message(
            embed=discord.Embed(
                title="📍 Salon Roblox UGC",
                description="Où publier les nouvelles créations UGC",
                color=0x00A86B
            ),
            view=v
        )
    
    @discord.ui.button(label="👤 Ajouter Créateur", style=discord.ButtonStyle.success, row=0)
    async def add_user(self, i, b):
        await i.response.send_modal(AdsRobloxAddUserModal(self.g, self.u))
    
    @discord.ui.button(label="👥 Ajouter Groupe", style=discord.ButtonStyle.success, row=0)
    async def add_group(self, i, b):
        await i.response.send_modal(AdsRobloxAddGroupModal(self.g, self.u))
    
    @discord.ui.button(label="🗑️ Supprimer", style=discord.ButtonStyle.danger, row=1)
    async def remove_feed(self, i, b):
        c = await cfg(self.g.id)
        feeds = c.get('ads_roblox_feeds', [])
        if not feeds:
            return await i.response.send_message("❌ Aucun feed à supprimer", ephemeral=True)
        
        opts = []
        for idx, f in enumerate(feeds[:25]):
            if isinstance(f, dict):
                feed_type = f.get('type', 'user')
                if feed_type == 'group':
                    label = f"👥 {f.get('group_name', str(idx))}"
                else:
                    label = f"👤 {f.get('username', str(idx))}"
            else:
                label = f"Feed #{idx+1}: {str(f)[:20]}"
            opts.append(discord.SelectOption(label=label[:25], value=str(idx)))

        if not opts:
            return await i.response.send_message("❌ Aucun feed valide à supprimer", ephemeral=True)

        v = AdsFeedRemoveView(self.u, self.g, opts, 'ads_roblox_feeds', 'roblox')
        await i.response.edit_message(embed=discord.Embed(title="🗑️ Supprimer un feed", color=0xE74C3C), view=v)
    
    @discord.ui.button(label="◀️ Retour", style=discord.ButtonStyle.secondary, row=1)
    async def back(self, i, b):
        v = AdsPanel(self.u, self.g)
        await i.response.edit_message(embed=await v.embed(), view=v)


class AdsRobloxAddUserModal(Modal, title="👤 Ajouter un créateur Roblox"):
    username = TextInput(label="Nom d'utilisateur Roblox", placeholder="Ex: Roblox", max_length=50)
    
    def __init__(self, g, u):
        super().__init__()
        self.g = g
        self.u = u
    
    async def on_submit(self, i):
        await i.response.defer(ephemeral=True)
        
        username = self.username.value.strip()
        
        # Récupérer l'ID utilisateur Roblox via l'API
        try:
            async with aiohttp.ClientSession() as session:
                # API pour obtenir l'ID utilisateur
                async with session.post(
                    'https://users.roblox.com/v1/usernames/users',
                    json={'usernames': [username], 'excludeBannedUsers': True}
                ) as resp:
                    if resp.status == 200:
                        data = await resp.json()
                        if data.get('data') and len(data['data']) > 0:
                            user_data = data['data'][0]
                            user_id = user_data.get('id')
                            display_name = user_data.get('displayName', username)
                            
                            # Vérifier si déjà ajouté
                            c = await cfg(self.g.id)
                            feeds = c.get('ads_roblox_feeds', [])
                            
                            for f in feeds:
                                if isinstance(f, dict) and f.get('type', 'user') == 'user' and f.get('user_id') == user_id:
                                    return await i.followup.send("❌ Ce créateur est déjà ajouté!", ephemeral=True)
                            
                            # Ajouter le créateur
                            new_feed = {
                                'type': 'user',
                                'username': display_name,
                                'user_id': user_id
                            }
                            feeds.append(new_feed)
                            await db_set(self.g.id, 'ads_roblox_feeds', feeds)
                            
                            await i.followup.send(f"✅ Créateur **{display_name}** (ID: {user_id}) ajouté !", ephemeral=True)
                        else:
                            await i.followup.send(f"❌ Utilisateur Roblox `{username}` introuvable", ephemeral=True)
                    else:
                        await i.followup.send("❌ Erreur lors de la recherche Roblox", ephemeral=True)
        except Exception as ex:
            print(f"Erreur Roblox API: {ex}")
            await i.followup.send("❌ Erreur de connexion à l'API Roblox", ephemeral=True)


class AdsRobloxAddGroupModal(Modal, title="👥 Ajouter un groupe Roblox"):
    group_input = TextInput(
        label="Nom ou ID du groupe Roblox",
        placeholder="Ex: UGC Creators ou 12345678",
        max_length=100
    )
    
    def __init__(self, g, u):
        super().__init__()
        self.g = g
        self.u = u
    
    async def on_submit(self, i):
        await i.response.defer(ephemeral=True)
        
        group_input = self.group_input.value.strip()
        
        try:
            async with aiohttp.ClientSession() as session:
                headers = {'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36'}
                
                group_id = None
                group_name = None
                
                # Vérifier si c'est un ID (que des chiffres)
                if group_input.isdigit():
                    # C'est un ID, on récupère directement les infos du groupe
                    group_id = int(group_input)
                    async with session.get(
                        f'https://groups.roblox.com/v1/groups/{group_id}',
                        headers=headers
                    ) as resp:
                        if resp.status == 200:
                            data = await resp.json()
                            group_name = data.get('name')
                        elif resp.status == 404:
                            return await i.followup.send(f"❌ Groupe avec l'ID `{group_id}` introuvable", ephemeral=True)
                        else:
                            return await i.followup.send("❌ Erreur lors de la recherche du groupe", ephemeral=True)
                else:
                    # C'est un nom, on recherche le groupe
                    search_url = f'https://groups.roblox.com/v1/groups/search/lookup?groupName={group_input}'
                    async with session.get(search_url, headers=headers) as resp:
                        if resp.status == 200:
                            data = await resp.json()
                            groups = data.get('data', [])
                            
                            if groups:
                                # Prendre le premier résultat (correspondance exacte ou proche)
                                group_data = groups[0]
                                group_id = group_data.get('id')
                                group_name = group_data.get('name')
                            else:
                                # Essayer une recherche plus large
                                search_url2 = f'https://groups.roblox.com/v1/groups/search?keyword={group_input}&limit=10'
                                async with session.get(search_url2, headers=headers) as resp2:
                                    if resp2.status == 200:
                                        data2 = await resp2.json()
                                        groups2 = data2.get('data', [])
                                        if groups2:
                                            group_data = groups2[0]
                                            group_id = group_data.get('id')
                                            group_name = group_data.get('name')
                                        else:
                                            return await i.followup.send(f"❌ Groupe `{group_input}` introuvable", ephemeral=True)
                                    else:
                                        return await i.followup.send("❌ Erreur lors de la recherche", ephemeral=True)
                        else:
                            return await i.followup.send("❌ Erreur lors de la recherche du groupe", ephemeral=True)
                
                if not group_id or not group_name:
                    return await i.followup.send("❌ Impossible de trouver ce groupe", ephemeral=True)
                
                # Vérifier si le groupe a des créations UGC
                # NOTE: Roblox bloque parfois les IP datacenter sur catalog.roblox.com
                # On essaye 2 endpoints, et on distingue "pas d'UGC" vs "API inaccessible"
                has_ugc = None  # None = inconnu, True = a des UGC, False = aucun UGC confirmé
                ugc_check_endpoints = [
                    f"https://catalog.roblox.com/v1/search/items?Category=All&CreatorType=Group&CreatorTargetId={group_id}&Limit=10&SortType=3",
                    f"https://catalog.roblox.com/v2/search/items/details?Category=All&CreatorType=Group&CreatorTargetId={group_id}&Limit=10&SortType=3",
                    f"https://catalog.roblox.com/v1/search/items?creatorTargetId={group_id}&creatorType=Group&limit=10",
                ]
                last_status = None
                last_error = None
                for ep in ugc_check_endpoints:
                    try:
                        async with session.get(ep, headers=headers, timeout=aiohttp.ClientTimeout(total=10)) as resp:
                            last_status = resp.status
                            if resp.status == 200:
                                cdata = await resp.json()
                                items_n = len(cdata.get('data', []))
                                has_ugc = items_n > 0
                                if has_ugc:
                                    break  # on a trouve, on s'arrete
                            else:
                                last_error = f"HTTP {resp.status}"
                                try:
                                    body = await resp.text()
                                    last_error += f" | body: {body[:200]}"
                                except Exception:
                                    pass
                    except Exception as ex:
                        last_error = f"{type(ex).__name__}: {ex}"

                if has_ugc is None:
                    print(f"[ROBLOX UGC] check group {group_id} echoue : last_status={last_status} err={last_error}")
                
                # Vérifier si déjà ajouté
                c = await cfg(self.g.id)
                feeds = c.get('ads_roblox_feeds', [])
                
                for f in feeds:
                    if isinstance(f, dict) and f.get('type') == 'group' and f.get('group_id') == group_id:
                        return await i.followup.send("❌ Ce groupe est déjà ajouté!", ephemeral=True)
                
                # Ajouter le groupe
                new_feed = {
                    'type': 'group',
                    'group_name': group_name,
                    'group_id': group_id
                }
                feeds.append(new_feed)
                await db_set(self.g.id, 'ads_roblox_feeds', feeds)
                
                # Message de confirmation
                if has_ugc is True:
                    await i.followup.send(f"✅ Groupe **{group_name}** (ID: {group_id}) ajouté !\n💡 Ce groupe a des créations UGC.", ephemeral=True)
                elif has_ugc is False:
                    await i.followup.send(f"✅ Groupe **{group_name}** (ID: {group_id}) ajouté !\n⚠️ Ce groupe ne semble pas avoir de créations UGC pour le moment.", ephemeral=True)
                else:
                    # has_ugc is None : check API echoue
                    await i.followup.send(
                        f"✅ Groupe **{group_name}** (ID: {group_id}) ajouté !\n"
                        f"ℹ️ Vérification UGC indisponible (API Roblox bloquée depuis l'hôte du bot — `{last_error or 'erreur inconnue'}`).\n"
                        f"Le tracking se fera quand même au prochain cycle.",
                        ephemeral=True,
                    )
                    
        except Exception as ex:
            print(f"Erreur Roblox Group API: {ex}")
            await i.followup.send("❌ Erreur de connexion à l'API Roblox", ephemeral=True)

