class V2AdsChannelPicker(LayoutView):
    """Selecteur de salon V2 natif (Phase 3.0j).

    Utilise discord.ui.ChannelSelect qui est V2-compatible et evite la
    transition V2 LayoutView -> V1 View+embed qui plantait en discord.py 2.7.
    """

    def __init__(self, u, g, config_key: str, platform: str, *,
                 title: str = "Choisir un salon",
                 description: str = "Selectionne un salon pour les publications.",
                 color: int = 0x5865F2,
                 channel_types=None):
        super().__init__(timeout=300)
        self.u = u
        self.g = g
        self.config_key = config_key
        self.platform = platform
        self.title = title
        self.description = description
        self.color = color
        self.channel_types = channel_types or [discord.ChannelType.text, discord.ChannelType.news]
        self._build()

    async def interaction_check(self, i):
        return i.user.id == self.u.id

    def _build(self):
        self.clear_items()

        # ChannelSelect V2 natif - pas de pagination car Discord-side
        sel = discord.ui.ChannelSelect(
            channel_types=self.channel_types,
            placeholder="📁 Choisir un salon...",
            min_values=1,
            max_values=1,
        )
        async def _on_select(i):
            try:
                ch = sel.values[0]
                # Resoud channel_id
                channel_id = ch.id if hasattr(ch, 'id') else int(ch)
                await db_set(i.guild.id, self.config_key, channel_id)
                # Retour au panel parent
                v = self._get_return_panel()
                if hasattr(v, 'render_to'):
                    await v.render_to(i, edit=True)
                    try:
                        await i.followup.send(
                            f"✅ Salon défini : <#{channel_id}>",
                            ephemeral=True,
                        )
                    except Exception:
                        pass
                else:
                    await i.response.edit_message(
                        content=f"✅ Salon défini : <#{channel_id}>",
                        embed=await v.embed(),
                        view=v,
                        attachments=[],
                    )
            except Exception as ex:
                import traceback
                traceback.print_exc()
                try:
                    await i.response.send_message(f"❌ Erreur : {ex}", ephemeral=True)
                except Exception:
                    pass
        sel.callback = _on_select

        # Bouton "Aucun" pour reset le salon
        b_none = Button(label="❌ Aucun (reset)", style=discord.ButtonStyle.secondary)
        async def _none(i):
            try:
                await db_set(i.guild.id, self.config_key, 0)
                v = self._get_return_panel()
                if hasattr(v, 'render_to'):
                    await v.render_to(i, edit=True)
                else:
                    await i.response.edit_message(embed=await v.embed(), view=v, attachments=[])
            except Exception as ex:
                import traceback
                traceback.print_exc()
                try:
                    await i.response.send_message(f"❌ Erreur : {ex}", ephemeral=True)
                except Exception:
                    pass
        b_none.callback = _none

        # Bouton retour
        b_back = Button(label="◀️ Retour", style=discord.ButtonStyle.danger)
        async def _back(i):
            try:
                v = self._get_return_panel()
                if hasattr(v, 'render_to'):
                    await v.render_to(i, edit=True)
                else:
                    await i.response.edit_message(embed=await v.embed(), view=v, attachments=[])
            except Exception as ex:
                import traceback
                traceback.print_exc()
                try:
                    await i.response.send_message(f"❌ Erreur : {ex}", ephemeral=True)
                except Exception:
                    pass
        b_back.callback = _back

        items = [
            v2_title(self.title),
            v2_subtitle(self.description),
            v2_divider(),
            v2_subtitle(f"📂 {len(self.g.text_channels)} salons textuels disponibles · scroll dans le menu pour chercher"),
            v2_divider(),
            discord.ui.ActionRow(sel),
            discord.ui.ActionRow(b_none, b_back),
        ]
        self.add_item(v2_container(*items, color=discord.Color(self.color)))

    def _get_return_panel(self):
        # Meme dispatch que PaginatedAdsChannelSelect
        if self.platform == 'youtube':
            return AdsLivePlatformV2(self.u, self.g, 'youtube')
        elif self.platform == 'twitch':
            return AdsLivePlatformV2(self.u, self.g, 'twitch')
        elif self.platform == 'tiktok':
            return AdsLivePlatformV2(self.u, self.g, 'tiktok')
        elif self.platform == 'twitter':
            return AdsSimplePlatformV2(self.u, self.g, 'twitter')
        elif self.platform == 'reddit':
            return AdsSimplePlatformV2(self.u, self.g, 'reddit')
        elif self.platform == 'discord':
            return AdsSimplePlatformV2(self.u, self.g, 'discord')
        elif self.platform == 'rosocial':
            return AdsSimplePlatformV2(self.u, self.g, 'rosocial')
        elif self.platform == 'roblox':
            return AdsRobloxPanelV2(self.u, self.g)
        elif self.platform == 'deals':
            return AdsDealsPanelV2(self.u, self.g)
        else:
            return AdsPanelV2(self.u, self.g)

    async def render_to(self, interaction, *, edit=True):
        if edit:
            await interaction.response.edit_message(content=None, view=self, embed=None, attachments=[])
        else:
            await interaction.response.send_message(view=self, ephemeral=True)


class PaginatedAdsChannelSelect(View):
    """Sélecteur de salon paginé pour les Ads"""
    def __init__(self, u, g, key, platform, page=0):
        super().__init__(timeout=180)
        self.u = u
        self.g = g
        self.key = key
        self.platform = platform
        self.page = page
        self.channels = list(g.text_channels)
        self.max_page = max(0, (len(self.channels) - 1) // 24)
        self._build()
    
    def _get_return_panel(self):
        # Tous les V2 (Phase 3.0c)
        if self.platform == 'youtube':
            return AdsLivePlatformV2(self.u, self.g, 'youtube')
        elif self.platform == 'twitch':
            return AdsLivePlatformV2(self.u, self.g, 'twitch')
        elif self.platform == 'tiktok':
            return AdsLivePlatformV2(self.u, self.g, 'tiktok')
        elif self.platform == 'twitter':
            return AdsSimplePlatformV2(self.u, self.g, 'twitter')
        elif self.platform == 'reddit':
            return AdsSimplePlatformV2(self.u, self.g, 'reddit')
        elif self.platform == 'discord':
            return AdsSimplePlatformV2(self.u, self.g, 'discord')
        elif self.platform == 'rosocial':
            return AdsSimplePlatformV2(self.u, self.g, 'rosocial')
        elif self.platform == 'roblox':
            return AdsRobloxPanelV2(self.u, self.g)
        elif self.platform == 'deals':
            return AdsDealsPanelV2(self.u, self.g)
        else:
            # Fallback safe : retour au master panel
            return AdsPanelV2(self.u, self.g)
    
    def _build(self):
        self.clear_items()
        
        start = self.page * 24
        end = start + 24
        page_channels = self.channels[start:end]
        
        opts = []
        for ch in page_channels:
            desc = ch.category.name[:50] if ch.category else "Sans catégorie"
            opts.append(discord.SelectOption(
                label=f"# {ch.name}"[:25],
                value=str(ch.id),
                description=desc
            ))
        
        if opts:
            select = PaginatedAdsChannelMenu(self, opts)
            self.add_item(select)
        
        # Navigation
        if self.max_page > 0:
            prev_btn = discord.ui.Button(label="◀️", style=discord.ButtonStyle.primary, disabled=(self.page == 0), row=1)
            prev_btn.callback = self.prev_page
            self.add_item(prev_btn)
            
            page_btn = discord.ui.Button(label=f"{self.page + 1}/{self.max_page + 1}", style=discord.ButtonStyle.secondary, disabled=True, row=1)
            self.add_item(page_btn)
            
            next_btn = discord.ui.Button(label="▶️", style=discord.ButtonStyle.primary, disabled=(self.page >= self.max_page), row=1)
            next_btn.callback = self.next_page
            self.add_item(next_btn)
        
        back_btn = discord.ui.Button(label="◀️ Retour", style=discord.ButtonStyle.danger, row=2)
        back_btn.callback = self.go_back
        self.add_item(back_btn)
    
    async def prev_page(self, i):
        self.page -= 1
        self._build()
        await i.response.edit_message(view=self)
    
    async def next_page(self, i):
        self.page += 1
        self._build()
        await i.response.edit_message(view=self)
    
    async def go_back(self, i):
        v = self._get_return_panel()
        # V2-aware : si le panneau cible a render_to, on est en V2
        if hasattr(v, 'render_to'):
            await v.render_to(i, edit=True)
        else:
            await i.response.edit_message(embed=await v.embed(), view=v, attachments=[])

class PaginatedAdsChannelMenu(Select):
    def __init__(self, parent, opts):
        super().__init__(placeholder=f"Page {parent.page + 1}/{parent.max_page + 1} - Choisir un salon...", options=opts)
        self.parent_view = parent

    async def callback(self, i):
        await db_set(i.guild.id, self.parent_view.key, int(self.values[0]))
        ch = i.guild.get_channel(int(self.values[0]))
        v = self.parent_view._get_return_panel()
        # V2-aware : panneau V2 → render_to + followup confirmation
        if hasattr(v, 'render_to'):
            await v.render_to(i, edit=True)
            try:
                await i.followup.send(
                    f"✅ Salon défini: **{ch.mention if ch else 'Aucun'}**",
                    ephemeral=True,
                )
            except Exception:
                pass
        else:
            await i.response.edit_message(
                content=f"✅ Salon défini: **{ch.mention if ch else 'Aucun'}**",
                embed=await v.embed(), view=v, attachments=[]
            )

class AdsFeedChannelPaginatedView(View):
    """Phase 21 : converti en ChannelSelect natif Discord (affiche TOUS les salons).

    Reste le même nom de classe pour compat — mais pagination supprimée car
    le picker natif gère ça automatiquement via search Discord.
    """
    def __init__(self, u, g, feed_data, feeds_config_key, page=0):
        super().__init__(timeout=180)
        self.u = u
        self.g = g
        self.feed_data = feed_data
        self.feeds_config_key = feeds_config_key
        self._build()

    def _build(self):
        self.clear_items()
        # Phase 21 : ChannelSelect natif (Discord affiche TOUS les salons avec recherche)
        select = discord.ui.ChannelSelect(
            channel_types=[discord.ChannelType.text, discord.ChannelType.news],
            placeholder="Choisir le salon de publication…",
            min_values=1, max_values=1,
        )
        select.callback = self._on_pick
        self.add_item(select)

        # Option "salon par défaut" via bouton
        default_btn = discord.ui.Button(
            label="📍 Salon par défaut",
            style=discord.ButtonStyle.secondary,
            row=1,
        )
        default_btn.callback = self._on_default
        self.add_item(default_btn)

    async def _on_pick(self, i):
        try:
            channel_id = int(i.data.get('values', ['0'])[0])
            self.feed_data['channel_id'] = channel_id
            await self._save_and_confirm(i, channel_id)
        except Exception as ex:
            print(f"[AdsFeedChannelPaginatedView _on_pick] {ex}")
            try:
                await i.response.send_message(f"❌ Erreur : `{ex}`", ephemeral=True)
            except Exception:
                pass

    async def _on_default(self, i):
        try:
            # Pas de channel_id custom → utilisera ads_*_channel par défaut
            await self._save_and_confirm(i, 0)
        except Exception as ex:
            print(f"[AdsFeedChannelPaginatedView _on_default] {ex}")

    async def _save_and_confirm(self, i, channel_id: int):
        c = await cfg(self.g.id)
        feeds = c.get(self.feeds_config_key, []) or []
        feeds.append(self.feed_data)
        await db_set(self.g.id, self.feeds_config_key, feeds)
        ch = self.g.get_channel(channel_id) if channel_id else None
        salon_txt = ch.mention if ch else "salon par défaut"
        name = (
            self.feed_data.get('name')
            or self.feed_data.get('username')
            or self.feed_data.get('id', '?')
        )
        kw = self.feed_data.get('keyword_filter', '')
        kw_note = f"\n🔍 Filtre actif : `{kw}`" if kw else ""
        try:
            await i.response.edit_message(
                content=f"✅ **{name}** ajouté ! Publications dans {salon_txt}{kw_note}",
                view=None,
                embed=None,
                attachments=[],
            )
        except discord.InteractionResponded:
            await i.followup.send(
                f"✅ **{name}** ajouté ! Publications dans {salon_txt}{kw_note}",
                ephemeral=True,
            )


