class AnnouncementPanelV2(LayoutView):
    """Système d'annonces en V2."""

    def __init__(self, u, g):
        super().__init__(timeout=600)
        self.u = u
        self.g = g
        self._build()

    async def interaction_check(self, i):
        return i.user.id == self.u.id

    def _build(self):
        self.clear_items()
        b_create = Button(label="📢 Créer une Annonce", style=discord.ButtonStyle.success, custom_id="apnv2_create")
        b_create.callback = self._cb_create
        b_back = Button(label="◀️ Retour", style=discord.ButtonStyle.secondary, custom_id="apnv2_back")
        b_back.callback = self._cb_back

        items: list = [
            v2_title("📢 Système d'Annonces"),
            v2_subtitle("Crée de belles annonces pour ton serveur"),
            v2_divider(),
            v2_body(
                "**✨ Fonctionnalités**\n"
                "• Titre personnalisé\n"
                "• Description détaillée\n"
                "• Couleur au choix\n"
                "• Image optionnelle\n"
                "• Mention optionnelle (@everyone, @here, rôle)"
            ),
            v2_divider(),
            v2_subtitle("💡 L'annonce sera envoyée immédiatement après création"),
            discord.ui.ActionRow(b_create, b_back),
        ]

        self.add_item(v2_container(*items, color=Palette.WARNING))

    async def render_to(self, interaction: discord.Interaction, *, edit: bool = True):
        if edit:
            await interaction.response.edit_message(content=None, view=self, embed=None, attachments=[])
        else:
            await interaction.response.send_message(view=self, ephemeral=True)

    async def _cb_create(self, i):
        await i.response.send_modal(AnnouncementCreateModal(self.u, self.g))

    async def _cb_back(self, i):
        v = CentrePanelV2(self.u, self.g)
        await i.response.edit_message(content=None, view=v, embed=None, attachments=[])


class AnnouncementCreateModal(Modal):
    def __init__(self, u, g):
        super().__init__(title="📢 Créer une Annonce")
        self.u = u
        self.g = g
        
        self.title_input = TextInput(
            label="Titre de l'annonce",
            placeholder="Ex: 🎉 Grande Mise à Jour !",
            max_length=100
        )
        self.description_input = TextInput(
            label="Description",
            placeholder="Décrivez votre annonce en détail...",
            style=discord.TextStyle.paragraph,
            max_length=2000
        )
        self.color_input = TextInput(
            label="Couleur (hex)",
            placeholder="#FF5733 ou rouge, bleu, vert, jaune, violet",
            required=False,
            max_length=20,
            default="#5865F2"
        )
        self.image_input = TextInput(
            label="URL de l'image (optionnel)",
            placeholder="https://...",
            required=False,
            max_length=500
        )
        self.mention_input = TextInput(
            label="Mention (optionnel)",
            placeholder="@everyone, @here, ou ID de rôle",
            required=False,
            max_length=50
        )
        
        self.add_item(self.title_input)
        self.add_item(self.description_input)
        self.add_item(self.color_input)
        self.add_item(self.image_input)
        self.add_item(self.mention_input)
    
    async def on_submit(self, i):
        # Parser la couleur
        color_str = self.color_input.value.strip().lower() if self.color_input.value else "#5865F2"
        color_map = {
            'rouge': 0xFF0000, 'red': 0xFF0000,
            'bleu': 0x0066FF, 'blue': 0x0066FF,
            'vert': 0x00FF00, 'green': 0x00FF00,
            'jaune': 0xFFFF00, 'yellow': 0xFFFF00,
            'violet': 0x9B59B6, 'purple': 0x9B59B6,
            'orange': 0xFF8C00,
            'rose': 0xFF69B4, 'pink': 0xFF69B4,
            'cyan': 0x00FFFF,
            'blanc': 0xFFFFFF, 'white': 0xFFFFFF,
            'noir': 0x000000, 'black': 0x000000,
        }
        
        if color_str in color_map:
            color = color_map[color_str]
        else:
            try:
                color = int(color_str.replace('#', ''), 16)
            except:
                color = C.BLURPLE
        
        # Sauvegarder les données et demander le salon
        announcement_data = {
            'title': self.title_input.value,
            'description': self.description_input.value,
            'color': color,
            'image_url': self.image_input.value or None,
            'mention': self.mention_input.value or None
        }
        
        v = AnnouncementPaginatedChannelView(self.u, self.g, announcement_data)
        await i.response.send_message("📍 **Sélectionnez le salon** où envoyer l'annonce:", view=v, ephemeral=True)


class AnnouncementPaginatedChannelView(View):
    """Sélection de salon paginée pour les annonces"""
    def __init__(self, u, g, data, page=0):
        super().__init__(timeout=120)
        self.u = u
        self.g = g
        self.data = data
        self.page = page
        self.per_page = 23
        self.channels = list(g.text_channels)
        self.max_page = max(0, (len(self.channels) - 1) // self.per_page)
        self._update_select()
    
    def _update_select(self):
        for item in self.children[:]:
            if isinstance(item, Select):
                self.remove_item(item)
        
        start = self.page * self.per_page
        end = start + self.per_page
        page_channels = self.channels[start:end]
        
        if page_channels:
            opts = [discord.SelectOption(
                label=f"# {ch.name}"[:25], 
                value=str(ch.id),
                description=f"Catégorie: {ch.category.name[:30] if ch.category else 'Aucune'}"
            ) for ch in page_channels]
            self.add_item(AnnouncementChannelSelectPaginated(self.u, self.g, opts, self.data))
    
    @discord.ui.button(label="◀️", style=discord.ButtonStyle.secondary, row=1)
    async def prev_page(self, i, b):
        if self.page > 0:
            self.page -= 1
            self._update_select()
        await i.response.edit_message(content=f"📍 **Sélectionnez le salon** (Page {self.page+1}/{self.max_page+1} - {len(self.channels)} salons):", view=self)
    
    @discord.ui.button(label="▶️", style=discord.ButtonStyle.secondary, row=1)
    async def next_page(self, i, b):
        if self.page < self.max_page:
            self.page += 1
            self._update_select()
        await i.response.edit_message(content=f"📍 **Sélectionnez le salon** (Page {self.page+1}/{self.max_page+1} - {len(self.channels)} salons):", view=self)
    
    @discord.ui.button(label="❌ Annuler", style=discord.ButtonStyle.danger, row=1)
    async def cancel(self, i, b):
        await i.response.edit_message(content="❌ Annulé", view=None)


class AnnouncementChannelSelectPaginated(Select):
    def __init__(self, u, g, opts, data):
        super().__init__(placeholder="Choisir un salon...", options=opts, row=0)
        self.u = u
        self.g = g
        self.data = data
    
    async def callback(self, i):
        channel_id = int(self.values[0])
        channel = self.g.get_channel(channel_id)
        
        if not channel:
            return await i.response.edit_message(content="❌ Salon introuvable", view=None)
        
        # Créer l'embed d'annonce
        e = discord.Embed(color=self.data['color'])
        e.set_author(name=f"📢 {self.g.name}", icon_url=self.g.icon.url if self.g.icon else None)
        
        e.title = self.data['title']
        e.description = self.data['description']
        
        if self.data['image_url']:
            e.set_image(url=self.data['image_url'])
        
        e.set_footer(text="Annonce officielle", icon_url=self.g.icon.url if self.g.icon else None)
        e.timestamp = now()
        
        mention_text = self.data.get('mention', '')
        
        try:
            await webhook_send(channel, 'announcement', content=mention_text if mention_text else None, embed=e)
            await i.response.edit_message(content=f"✅ **Annonce envoyée** dans {channel.mention}!", view=None)
        except discord.Forbidden:
            await i.response.edit_message(content="❌ Je n'ai pas la permission d'envoyer dans ce salon", view=None)
        except Exception as ex:
            await i.response.edit_message(content=f"❌ Erreur: {ex}", view=None)


# Ancien code conservé pour compatibilité
class AnnouncementChannelSelectView(View):
    def __init__(self, u, g, opts, data):
        super().__init__(timeout=120)
        self.add_item(AnnouncementChannelSelect(u, g, opts, data))

class AnnouncementChannelSelect(Select):
    def __init__(self, u, g, opts, data):
        super().__init__(placeholder="Choisir un salon...", options=opts)
        self.u = u
        self.g = g
        self.data = data
    
    async def callback(self, i):
        channel_id = int(self.values[0])
        channel = self.g.get_channel(channel_id)
        
        if not channel:
            return await i.response.edit_message(content="❌ Salon introuvable", view=None)
        
        # Créer l'embed d'annonce
        e = discord.Embed(color=self.data['color'])
        e.set_author(name=f"📢 {self.g.name}", icon_url=self.g.icon.url if self.g.icon else None)
        
        e.title = self.data['title']
        e.description = self.data['description']
        
        if self.data['image_url']:
            e.set_image(url=self.data['image_url'])
        
        e.set_footer(text=f"Par {self.u.display_name}", icon_url=self.u.display_avatar.url if self.u.display_avatar else None)
        e.timestamp = now()
        
        # Préparer le contenu de mention
        content = None
        mention = self.data.get('mention', '')
        if mention:
            mention_lower = mention.lower().strip()
            if mention_lower == '@everyone':
                content = "@everyone"
            elif mention_lower == '@here':
                content = "@here"
            elif mention.isdigit():
                content = f"<@&{mention}>"
        
        # Envoyer l'annonce
        try:
            await webhook_send(channel, 'announcement', content=content, embed=e)
            await i.response.edit_message(content=f"✅ **Annonce envoyée** dans {channel.mention} !", view=None)
        except Exception as ex:
            await i.response.edit_message(content=f"❌ Erreur: {ex}", view=None)

