class GiveawayPaginatedChannelView(View):
    """Sélection de salon paginée pour les giveaways"""
    def __init__(self, u, g, data, page=0):
        super().__init__(timeout=120)
        self.u = u
        self.g = g
        self.data = data
        self.page = page
        self.per_page = 23
        self.channels = list(g.text_channels)
        self.max_page = max(0, (len(self.channels) - 1) // self.per_page)
        self._update_select()
    
    def _update_select(self):
        for item in self.children[:]:
            if isinstance(item, Select):
                self.remove_item(item)
        
        start = self.page * self.per_page
        end = start + self.per_page
        page_channels = self.channels[start:end]
        
        if page_channels:
            opts = [discord.SelectOption(
                label=f"# {ch.name}"[:25], 
                value=str(ch.id),
                description=f"Cat: {ch.category.name[:25] if ch.category else 'Aucune'}"
            ) for ch in page_channels]
            self.add_item(GiveawayChannelSelectPaginated(self.u, self.g, opts, self.data))
    
    @discord.ui.button(label="◀️", style=discord.ButtonStyle.secondary, row=1)
    async def prev_page(self, i, b):
        if self.page > 0:
            self.page -= 1
            self._update_select()
        await i.response.edit_message(content=f"📢 **Sélectionnez le salon** (Page {self.page+1}/{self.max_page+1}):", view=self)
    
    @discord.ui.button(label="▶️", style=discord.ButtonStyle.secondary, row=1)
    async def next_page(self, i, b):
        if self.page < self.max_page:
            self.page += 1
            self._update_select()
        await i.response.edit_message(content=f"📢 **Sélectionnez le salon** (Page {self.page+1}/{self.max_page+1}):", view=self)


def _count_giveaway_conditions(conditions: dict) -> int:
    """Compte le nombre de conditions actives sur ce giveaway."""
    n = 0
    if conditions.get('min_messages', 0) > 0: n += 1
    if conditions.get('min_vocal_minutes', 0) > 0: n += 1
    if conditions.get('required_role', 0) > 0: n += 1
    if conditions.get('min_account_days', 0) > 0: n += 1
    if conditions.get('no_afk', False): n += 1
    return n


def _format_giveaway_conditions(conditions: dict, guild) -> str:
    """Format les conditions giveaway en texte propre (utilisé pour l'embed ephemeral)."""
    mode = conditions.get('condition_mode', 'OR')
    parts = []

    if conditions.get('min_messages', 0) > 0:
        parts.append(f"📝 **{conditions['min_messages']}**+ messages envoyés")
    if conditions.get('min_vocal_minutes', 0) > 0:
        parts.append(f"🎤 **{conditions['min_vocal_minutes']}**+ minutes en vocal")
    if conditions.get('required_role', 0) > 0:
        role = guild.get_role(conditions['required_role'])
        if role:
            parts.append(f"🎭 Avoir le rôle {role.mention}")
    if conditions.get('min_account_days', 0) > 0:
        parts.append(f"📅 Compte créé il y a ≥ **{conditions['min_account_days']}** jours")
    if conditions.get('no_afk', False):
        afk_days = conditions.get('afk_days', 7)
        parts.append(f"❌ Ne pas être AFK depuis **{afk_days}** jours")

    if not parts:
        return "✅ **Aucune condition** — tout le monde peut participer !"

    sep = "\n**OU** ".join if mode == 'OR' else "\n**ET** ".join
    header = (
        "📋 Conditions (mode **OU** — une seule suffit) :"
        if mode == 'OR'
        else "📋 Conditions (mode **ET** — toutes requises) :"
    )
    body = "\n".join(parts) if mode == 'AND' else " **OU**\n".join(parts)
    return f"{header}\n\n{body}"


def _build_giveaway_embed(data, guild, user, participants_count: int = 0):
    """Construit l'embed du giveaway (Phase 4.3 — refonte propre, conditions cachées).

    Les conditions ne sont PLUS affichées dans l'embed principal — uniquement
    un indicateur "N condition(s)". Le bouton 📋 Conditions sur la view envoie
    un message ephemeral détaillé au clicker.
    """
    end_time = now() + timedelta(seconds=data['duration_seconds'])
    conditions = data.get('conditions', {})

    e = discord.Embed(color=0xF1C40F)
    e.set_author(name="🎁 GIVEAWAY", icon_url=guild.icon.url if guild.icon else None)
    e.title = data['title']

    n_cond = _count_giveaway_conditions(conditions)
    cond_line = (
        f"📋 **Conditions** · `{n_cond}` à respecter — clique le bouton pour voir"
        if n_cond > 0
        else "✅ **Aucune condition** — ouvert à tous"
    )

    e.description = (
        f"{data['description']}\n\n"
        f"━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n"
        f"🏆 **Prix** · `{data['prize']}`\n"
        f"⏰ **Fin** · <t:{int(end_time.timestamp())}:R> · <t:{int(end_time.timestamp())}:f>\n"
        f"👥 **Participants** · `{participants_count}`\n"
        f"{cond_line}\n"
        f"━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━"
    )

    if data.get('image_url'):
        e.set_image(url=data['image_url'])

    e.set_footer(
        text=f"Par {user.display_name} · Bonne chance !",
        icon_url=user.display_avatar.url if user.display_avatar else None,
    )
    e.timestamp = now()
    return e, conditions


async def _publish_giveaway(data, guild, user, channel):
    """Publie un giveaway dans un salon et sauvegarde en BDD"""
    e, conditions = _build_giveaway_embed(data, guild, user)

    giveaway_view = GiveawayParticipateView()
    msg = await webhook_send(channel, 'giveaway', embed=e, view=giveaway_view)

    # Ping le rôle configuré
    ping_role_id = data.get('ping_role', 0)
    if ping_role_id:
        ping_role = guild.get_role(ping_role_id)
        if ping_role:
            try:
                await channel.send(ping_role.mention, delete_after=5)
            except:
                pass

    # Sauvegarder en BDD
    end_time = now() + timedelta(seconds=data['duration_seconds'])
    try:
        async with get_db() as db:
            await db.execute('''
                INSERT INTO giveaways (guild_id, channel_id, message_id, title, description, prize, image_url, end_time, conditions, created_by)
                VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            ''', (
                guild.id, channel.id, msg.id if msg else 0,
                data['title'], data['description'], data['prize'],
                data.get('image_url'), end_time.isoformat(),
                json.dumps(conditions),
                user.id
            ))
            await db.commit()
    except Exception as ex:
        print(f"Erreur sauvegarde giveaway: {ex}")

    return msg


class GiveawayChannelSelectPaginated(Select):
    def __init__(self, u, g, opts, data):
        super().__init__(placeholder="Choisir un salon...", options=opts, row=0)
        self.u = u
        self.g = g
        self.data = data

    async def callback(self, i):
        channel = self.g.get_channel(int(self.values[0]))
        if not channel:
            return await i.response.edit_message(content="❌ Salon introuvable", view=None)
        await _publish_giveaway(self.data, self.g, self.u, channel)
        await i.response.edit_message(content=f"✅ **Cadeau créé !** Publié dans {channel.mention}", view=None)

class GiveawayConditionModal(Modal):
    def __init__(self, panel, condition_key, label, placeholder):
        super().__init__(title=f"⚙️ {label}")
        self.panel = panel
        self.condition_key = condition_key
        
        current_val = self.panel.data.get('conditions', {}).get(condition_key, '')
        self.value_input = TextInput(
            label=label,
            placeholder=placeholder,
            required=False,
            default=str(current_val) if current_val else ""
        )
        self.add_item(self.value_input)
    
    async def on_submit(self, i):
        try:
            value = int(self.value_input.value) if self.value_input.value else 0
        except:
            value = 0
        
        if 'conditions' not in self.panel.data:
            self.panel.data['conditions'] = {}
        
        if value > 0:
            self.panel.data['conditions'][self.condition_key] = value
            # Gérer le cas spécial de no_afk
            if self.condition_key == 'afk_days':
                self.panel.data['conditions']['no_afk'] = True
        else:
            self.panel.data['conditions'].pop(self.condition_key, None)
            if self.condition_key == 'afk_days':
                self.panel.data['conditions']['no_afk'] = False
        
        await i.response.edit_message(embed=self.panel.embed(), view=self.panel)

class GiveawayRolePaginatedView(View):
    """Sélecteur de rôle paginé pour les giveaways — supporte TOUS les rôles du serveur"""
    def __init__(self, panel, role_key, title, page=0):
        super().__init__(timeout=180)
        self.panel = panel
        self.role_key = role_key  # 'required_role' ou 'ping_role'
        self.title = title
        self.page = page
        self.roles = [r for r in panel.g.roles if not r.is_default() and not r.is_bot_managed()]
        self.per_page = 23
        self.max_page = max(0, (len(self.roles) - 1) // self.per_page)
        self._build()

    def _build(self):
        self.clear_items()
        start = self.page * self.per_page
        end = start + self.per_page
        page_roles = self.roles[start:end]

        opts = []
        if self.page == 0:
            none_label = "❌ Aucun rôle requis" if self.role_key == 'required_role' else "❌ Aucun ping"
            opts.append(discord.SelectOption(label=none_label, value="0", emoji="🚫"))

        for r in page_roles:
            desc = f"{len(r.members)} membres"
            opts.append(discord.SelectOption(label=f"@{r.name}"[:25], value=str(r.id), description=desc))

        if opts:
            select = GiveawayRolePaginatedSelect(self, opts)
            self.add_item(select)

        if self.max_page > 0:
            prev_btn = discord.ui.Button(label="◀️", style=discord.ButtonStyle.primary, disabled=(self.page == 0), row=1)
            prev_btn.callback = self._prev
            self.add_item(prev_btn)
            page_btn = discord.ui.Button(label=f"{self.page+1}/{self.max_page+1}", style=discord.ButtonStyle.secondary, disabled=True, row=1)
            self.add_item(page_btn)
            next_btn = discord.ui.Button(label="▶️", style=discord.ButtonStyle.primary, disabled=(self.page >= self.max_page), row=1)
            next_btn.callback = self._next
            self.add_item(next_btn)

        back_btn = discord.ui.Button(label="◀️ Retour", style=discord.ButtonStyle.danger, row=2)
        back_btn.callback = self._back
        self.add_item(back_btn)

    async def _prev(self, i):
        self.page -= 1
        self._build()
        await i.response.edit_message(view=self)

    async def _next(self, i):
        self.page += 1
        self._build()
        await i.response.edit_message(view=self)

    async def _back(self, i):
        await i.response.edit_message(embed=self.panel.embed(), view=self.panel)


class GiveawayRolePaginatedSelect(Select):
    def __init__(self, parent, opts):
        placeholder = f"Page {parent.page+1}/{parent.max_page+1} — {parent.title}"[:100]
        super().__init__(placeholder=placeholder, options=opts)
        self.parent_view = parent

    async def callback(self, i):
        role_id = int(self.values[0])
        panel = self.parent_view.panel

        if self.parent_view.role_key == 'required_role':
            if 'conditions' not in panel.data:
                panel.data['conditions'] = {}
            if role_id > 0:
                panel.data['conditions']['required_role'] = role_id
            else:
                panel.data['conditions'].pop('required_role', None)
        elif self.parent_view.role_key == 'ping_role':
            if role_id > 0:
                panel.data['ping_role'] = role_id
            else:
                panel.data.pop('ping_role', None)

        await i.response.edit_message(embed=panel.embed(), view=panel)

def parse_duration_to_seconds(duration_str):
    """Convertit une durée (1h, 2d, etc.) en secondes"""
    import re
    total = 0
    matches = re.findall(r'(\d+)([smhdw])', duration_str)
    for value, unit in matches:
        value = int(value)
        if unit == 's':
            total += value
        elif unit == 'm':
            total += value * 60
        elif unit == 'h':
            total += value * 3600
        elif unit == 'd':
            total += value * 86400
        elif unit == 'w':
            total += value * 604800
    return total

