    async def add(self, i, b):
        c = await cfg(self.g.id)
        pnl = c.get('ticket_panels', {}).get(self.pid, {})
        if len(pnl.get('questions', [])) >= 5:
            return await i.response.send_message("❌ Maximum 5 questions", ephemeral=True)
