async def _handle_boost_started(member):
    """Envoie le message de boost configuré dans le salon défini."""
    try:
        c = await cfg(member.guild.id)
        if not c.get('boost_enabled', False):
            return
        ch_id = int(c.get('boost_channel', 0) or 0)
        if not ch_id:
            return
        ch = member.guild.get_channel(ch_id)
        if not ch:
            return

        # Vérifier permissions
        perms = ch.permissions_for(member.guild.me)
        if not (perms.send_messages and perms.embed_links):
            print(f"[BOOST] permissions manquantes dans #{ch.name}")
            return

        tpl = c.get('boost_message', '') or "🎉 Merci {user} pour le boost ! 💎"
        total_boosters = len([m for m in member.guild.members if m.premium_since])
        try:
            text = tpl.format(
                user=member.mention,
                user_name=member.display_name,
                count=member.guild.premium_subscription_count or 0,
                guild=member.guild.name,
                total_boosters=total_boosters,
            )
        except Exception as ex:
            text = (
                f"🎉 Merci {member.mention} pour le boost ! "
                f"💎 ({member.guild.premium_subscription_count or 0} boost(s))"
                f"\n_(erreur template : {ex})_"
            )

        # Embed riche
        e = discord.Embed(
            description=text,
            color=0xF47FFF,  # rose Nitro
            timestamp=now(),
        )
        e.set_author(name=f"💎 Nouveau boost !", icon_url=member.display_avatar.url)
        e.set_thumbnail(url=member.display_avatar.url)
        e.add_field(name="👤 Booster", value=member.mention, inline=True)
        e.add_field(name="💎 Boosts totaux", value=f"`{member.guild.premium_subscription_count or 0}`", inline=True)
        e.add_field(name="🎁 Boosters actifs", value=f"`{total_boosters}`", inline=True)
        e.set_footer(text=f"{member.guild.name}", icon_url=(member.guild.icon.url if member.guild.icon else None))

        await ch.send(content=member.mention, embed=e)

        # Log unifié
        try:
            await ulogger2026.log_event(
                bot, member.guild, ulogger2026.EventType.MEMBER_BOOSTED
                if hasattr(ulogger2026.EventType, 'MEMBER_BOOSTED')
                else ulogger2026.EventType.SEC_SPAM,
                title_override="💎 Boost serveur",
                description=f"{member.mention} a boosté le serveur ! ({member.guild.premium_subscription_count or 0} boosts au total)",
                user=member,
                channel=ch,
            )
        except Exception:
            pass

        print(f"[BOOST] {member} a boosté {member.guild.name} (total: {member.guild.premium_subscription_count})")
    except Exception as ex:
        print(f"[_handle_boost_started] {ex}")
        import traceback; traceback.print_exc()


@bot.event
async def on_member_join(m):
    # ═══ Tracking stats journalières ═══
    try:
        today = now().strftime('%Y-%m-%d')
        async with get_db() as db:
            await db.execute('''
                INSERT INTO daily_guild_stats (guild_id, date, new_members)
                VALUES (?, ?, 1)
                ON CONFLICT(guild_id, date) DO UPDATE SET new_members = new_members + 1
            ''', (m.guild.id, today))
            await db.commit()
    except: pass

    # ═══ Phase 147 : raid_detector smart (account-signature based) ═══
    # Ne déclenche QUE si plusieurs comptes suspects join en cluster.
    # Friendly aux surges légitimes (lives streaming → comptes variés).
    try:
        await raid_module.on_member_join(m)
    except Exception as ex:
        print(f"[on_member_join raid_module] {ex}")

    # ═══ Phase 153 : démarre le parcours d'onboarding ═══
    if not m.bot:
        try:
            await onboarding_module.start_for_member(m)
        except Exception as ex:
            print(f"[on_member_join onboarding] {ex}")

    # ═══ Phase 139 : Observabilité (join tracking pour retention) ═══
    try:
        await obs_module.record_join(m.guild.id, m.id)
    except Exception as ex:
        print(f"[on_member_join obs_record_join] {ex}")

    # ═══ Log unifié (Phase 3.7) ═══
    try:
        await ulogger2026.log_member_join(bot, m.guild, m)
    except Exception as ex:
        print(f"[UNIFIED LOG member_join] {ex}")
    
    try:
        c = await cfg(m.guild.id)
        guild_id = m.guild.id
        
        # ═══════════════ ANTI-RAID SYSTÈME ═══════════════
        if c.get('anti_raid'):
            raid_cfg = c.get('raid_config', {})
            join_threshold = raid_cfg.get('join_threshold', 10)
            join_interval = raid_cfg.get('join_interval', 10)
            min_account_age = raid_cfg.get('min_account_age', 7)
            auto_mode = raid_cfg.get('auto_mode', True)
            block_invites = raid_cfg.get('block_invites', True)
            action = raid_cfg.get('action', 'kick')
            
            # Initialiser le tracker si nécessaire
            if guild_id not in raid_tracker:
                raid_tracker[guild_id] = {'joins': [], 'lockdown': False, 'lockdown_at': None}
            
            current_time = now()
            
            # Auto-unlock lockdown après 5 minutes
            lockdown_at = raid_tracker[guild_id].get('lockdown_at')
            if raid_tracker[guild_id].get('lockdown') and lockdown_at:
                if (current_time - lockdown_at).total_seconds() > 300:
                    raid_tracker[guild_id]['lockdown'] = False
                    raid_tracker[guild_id]['lockdown_at'] = None
                    # Log auto-unlock
                    log_ch = m.guild.get_channel(c.get('log_anti_raid', 0))
                    if log_ch:
                        e = discord.Embed(
                            title="✅ Lockdown terminé",
                            description="Le mode lockdown anti-raid s'est désactivé automatiquement après 5 minutes.",
                            color=0x57F287
                        )
                        e.timestamp = current_time
                        try: await webhook_send(log_ch, 'raid_alert', embed=e)
                        except: pass
            
            # Nettoyer les anciennes entrées (hors intervalle)
            cutoff = current_time - timedelta(seconds=join_interval)
            raid_tracker[guild_id]['joins'] = [
                (uid, ts) for uid, ts in raid_tracker[guild_id]['joins']
                if ts > cutoff
            ]
            
            # Ajouter cette arrivée
            raid_tracker[guild_id]['joins'].append((m.id, current_time))
            
            # Vérifier l'âge du compte
            account_age = (current_time - m.created_at.replace(tzinfo=timezone.utc)).days
            is_suspicious = account_age < min_account_age
            
            # Vérifier si c'est un raid (trop de joins récents)
            recent_joins = len(raid_tracker[guild_id]['joins'])
            is_raid = recent_joins >= join_threshold
            
            # Si raid détecté → activer lockdown
            if is_raid and not raid_tracker[guild_id].get('lockdown', False):
                raid_tracker[guild_id]['lockdown'] = True
                raid_tracker[guild_id]['lockdown_at'] = current_time
                
                # Log + alerte
                log_ch = m.guild.get_channel(c.get('log_anti_raid', 0))
                if log_ch:
                    e = discord.Embed(
                        title="🚨 RAID DÉTECTÉ !",
                        description=f"**{recent_joins} membres** ont rejoint en moins de **{join_interval} secondes**\n\n"
                                    f"⚡ **Action auto:** {'Activée' if auto_mode else 'Désactivée'}\n"
                                    f"🔒 **Lockdown:** Activé (auto-désactivation dans 5 min)\n"
                                    f"🎯 **Action:** {action.upper()}",
                        color=0xFF0000
                    )
                    # Lister les derniers joins
                    recent = raid_tracker[guild_id]['joins'][-10:]
                    join_list = []
                    for uid, ts in recent:
                        member = m.guild.get_member(uid)
                        name = f"{member.name}" if member else f"ID:{uid}"
                        age = (current_time - ts).total_seconds()
                        join_list.append(f"`{name}` — il y a {int(age)}s")
                    if join_list:
                        e.add_field(name=f"👥 Derniers joins ({len(recent)})", value="\n".join(join_list[:10]), inline=False)
                    
                    e.set_footer(text="🛡️ Anti-Raid • /configure > Protection")
                    e.timestamp = current_time
                    await webhook_send(log_ch, 'raid_alert', content="@here" if auto_mode else "", embed=e)
            
            # Appliquer l'action si nécessaire
            should_act = (is_raid or is_suspicious) and (auto_mode or raid_tracker[guild_id].get('lockdown', False))
            
            if should_act:
                reason = f"Anti-Raid: {'Raid détecté' if is_raid else 'Compte suspect'} (âge: {account_age}j)"
                
                try:
                    if action == 'ban':
                        await m.ban(reason=reason)
                    elif action == 'kick':
                        await m.kick(reason=reason)
                    elif action == 'mute':
                        # Mute avec timeout
                        await m.timeout(timedelta(hours=24), reason=reason)
                    
                    # Log l'action
                    await send_log(m.guild, 'anti_raid', m, None, reason, f"Action: {action.upper()}")
                except:
                    pass
                
                return  # Ne pas continuer le traitement
        
        # ═══════════════ ANTI-NEWACCOUNT (standalone) ═══════════════
        if c.get('anti_newaccount'):
            days = c.get('newaccount_days', 7)
            age = (now() - m.created_at.replace(tzinfo=timezone.utc)).days
            if age < days:
                await send_log(m.guild, 'anti_newaccount', m, None, "Compte trop récent", f"Âge: {age} jour(s)")
                await m.kick(reason=f"Compte trop récent ({age} jours)")
                return  # Ne pas continuer
        
        # ═══════════════ ANTI-ALT (Comptes Secondaires) ═══════════════
        # Toujours sauvegarder le fingerprint du nouveau membre
        await save_user_fingerprint(m.guild.id, m)
        
        if c.get('anti_alt'):
            alt_cfg = c.get('alt_config', {})
            auto_action = alt_cfg.get('auto_action', False)
            min_confidence = alt_cfg.get('min_confidence', 70)
            action = c.get('alt_action', 'kick')
            
            # Détecter si c'est un compte secondaire
            is_alt, confidence, main_id, reasons = await detect_alt_account(m.guild, m)
            
            if is_alt and confidence >= min_confidence:
                # Envoyer le log
                main_member = m.guild.get_member(main_id)
                main_txt = f"{main_member.name} ({main_id})" if main_member else f"ID: {main_id} (banni/parti)"
                
                log_ch = m.guild.get_channel(c.get('log_anti_alt', 0))
                if log_ch:
                    e = discord.Embed(
                        title="👥 COMPTE SECONDAIRE DÉTECTÉ !",
                        description=f"**Compte secondaire:** {m.mention} (`{m.id}`)\n**Compte principal:** {main_txt}\n**Confiance:** {confidence}%",
                        color=0xE74C3C
                    )
                    e.add_field(name="📋 Raisons", value="\n".join([f"• {r}" for r in reasons[:5]]), inline=False)
                    e.add_field(name="⚡ Action auto", value="✅ Activée" if auto_action else "❌ Désactivée", inline=True)
                    e.set_thumbnail(url=m.display_avatar.url if m.display_avatar else None)
                    e.timestamp = now()
                    await webhook_send(log_ch, 'protection', embed=e)
                
                # Appliquer l'action automatique si activée
                if auto_action:
                    reason = f"Compte secondaire détecté (confiance: {confidence}%, principal: {main_id})"
                    try:
                        if action == 'ban':
                            await m.ban(reason=reason)
                        elif action == 'kick':
                            await m.kick(reason=reason)
                        elif action == 'mute':
                            await m.timeout(timedelta(hours=24), reason=reason)
                        
                        await update_alt_status(m.guild.id, m.id, 'actioned', action)
                        await send_log(m.guild, 'anti_alt', m, None, "Compte secondaire", f"Confiance: {confidence}%, Action: {action.upper()}")
                    except Exception as ex:
                        print(f"[ALT] Erreur action: {ex}")
                    
                    return  # Ne pas continuer

        # ═══════════════ AUTO-RÔLE D'ACTIVITÉ (donné dès l'arrivée) ═══════════════
        # Si un activity_role est configuré, on l'attribue automatiquement
        # au nouveau membre sans qu'il ait besoin d'envoyer un message au préalable.
        try:
            stat_cfg = c.get('stat_config', {})
            role_id = stat_cfg.get('activity_role', 0)
            if role_id:
                role = m.guild.get_role(role_id)
                if role and role not in m.roles and role < m.guild.me.top_role:
                    await m.add_roles(role, reason="Rôle d'activité automatique à l'arrivée")
        except discord.Forbidden:
            print(f"[AUTOROLE] Permission refusée pour {m} dans {m.guild.name}")
        except Exception as ex:
            print(f"[AUTOROLE] Erreur ajout rôle d'activité: {ex}")

    except Exception as ex:
        print(f"Erreur on_member_join: {ex}")

    # ═══ Phase 28.2 : Anti-Raid (nouveau système configurable) ═══
    try:
        await _handle_antiraid_join(m)
    except Exception as ex:
        print(f"[antiraid_join] {ex}")

    # ═══ Phase 28.3 : Welcome message ═══
    try:
        await _handle_welcome(m)
    except Exception as ex:
        print(f"[welcome] {ex}")

    # ═══ Phase 40 : Onboarding DM (3 min après l'arrivée, en background) ═══
    # ⚠️ AUDIT fix : on store la task dans un set pour éviter le GC mid-sleep
    try:
        t = asyncio.create_task(_send_onboarding_dm(m))
        _pending_onboardings.add(t)
        t.add_done_callback(_pending_onboardings.discard)
    except Exception as ex:
        print(f"[onboarding_dm schedule] {ex}")

    # ═══ Phase 64 : alt detection heuristic ═══
    try:
        await _check_alt_account(m)
    except Exception as ex:
        print(f"[_check_alt_account] {ex}")

    # ═══ Phase 49 : NPC greeting (proba 30% pour pas spammer) ═══
    try:
        if random.random() < 0.30:
            c2 = await cfg(m.guild.id)
            hub_id2 = int(c2.get('hub_channel', 0) or 0)
            hub_ch2 = m.guild.get_channel(hub_id2) if hub_id2 else None
            if hub_ch2 and await _is_chatty_channel(hub_ch2):
                # pick un NPC qui n'a pas accueilli quelqu'un dans les 6 dernières heures
                npc_choices = []
                for npc_id in lore.NPCS:
                    if not await _npc_recently_posted(m.guild.id, npc_id, hours=6):
                        npc_choices.append(npc_id)
                if npc_choices:
                    chosen = random.choice(npc_choices)
                    npc = lore.get_npc(chosen)
                    line = lore.pick_npc_line(chosen, 'new_member')
                    if npc and line:
                        # Replace mention "_un nouveau_" par le mention du membre quand cohérent
                        await _post_npc_line(
                            hub_ch2, chosen, 'new_member',
                            line=line,
                            extra_desc=f"👋 Bienvenue {m.mention} dans la guilde !",
                            ttl_seconds=2 * 3600,
                        )
    except Exception as ex:
        print(f"[npc greeting member_join] {ex}")


async def _handle_antiraid_join(member):
    """Phase 28.2 — détecte les raids et applique l'action configurée."""
    c = await cfg(member.guild.id)
    if not c.get('antiraid_enabled', False):
        return

    threshold = int(c.get('antiraid_join_threshold', 5))
    window = int(c.get('antiraid_join_window_sec', 10))
    min_age_days = int(c.get('antiraid_min_account_age_days', 7))
    action = str(c.get('antiraid_action', 'kick'))

    now_ts = time.time()
    joins = _recent_joins.setdefault(member.guild.id, [])
    # Purge anciens (garde uniquement les joins dans la fenêtre)
    cutoff = now_ts - window
    joins[:] = [entry for entry in joins if isinstance(entry, tuple) and entry[0] > cutoff]
    joins.append((now_ts, member.id))

    # Compte d'âge suspect ?
    account_age_days = (datetime.now(timezone.utc) - member.created_at).days
    is_suspect = account_age_days < min_age_days

    if len(joins) < threshold:
        return  # Pas encore raid

    # ── Raid détecté ──
    print(f"[ANTIRAID] guild={member.guild.id} {len(joins)} joins en {window}s → RAID")

    # Récupérer les membres récents pour action
    recent_member_ids = [mid for (_, mid) in joins[-threshold:]]
    recent_members = []
    for mid in recent_member_ids:
        m = member.guild.get_member(mid)
        if m and not m.bot and m.id != member.guild.owner_id:
            recent_members.append(m)

    # Appliquer l'action
    applied = 0
    failed = 0
    for m in recent_members:
        try:
            if action == 'kick':
                await m.kick(reason=f"Anti-Raid auto : {len(joins)} joins en {window}s")
            elif action == 'ban':
                await m.ban(reason=f"Anti-Raid auto : {len(joins)} joins en {window}s", delete_message_seconds=0)
            elif action == 'lockdown':
                # Lockdown = élève verification level + auto-restore après 10 min
                try:
                    previous_level = member.guild.verification_level
                    await member.guild.edit(verification_level=discord.VerificationLevel.highest, reason="Anti-Raid lockdown")
                    # Schedule restoration
                    async def _restore_lockdown(guild, prev):
                        try:
                            await asyncio.sleep(600)  # 10 minutes
                            await guild.edit(verification_level=prev, reason="Anti-Raid lockdown terminé")
                            print(f"[ANTIRAID] guild={guild.id} lockdown restauré à {prev}")
                        except Exception as ex:
                            print(f"[ANTIRAID restore] {ex}")
                    asyncio.create_task(_restore_lockdown(member.guild, previous_level))
                except Exception:
                    pass
                # Pas d'action sur le membre individuellement en lockdown mode
                break
            applied += 1
        except Exception as ex:
            print(f"[ANTIRAID action] {ex}")
            failed += 1

    # Log dans le salon dédié
    log_ch_id = int(c.get('antiraid_log_channel', 0) or 0)
    log_ch = member.guild.get_channel(log_ch_id) if log_ch_id else None
    if log_ch:
        try:
            e = discord.Embed(
                title="🚨 RAID DÉTECTÉ",
                description=(
                    f"**{len(joins)}** joins en `{window}`s (seuil : `{threshold}`)\n"
                    f"**Action** : `{action}` appliquée à `{applied}`/`{len(recent_members)}` membres"
                ),
                color=0xE74C3C,
                timestamp=datetime.now(timezone.utc),
            )
            e.add_field(name="🆕 Membres concernés", value="\n".join(f"• {m.mention} (`{m.id}`)" for m in recent_members[:10]) or "_aucun_", inline=False)
            if is_suspect:
                e.add_field(name="⚠️ Compte suspect", value=f"Le dernier compte a `{account_age_days}`j d'âge (seuil : `{min_age_days}`j)", inline=False)
            await log_ch.send(embed=e)
        except Exception as ex:
            print(f"[ANTIRAID log] {ex}")

    # Reset le tracker après action
    _recent_joins[member.guild.id] = []


async def _handle_welcome(member):
    """Phase 28.3 — envoie le message de welcome."""
    c = await cfg(member.guild.id)
    if not c.get('welcome_enabled', False):
        return
    ch_id = int(c.get('welcome_channel', 0) or 0)
    if not ch_id:
        return
    ch = member.guild.get_channel(ch_id)
    if not ch:
        return
    perms = ch.permissions_for(member.guild.me)
    if not (perms.send_messages and perms.embed_links):
        return
    tpl = c.get('welcome_message', '') or ''
    try:
        text = tpl.format(
            user=member.mention,
            user_name=member.display_name,
            guild=member.guild.name,
            count=member.guild.member_count or 0,
        )
    except Exception as ex:
        text = f"👋 Bienvenue {member.mention} ! _(erreur template: {ex})_"
    e = discord.Embed(description=text, color=0x57F287, timestamp=datetime.now(timezone.utc))
    e.set_author(name=f"👋 Bienvenue", icon_url=member.display_avatar.url)
    e.set_thumbnail(url=member.display_avatar.url)
    e.set_footer(text=f"{member.guild.name} · {member.guild.member_count} membres", icon_url=(member.guild.icon.url if member.guild.icon else None))
    try:
        await ch.send(content=member.mention, embed=e)
    except Exception as ex:
        print(f"[welcome send] {ex}")


