#                              📊 SUGGESTION VOTE TRACKING
# ═══════════════════════════════════════════════════════════════════════════════

async def _handle_reaction_role(payload, *, add: bool):
    """Phase 28.4 — applique/retire un rôle quand emoji = match."""
    try:
        if payload.user_id == bot.user.id or not payload.guild_id:
            return
        emoji_str = str(payload.emoji)
        async with get_db() as db:
            async with db.execute(
                'SELECT role_id FROM reaction_roles WHERE guild_id=? AND message_id=? AND emoji=?',
                (payload.guild_id, payload.message_id, emoji_str),
            ) as cur:
                row = await cur.fetchone()
        if not row:
            return
        role_id = int(row[0])
        guild = bot.get_guild(payload.guild_id)
        if not guild:
            return
        role = guild.get_role(role_id)
        if not role:
            return
        member = guild.get_member(payload.user_id)
        if not member or member.bot:
            return
        try:
            if add and role not in member.roles:
                await member.add_roles(role, reason="Reaction Role")
            elif not add and role in member.roles:
                await member.remove_roles(role, reason="Reaction Role (retrait)")
        except discord.Forbidden:
            print(f"[ReactionRole] perm refusée sur {role.name}")
        except Exception as ex:
            print(f"[ReactionRole] {ex}")
    except Exception as ex:
        print(f"[_handle_reaction_role] {ex}")


async def _update_suggestion_colors(payload):
    """Refresh la couleur de l'embed d'une suggestion en fonction des votes."""
    try:
        async with get_db() as db:
            async with db.execute('SELECT id FROM suggestions WHERE message_id=?', (payload.message_id,)) as c:
                if not await c.fetchone():
                    return

        channel = bot.get_channel(payload.channel_id)
        if not channel:
            return
        msg = await channel.fetch_message(payload.message_id)

        votes = {"✅": 0, "🟠": 0, "❌": 0}
        for reaction in msg.reactions:
            if reaction.emoji in votes:
                votes[reaction.emoji] = max(0, reaction.count - 1)

        total = sum(votes.values())
        if total == 0:
            color = C.BLURPLE
        elif votes["✅"] > votes["❌"] and votes["✅"] > votes["🟠"]:
            color = C.GREEN
        elif votes["❌"] > votes["✅"] and votes["❌"] > votes["🟠"]:
            color = C.RED
        elif votes["🟠"] > votes["✅"] and votes["🟠"] > votes["❌"]:
            color = C.ORANGE
        else:
            color = C.BLURPLE

        if msg.embeds:
            old_embed = msg.embeds[0]
            new_embed = discord.Embed(
                title=old_embed.title,
                description=old_embed.description,
                color=color,
                timestamp=old_embed.timestamp,
            )
            for field in old_embed.fields:
                new_embed.add_field(name=field.name, value=field.value, inline=field.inline)
            if old_embed.thumbnail:
                new_embed.set_thumbnail(url=old_embed.thumbnail.url)
            new_embed.set_footer(text=f"✅ {votes['✅']} | 🟠 {votes['🟠']} | ❌ {votes['❌']}")
            await msg.edit(embed=new_embed)
    except Exception:
        pass


@bot.event
async def on_raw_reaction_add(payload):
    if payload.user_id == bot.user.id:
        return

    # Phase 28.4 : Reaction Roles
    await _handle_reaction_role(payload, add=True)

    # Suggestions : refresh couleur
    await _update_suggestion_colors(payload)

    # Phase 41 : tracking quests + achievements
    try:
        await _track_reaction_p41(payload)
    except Exception as ex:
        print(f"[_track_reaction_p41] {ex}")

    # Phase 49 : tracking missions (étapes reactions_unique)
    try:
        await _track_reaction_for_missions(payload)
    except Exception as ex:
        print(f"[_track_reaction_for_missions] {ex}")

    # Phase 46.2 : Game Night sync_react tracking
    try:
        await _check_game_night_sync_react(payload)
    except Exception as ex:
        print(f"[_check_game_night_sync_react] {ex}")

@bot.event
async def on_raw_reaction_remove(payload):
    if payload.user_id == bot.user.id:
        return
    # Phase 28.4 : Reaction Roles (retrait du rôle uniquement, PAS add)
    await _handle_reaction_role(payload, add=False)
    # Suggestions : refresh couleur SANS re-ajouter le rôle
    await _update_suggestion_colors(payload)

