# Mise à jour activité sur vocal + Vocaux Temporaires
@bot.event
async def on_voice_state_update(member, before, after):
    if member.bot:
        return
    
    guild_id = member.guild.id
    user_id = member.id
    key = (guild_id, user_id)
    
    # ═══════════════ VOCAUX TEMPORAIRES (MULTI-HUBS) ═══════════════
    try:
        c = await cfg(guild_id)
        voice_cfg = c.get('temp_voice_config', {})
        
        if voice_cfg.get('enabled', False):
            hubs = voice_cfg.get('hubs', {})
            perms = voice_cfg.get('owner_permissions', {
                'can_rename': True, 'can_limit': True, 'can_mute': True, 'can_kick': True
            })
            
            # Vérifier si l'utilisateur rejoint un des hubs configurés
            if after.channel:
                hub_data = hubs.get(str(after.channel.id))
                
                if hub_data:
                    # C'est un hub configuré !
                    cat_id = hub_data.get('category', 0)
                    required_role_id = hub_data.get('required_role', 0)
                    default_name = hub_data.get('default_name', '🔊 Vocal de {user}')
                    
                    # Vérifier si le membre a le rôle requis (si défini)
                    if required_role_id:
                        required_role = member.guild.get_role(required_role_id)
                        if required_role and required_role not in member.roles:
                            # Le membre n'a pas le rôle requis → le déconnecter
                            try:
                                await member.move_to(None)
                                # Envoyer un message privé expliquant pourquoi
                                try:
                                    await member.send(
                                        f"❌ Vous ne pouvez pas créer de vocal dans ce hub.\n"
                                        f"🔒 Rôle requis: **{required_role.name}**\n"
                                        f"📍 Serveur: {member.guild.name}"
                                    )
                                except:
                                    pass  # DM désactivés
                                print(f"[TEMP VOICE] {member.display_name} expulsé du hub (rôle manquant: {required_role.name})")
                            except:
                                pass
                            return
                    
                    # Le membre peut créer un vocal
                    category = member.guild.get_channel(cat_id)
                    if category:
                        channel_name = default_name.replace('{user}', member.display_name)[:50]
                        # Phase 25 : taille (user_limit) configurable par hub
                        try:
                            default_user_limit = int(hub_data.get('default_limit', 0) or 0)
                            if default_user_limit < 0 or default_user_limit > 99:
                                default_user_limit = 0
                        except Exception:
                            default_user_limit = 0
                        
                        # Récupérer le rôle requis pour les permissions
                        required_role = member.guild.get_role(required_role_id) if required_role_id else None
                        
                        # Permissions de base
                        overwrites = {}
                        
                        if required_role:
                            # ═══ VOCAL RESTREINT AU RÔLE ═══
                            # @everyone ne peut PAS voir ni rejoindre le vocal
                            overwrites[member.guild.default_role] = discord.PermissionOverwrite(
                                view_channel=False,  # ❌ Invisible pour ceux sans le rôle
                                connect=False,
                                speak=False
                            )
                            
                            # Le rôle requis PEUT voir et rejoindre le vocal
                            overwrites[required_role] = discord.PermissionOverwrite(
                                view_channel=True,   # ✅ Visible pour ceux avec le rôle
                                connect=True,
                                speak=True,
                                use_voice_activation=True,
                                stream=True,
                                send_messages=False,
                                read_messages=True
                            )
                        else:
                            # ═══ VOCAL PUBLIC ═══
                            # @everyone peut voir et rejoindre
                            overwrites[member.guild.default_role] = discord.PermissionOverwrite(
                                view_channel=True,
                                connect=True,
                                speak=True,
                                use_voice_activation=True,
                                stream=True,
                                send_messages=False,
                                read_messages=True
                            )
                        
                        # Le propriétaire a toutes les permissions
                        overwrites[member] = discord.PermissionOverwrite(
                            view_channel=True,
                            connect=True,
                            speak=True,
                            use_voice_activation=True,
                            stream=True,
                            send_messages=False,
                            read_messages=True,
                            mute_members=perms.get('can_mute', True),
                            move_members=perms.get('can_kick', True),
                            manage_channels=perms.get('can_rename', True) or perms.get('can_limit', True)
                        )
                        
                        # Le bot a toutes les permissions
                        overwrites[member.guild.me] = discord.PermissionOverwrite(
                            view_channel=True,
                            connect=True,
                            speak=True,
                            manage_channels=True,
                            move_members=True,
                            send_messages=True
                        )
                        
                        new_channel = await member.guild.create_voice_channel(
                            name=channel_name,
                            category=category,
                            overwrites=overwrites,
                            user_limit=default_user_limit,
                        )
                        
                        temp_voice_channels[new_channel.id] = {
                            'owner': member.id,
                            'hub_id': after.channel.id,
                            'created_at': now()
                        }
                        
                        await member.move_to(new_channel)
                        print(f"[TEMP VOICE] Créé vocal '{channel_name}' pour {member.display_name} (hub: {after.channel.name})")
            
            # Si l'utilisateur quitte un vocal temporaire → vérifier si vide et supprimer
            if before.channel and before.channel.id in temp_voice_channels:
                await asyncio.sleep(1)
                
                try:
                    channel = member.guild.get_channel(before.channel.id)
                    if channel and len(channel.members) == 0:
                        await channel.delete(reason="Vocal temporaire vide")
                        del temp_voice_channels[before.channel.id]
                        print(f"[TEMP VOICE] Supprimé vocal vide: {before.channel.name}")
                except discord.NotFound:
                    if before.channel.id in temp_voice_channels:
                        del temp_voice_channels[before.channel.id]
                except Exception as ex:
                    print(f"[TEMP VOICE] Erreur suppression: {ex}")
                    
    except Exception as ex:
        print(f"Erreur temp voice: {ex}")
    
    # ═══════════════ TRACKING ACTIVITÉ VOCALE ═══════════════
    try:
        # Cas 1: L'utilisateur REJOINT un vocal (était pas en vocal ou change de salon)
        if after.channel and (before.channel is None or before.channel.id != after.channel.id):
            print(f"[VOCAL] {member.display_name} rejoint {after.channel.name}")
            
            # Enregistrer l'heure de connexion
            voice_join_tracker[key] = now()
            
            # Mettre à jour last_vocal et redonner le rôle si configuré
            await track_member_vocal_join(member, after.channel)
            await update_realsy_activity(guild_id, user_id)
        
        # Cas 2: L'utilisateur QUITTE un vocal (quitte complètement ou change de salon)
        if before.channel and (after.channel is None or before.channel.id != after.channel.id):
            print(f"[VOCAL] {member.display_name} quitte {before.channel.name}")
            
            # Calculer le temps passé
            join_time = voice_join_tracker.pop(key, None)
            if join_time:
                duration = int((now() - join_time).total_seconds())
                print(f"[VOCAL] Durée: {duration} secondes")
                if duration > 0:
                    await track_member_vocal_leave(member, before.channel, duration)
            else:
                print(f"[VOCAL] Pas de join_time trouvé pour {member.display_name}")
    except Exception as ex:
        print(f"Erreur tracking vocal: {ex}")

async def track_member_message(msg):
    """Enregistre un message dans le tracking d'activité.

    Phase 4.5 : si le système AFK est actif ET qu'une liste de salons surveillés
    est définie, seuls les messages dans ces salons mettent à jour `last_message`.
    Le compteur total_messages reste mis à jour partout (pour stats globales).
    """
    try:
        # Phase 4.5 : vérifier si le salon compte pour l'activité AFK
        afk_tracks_this_channel = True
        try:
            c = await cfg(msg.guild.id)
            afk_cfg = c.get('afk_role_config', {})
            if afk_cfg.get('enabled', False):
                tracked = afk_cfg.get('tracked_channels', []) or []
                if tracked and msg.channel.id not in tracked:
                    afk_tracks_this_channel = False
        except Exception:
            pass  # En cas d'erreur, on compte (fail-open)

        async with get_db() as db:
            now_str = now().isoformat()
            today = now().strftime('%Y-%m-%d')

            # Mettre à jour activity_tracking
            # Si AFK actif mais salon hors-liste : on incrémente total_messages
            # mais on NE met PAS à jour last_message (donc AFK continue à compter)
            if afk_tracks_this_channel:
                await db.execute('''
                    INSERT INTO activity_tracking (guild_id, user_id, last_message, total_messages)
                    VALUES (?, ?, ?, 1)
                    ON CONFLICT(guild_id, user_id) DO UPDATE SET
                        last_message = ?,
                        total_messages = total_messages + 1
                ''', (msg.guild.id, msg.author.id, now_str, now_str))
            else:
                # Incrémenter compteur uniquement (sans toucher last_message)
                await db.execute('''
                    INSERT INTO activity_tracking (guild_id, user_id, total_messages)
                    VALUES (?, ?, 1)
                    ON CONFLICT(guild_id, user_id) DO UPDATE SET
                        total_messages = total_messages + 1
                ''', (msg.guild.id, msg.author.id))
            
            # Enregistrer dans member_activity pour les stats détaillées
            await db.execute('''
                INSERT INTO member_activity (guild_id, user_id, activity_type, channel_id, message_id, created_at)
                VALUES (?, ?, 'message', ?, ?, ?)
            ''', (msg.guild.id, msg.author.id, msg.channel.id, msg.id, now_str))
            
            # ═══ Stats journalières agrégées (pour graphiques tendances) ═══
            await db.execute('''
                INSERT INTO daily_guild_stats (guild_id, date, total_messages, active_members)
                VALUES (?, ?, 1, 1)
                ON CONFLICT(guild_id, date) DO UPDATE SET
                    total_messages = total_messages + 1
            ''', (msg.guild.id, today))
            
            await db.commit()
        
        # ═══════════════ RESTAURATION DU RÔLE D'ACTIVITÉ ═══════════════
        # Si le membre a perdu son rôle d'activité à cause de l'AFK,
        # un simple message N'IMPORTE OÙ suffit à le récupérer
        try:
            c = await cfg(msg.guild.id)
            stat_cfg = c.get('stat_config', {})
            role_id = stat_cfg.get('activity_role', 0)
            if role_id:
                role = msg.guild.get_role(role_id)
                if role and role not in msg.author.roles:
                    try:
                        await msg.author.add_roles(role, reason="Retour d'activité via message")
                    except discord.Forbidden:
                        print(f"[ACTIVITY] Permission refusée pour rôle {role.name} à {msg.author}")
                    except Exception as ex:
                        print(f"[ACTIVITY] Erreur ajout rôle: {ex}")
        except:
            pass
        
        # ═══════════════ NOUVEAU SYSTÈME DE NIVEAUX ═══════════════
        try:
            c = await cfg(msg.guild.id)
            level_cfg = c.get('level_config', {})
            
            # Vérifier si le système est activé
            if not level_cfg.get('enabled', False):
                return
            
            # ═══════════════ VÉRIFIER SI LE SALON EST AUTORISÉ ═══════════════
            xp_text_channels = level_cfg.get('xp_text_channels', [])
            if xp_text_channels and msg.channel.id not in xp_text_channels:
                return  # Salon non autorisé, pas de gains
            
            # Ajouter de l'XP
            xp_per_msg = level_cfg.get('xp_per_message', 15)
            if xp_per_msg > 0:
                new_level = await add_xp(msg.guild.id, msg.author.id, xp_per_msg)
                
                # Si level up
                if new_level:
                    # Annoncer le level up
                    levelup_ch_id = level_cfg.get('levelup_channel', 0)
                    levelup_ch = msg.guild.get_channel(levelup_ch_id) if levelup_ch_id else msg.channel
                    
                    e = discord.Embed(color=0xF1C40F, timestamp=now())
                    e.set_author(name="⭐ Level Up !", icon_url=msg.author.display_avatar.url if msg.author.display_avatar else None)
                    e.description = f"🎉 {msg.author.mention} est passé au **niveau {new_level}** !"
                    e.set_thumbnail(url=msg.author.display_avatar.url if msg.author.display_avatar else None)
                    e.set_footer(text=msg.author.display_name, icon_url=msg.guild.icon.url if msg.guild.icon else None)
                    
                    try:
                        _lu = await webhook_send(levelup_ch, 'level_up', embed=e)
                        if _lu:
                            async def _del(m): 
                                await asyncio.sleep(30)
                                try: await m.delete()
                                except: pass
                            asyncio.create_task(_del(_lu))
                    except:
                        pass
                    
                    # Vérifier les récompenses de niveau
                    async with get_db() as db:
                        async with db.execute('SELECT role_id FROM level_rewards WHERE guild_id=? AND level=?', (msg.guild.id, new_level)) as cursor:
                            row = await cursor.fetchone()
                            if row:
                                role = msg.guild.get_role(row[0])
                                if role:
                                    try:
                                        await msg.author.add_roles(role, reason=f"Récompense niveau {new_level}")
                                    except:
                                        pass
            
            # Ajouter des pièces (basé sur le nombre de messages)
            coins_per_messages = level_cfg.get('coins_per_messages', 1)
            coins_amount = level_cfg.get('coins_amount', 1)
            
            if coins_per_messages > 0 and coins_amount > 0:
                # Récupérer le compteur de messages pour les pièces
                eco = await get_user_economy(msg.guild.id, msg.author.id)
                msg_count = eco.get('message_count', 0) + 1
                
                if msg_count >= coins_per_messages:
                    # Donner les pièces et réinitialiser le compteur
                    await add_coins(msg.guild.id, msg.author.id, coins_amount)
                    await update_user_economy(msg.guild.id, msg.author.id, message_count=0)
                else:
                    # Incrémenter le compteur
                    await update_user_economy(msg.guild.id, msg.author.id, message_count=msg_count)
        except Exception as ex:
            print(f"Erreur level system: {ex}")
    except:
        pass

async def handle_recovery_message(msg, stat_cfg):
    """Gère un message dans le salon de récupération - supprime le message et redonne le rôle"""
    try:
        role_id = stat_cfg.get('activity_role', 0)
        
        role = msg.guild.get_role(role_id) if role_id else None
        
        # ═══════════════ ÉTAPE 1: METTRE À JOUR L'ACTIVITÉ EN PREMIER ═══════════════
        now_str = now().isoformat()
        async with get_db() as db:
            await db.execute('''
                INSERT INTO activity_tracking (guild_id, user_id, last_message, total_messages)
                VALUES (?, ?, ?, 1)
                ON CONFLICT(guild_id, user_id) DO UPDATE SET
                    last_message = ?,
                    total_messages = total_messages + 1
            ''', (msg.guild.id, msg.author.id, now_str, now_str))
            await db.commit()
        
        # ═══════════════ ÉTAPE 2: REDONNER LE RÔLE ═══════════════
        if role and role not in msg.author.roles:
            try:
                await msg.author.add_roles(role, reason="Récupération d'activité via salon dédié")
                print(f"[RECOVERY] Rôle {role.name} redonné à {msg.author} dans {msg.guild.name}")
            except discord.Forbidden:
                print(f"[RECOVERY] Permission refusée pour ajouter le rôle {role.name} à {msg.author}")
            except Exception as ex:
                print(f"[RECOVERY] Erreur ajout rôle: {ex}")
        elif not role:
            print(f"[RECOVERY] Aucun rôle d'activité configuré (role_id={role_id})")

        # ═══════════════ ÉTAPE 3: SUPPRIMER LE MESSAGE ═══════════════
        try:
            await msg.delete()
        except:
            pass

    except Exception as ex:
        print(f"Erreur handle_recovery_message: {ex}")

async def track_member_vocal_join(member, channel):
    """Enregistre une connexion vocale"""
    try:
        async with get_db() as db:
            now_str = now().isoformat()
            
            # Mettre à jour last_vocal
            await db.execute('''
                INSERT INTO activity_tracking (guild_id, user_id, last_vocal)
                VALUES (?, ?, ?)
                ON CONFLICT(guild_id, user_id) DO UPDATE SET
                    last_vocal = ?
            ''', (member.guild.id, member.id, now_str, now_str))
            
            await db.commit()
        
        # Redonner le rôle d'activité si configuré
        await restore_activity_role(member)
        
    except Exception as ex:
        print(f"Erreur track vocal join: {ex}")

async def track_member_vocal_leave(member, channel, duration):
    """Enregistre le temps passé en vocal et donne XP/pièces"""
    try:
        async with get_db() as db:
            now_str = now().isoformat()
            
            # Mettre à jour le temps total en vocal
            await db.execute('''
                INSERT INTO activity_tracking (guild_id, user_id, total_vocal_time)
                VALUES (?, ?, ?)
                ON CONFLICT(guild_id, user_id) DO UPDATE SET
                    total_vocal_time = COALESCE(total_vocal_time, 0) + ?
            ''', (member.guild.id, member.id, duration, duration))
            
            # Enregistrer la session vocale
            await db.execute('''
                INSERT INTO member_activity (guild_id, user_id, activity_type, channel_id, duration, created_at)
                VALUES (?, ?, 'vocal', ?, ?, ?)
            ''', (member.guild.id, member.id, channel.id, duration, now_str))
            
            await db.commit()
            print(f"[VOCAL DB] Enregistré {duration}s pour {member.display_name} dans {channel.name}")
        
        # ═══════════════ XP ET PIÈCES VOCAUX ═══════════════
        try:
            c = await cfg(member.guild.id)
            level_cfg = c.get('level_config', {})
            
            if level_cfg.get('enabled', False) and duration > 0:
                # ═══════════════ VÉRIFIER SI LE SALON EST AUTORISÉ ═══════════════
                xp_voice_channels = level_cfg.get('xp_voice_channels', [])
                if xp_voice_channels and channel.id not in xp_voice_channels:
                    print(f"[VOCAL] Salon {channel.name} non autorisé pour XP/pièces")
                    return  # Salon non autorisé, pas de gains
                
                # Fonction pour convertir la durée selon l'unité
                def get_units(seconds, unit):
                    if unit == 'minute':
                        return seconds // 60
                    elif unit == 'hour':
                        return seconds // 3600
                    elif unit == 'day':
                        return seconds // 86400
                    return seconds // 60  # Par défaut en minutes
                
                # XP Vocal
                xp_per_vocal = level_cfg.get('xp_per_vocal', level_cfg.get('xp_per_vocal_minute', 5))
                xp_vocal_unit = level_cfg.get('xp_vocal_unit', 'minute')
                xp_units = get_units(duration, xp_vocal_unit)
                
                if xp_units > 0 and xp_per_vocal > 0:
                    total_xp = xp_units * xp_per_vocal
                    print(f"[VOCAL XP] {member.display_name}: {xp_units} {xp_vocal_unit}s x {xp_per_vocal} = {total_xp} XP")
                    new_level = await add_xp(member.guild.id, member.id, total_xp)
                    
                    # Si level up
                    if new_level:
                        levelup_ch_id = level_cfg.get('levelup_channel', 0)
                        levelup_ch = member.guild.get_channel(levelup_ch_id) if levelup_ch_id else None
                        
                        if levelup_ch:
                            e = discord.Embed(color=0xF1C40F, timestamp=now())
                            e.set_author(name="⭐ Level Up !", icon_url=member.display_avatar.url if member.display_avatar else None)
                            e.description = f"🎉 {member.mention} est passé au **niveau {new_level}** !"
                            e.set_thumbnail(url=member.display_avatar.url if member.display_avatar else None)
                            e.set_footer(text=f"🎤 Temps en vocal: {duration // 60} min", icon_url=member.guild.icon.url if member.guild.icon else None)
                            try:
                                _lu = await webhook_send(levelup_ch, 'level_up', embed=e)
                                if _lu:
                                    async def _del2(m): 
                                        await asyncio.sleep(30)
                                        try: await m.delete()
                                        except: pass
                                    asyncio.create_task(_del2(_lu))
                            except:
                                pass
                        
                        # Vérifier les récompenses de niveau
                        async with get_db() as db:
                            async with db.execute('SELECT role_id FROM level_rewards WHERE guild_id=? AND level=?', (member.guild.id, new_level)) as cursor:
                                row = await cursor.fetchone()
                                if row:
                                    role = member.guild.get_role(row[0])
                                    if role:
                                        try:
                                            await member.add_roles(role, reason=f"Récompense niveau {new_level}")
                                        except:
                                            pass
                
                # Pièces Vocal
                coins_per_vocal = level_cfg.get('coins_per_vocal', level_cfg.get('coins_per_vocal_minute', 1))
                coins_vocal_unit = level_cfg.get('coins_vocal_unit', 'minute')
                coins_units = get_units(duration, coins_vocal_unit)
                
                if coins_units > 0 and coins_per_vocal > 0:
                    total_coins = coins_units * coins_per_vocal
                    print(f"[VOCAL COINS] {member.display_name}: {coins_units} {coins_vocal_unit}s x {coins_per_vocal} = {total_coins} pièces")
                    await add_coins(member.guild.id, member.id, total_coins)
        except Exception as ex:
            print(f"Erreur XP/coins vocal: {ex}")
            
    except Exception as ex:
        print(f"Erreur track vocal leave: {ex}")

async def restore_activity_role(member):
    """Redonne le rôle d'activité si le membre rejoint un vocal"""
    try:
        c = await cfg(member.guild.id)
        stat_cfg = c.get('stat_config', {})
        role_id = stat_cfg.get('activity_role', 0)
        
        if not role_id:
            return
        
        role = member.guild.get_role(role_id)
        if not role:
            return
        
        # ═══════════════ ENREGISTRER L'ACTIVITÉ ═══════════════
        now_str = now().isoformat()
        async with get_db() as db:
            await db.execute('''
                INSERT INTO activity_tracking (guild_id, user_id, last_vocal)
                VALUES (?, ?, ?)
                ON CONFLICT(guild_id, user_id) DO UPDATE SET
                    last_vocal = ?
            ''', (member.guild.id, member.id, now_str, now_str))
            await db.commit()
        
        # Redonner le rôle silencieusement
        if role not in member.roles:
            try:
                await member.add_roles(role, reason="Retour d'activité via vocal")
            except:
                pass
                
    except Exception as ex:
        print(f"Erreur restore role: {ex}")

# ═══════════════════════════════════════════════════════════════════════════════
#                           🎁 TÂCHE AUTOMATIQUE GIVEAWAYS
# ═══════════════════════════════════════════════════════════════════════════════

@tasks.loop(seconds=30)
async def check_giveaways():
    """Vérifie et termine les giveaways expirés"""
    try:
        now_dt = now()
        
        async with get_db() as db:
            # Récupérer les giveaways à terminer
            async with db.execute(
                'SELECT id, guild_id, channel_id, message_id, title, prize, participants FROM giveaways WHERE ended=0 AND end_time <= ?',
                (now_dt.isoformat(),)
            ) as cursor:
                giveaways_to_end = []
                async for row in cursor:
                    giveaways_to_end.append(row)
            
            # Terminer chaque giveaway
            for gw_id, guild_id, channel_id, message_id, title, prize, participants_str in giveaways_to_end:
                try:
                    guild = bot.get_guild(guild_id)
                    if not guild:
                        continue
                    
                    channel = guild.get_channel(channel_id)
                    if not channel:
                        continue
                    
                    participants = json.loads(participants_str) if participants_str else []
                    
                    # Marquer comme terminé
                    await db.execute('UPDATE giveaways SET ended=1 WHERE id=?', (gw_id,))
                    
                    if not participants:
                        # Pas de participants
                        e = discord.Embed(color=0xE74C3C)
                        e.set_author(name="🎁 GIVEAWAY TERMINÉ", icon_url=guild.icon.url if guild.icon else None)
                        e.title = title
                        e.description = (
                            f"━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n"
                            f"❌ **Aucun participant !**\n"
                            f"Le cadeau n'a pas pu être attribué.\n"
                            f"━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━"
                        )
                        e.set_footer(text="Giveaway terminé")
                        e.timestamp = now()
                        
                        try:
                            await webhook_edit(channel, 'giveaway', message_id, embed=e, view=None)
                        except:
                            pass
                    else:
                        # Tirer un gagnant
                        import random
                        winner_id = random.choice(participants)
                        winner = guild.get_member(winner_id)
                        winner_txt = winner.mention if winner else f'<@{winner_id}>'
                        
                        e = discord.Embed(color=0xF1C40F)
                        e.set_author(name="🎁 GIVEAWAY TERMINÉ", icon_url=guild.icon.url if guild.icon else None)
                        e.title = title
                        e.description = (
                            f"━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n"
                            f"🏆 **Gagnant :** {winner_txt}\n"
                            f"🎁 **Prix :** `{prize}`\n"
                            f"👥 **Participants :** `{len(participants)}`\n"
                            f"━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━"
                        )
                        e.set_footer(text="🎉 Félicitations au gagnant !")
                        e.timestamp = now()
                        
                        try:
                            await webhook_edit(channel, 'giveaway', message_id, embed=e, view=None)
                            
                            win_e = discord.Embed(color=0xF1C40F)
                            win_e.set_author(name="🎉 GAGNANT ANNONCÉ !", icon_url=guild.icon.url if guild.icon else None)
                            win_e.description = (
                                f"Félicitations {winner_txt} !\n\n"
                                f"Tu as gagné **{title}** 🏆\n"
                                f"Prix : `{prize}`"
                            )
                            if winner and winner.display_avatar:
                                win_e.set_thumbnail(url=winner.display_avatar.url)
                            win_e.set_footer(text=f"Merci aux {len(participants)} participants !")
                            win_e.timestamp = now()
                            await webhook_send(channel, 'giveaway', embed=win_e)
                        except:
                            pass
                    
                except Exception as ex:
                    print(f"Erreur fin giveaway {gw_id}: {ex}")
            
            await db.commit()
            
    except Exception as ex:
        print(f"Erreur tâche giveaways: {ex}")

@check_giveaways.before_loop
async def before_check_giveaways():
    await bot.wait_until_ready()

# ═══════════════════════════════════════════════════════════════════════════════
#                           📨 TÂCHE AUTOMATIQUE MESSAGES PROGRAMMÉS
# ═══════════════════════════════════════════════════════════════════════════════

@tasks.loop(minutes=1)
async def check_scheduled_messages():
    """Vérifie et envoie les messages programmés"""
    try:
        now_dt = now()
        current_hour = now_dt.hour
        current_minute = now_dt.minute
        
        async with get_db() as db:
            # Récupérer tous les messages actifs
            async with db.execute(
                'SELECT id, guild_id, channel_id, title, description, color, image_url, footer, frequency, frequency_value, send_hour, send_minute, last_sent FROM scheduled_messages WHERE enabled=1'
            ) as cursor:
                messages = []
                async for row in cursor:
                    messages.append(row)
            
            for msg_id, guild_id, channel_id, title, description, color, image_url, footer, frequency, freq_val, send_hour, send_minute, last_sent_str in messages:
                try:
                    # Calculer l'intervalle minimum selon la fréquence
                    if frequency == 'minutes':
                        min_interval = timedelta(minutes=max(1, freq_val))
                    elif frequency == 'hourly':
                        min_interval = timedelta(hours=max(1, freq_val))
                    elif frequency == 'daily':
                        min_interval = timedelta(days=max(1, freq_val))
                    elif frequency == 'weekly':
                        min_interval = timedelta(weeks=max(1, freq_val))
                    else:
                        continue

                    # Pour daily/weekly: vérifier heure ET minute exactes
                    # Pour minutes/hourly: pas de gate horaire, on utilise seulement l'intervalle
                    if frequency in ('daily', 'weekly'):
                        if current_hour != send_hour or current_minute != send_minute:
                            continue

                    # Vérifier le dernier envoi (intervalle minimum)
                    if last_sent_str:
                        try:
                            last_sent = datetime.fromisoformat(last_sent_str)
                            if now_dt - last_sent < min_interval:
                                continue
                        except:
                            pass
                    
                    # Envoyer le message
                    guild = bot.get_guild(guild_id)
                    if not guild:
                        continue
                    
                    channel = guild.get_channel(channel_id)
                    if not channel:
                        continue
                    
                    # Créer l'embed
                    try:
                        embed_color = int(color.replace('#', ''), 16) if color else C.BLURPLE
                    except:
                        embed_color = C.BLURPLE
                    
                    e = discord.Embed(title=title, description=description, color=embed_color)
                    
                    if image_url:
                        e.set_image(url=image_url)
                    
                    if footer:
                        e.set_footer(text=footer)
                    
                    e.timestamp = now()
                    
                    await webhook_send(channel, 'auto_message', embed=e)
                    
                    # Mettre à jour last_sent
                    await db.execute(
                        'UPDATE scheduled_messages SET last_sent=? WHERE id=?',
                        (now_dt.isoformat(), msg_id)
                    )
                    
                except Exception as ex:
                    print(f"Erreur message programmé {msg_id}: {ex}")
            
            await db.commit()
            
    except Exception as ex:
        print(f"Erreur tâche messages programmés: {ex}")

@check_scheduled_messages.before_loop
async def before_check_scheduled_messages():
    await bot.wait_until_ready()

# ═══════════════════════════════════════════════════════════════════════════════
#                           📈 COMMANDES NIVEAU & BOUTIQUE
# ═══════════════════════════════════════════════════════════════════════════════

async def check_level_channel(i):
    """Vérifie si la commande peut être utilisée dans ce salon"""
    c = await cfg(i.guild.id)
    level_cfg = c.get('level_config', {})
    allowed = level_cfg.get('allowed_channels', [])
    
    if allowed and i.channel.id not in allowed:
        mentions = ", ".join([f"<#{ch}>" for ch in allowed[:3]])
        await i.response.send_message(f"❌ Cette commande n'est utilisable que dans: {mentions}", ephemeral=True)
        return False
    return True

def create_progress_bar(current, total, length=20):
    """Crée une barre de progression visuelle"""
    filled = int(length * current / total) if total > 0 else 0
    empty = length - filled
    return "█" * filled + "░" * empty

@bot.tree.command(name="level", description="📈 Voir votre progression de niveau")
@app_commands.describe(membre="Le membre dont vous voulez voir le niveau")
async def level_cmd(i: discord.Interaction, membre: discord.Member = None):
    # Vérifier le salon
    if not await check_level_channel(i):
        return

    # Vérifier si le système est activé
    c = await cfg(i.guild.id)
    level_cfg = c.get('level_config', {})
    if not level_cfg.get('enabled', False):
        return await i.response.send_message("❌ Le système de niveaux n'est pas activé", ephemeral=True)

    target = membre or i.user
    eco = await get_user_economy(i.guild.id, target.id)

    current_level = eco['level']
    current_xp = eco['xp']
    xp_progress = current_xp % 100 if current_level > 1 else current_xp
    xp_needed = 100
    progress_bar = create_progress_bar(xp_progress, xp_needed)
    percentage = int((xp_progress / xp_needed) * 100) if xp_needed > 0 else 0

    # Prochaine récompense de rôle
    async with get_db() as db:
        async with db.execute(
            'SELECT level, role_id FROM level_rewards WHERE guild_id=? AND level > ? ORDER BY level LIMIT 1',
            (i.guild.id, current_level)
        ) as cursor:
            next_reward = await cursor.fetchone()

    # ─── Construction du LayoutView V2 ───
    items = [
        v2_section(
            v2_title(f"📈 Niveau de {target.display_name}"),
            v2_body(f"🏆 Niveau **{current_level}**  ·  ✨ **{current_xp} XP**  ·  🪙 **{eco['coins']} pièces**"),
            accessory=v2_thumb(target.display_avatar.url),
        ),
        v2_divider(),
        v2_title(f"Progression — niveau {current_level + 1}", level=2),
        v2_body(f"`{progress_bar}` **{percentage}%**"),
        v2_subtitle(f"{xp_progress} / {xp_needed} XP avant le prochain niveau"),
    ]

    if next_reward:
        role = i.guild.get_role(next_reward[1])
        if role:
            items.append(v2_divider())
            items.append(v2_title("🎁 Prochain rôle débloqué", level=3))
            items.append(v2_body(f"Niveau **{next_reward[0]}** → {role.mention}"))

    items.append(v2_divider())
    items.append(v2_subtitle(f"Gain : {level_cfg.get('xp_per_message', 15)} XP par message"))

    view = LayoutView(timeout=None)
    view.add_item(v2_container(*items, color=Palette.PRIMARY))
    await i.response.send_message(view=view)

@bot.tree.command(name="shop", description="🛒 Ouvrir la boutique")
async def shop_cmd(i: discord.Interaction):
    # Vérifier le salon
    if not await check_level_channel(i):
        return

    # Vérifier si le système est activé
    c = await cfg(i.guild.id)
    level_cfg = c.get('level_config', {})
    if not level_cfg.get('enabled', False):
        return await i.response.send_message("❌ Le système de niveaux n'est pas activé", ephemeral=True)

    shop_items = level_cfg.get('shop_items', [])
    if not shop_items:
        return await i.response.send_message("❌ La boutique est vide", ephemeral=True)

    eco = await get_user_economy(i.guild.id, i.user.id)
    view = ShopV2View(i.user, i.guild, shop_items, eco['coins'])
    await i.response.send_message(view=view, ephemeral=True)


class ShopV2View(LayoutView):
    """Boutique V2 — Container + ActionRow(Select) en un seul LayoutView."""

    def __init__(self, user, guild, items, coins):
        super().__init__(timeout=120)
        self.user = user
        self.guild = guild
        self.items = items
        self.coins = coins

        # Lignes d'affichage des articles (max 10 visibles)
        item_lines = []
        for idx, item in enumerate(items[:10]):
            role = guild.get_role(item.get('role_id', 0))
            price = item.get('price', 0)
            duration = item.get('duration', 3600)
            dur_txt = format_duration(duration)
            mark = "✅" if coins >= price else "❌"
            item_lines.append(
                f"{mark} **{role.name if role else '?'}** · `{price:,}` 🪙 · {dur_txt}"
            )

        # Options du Select (max 25 selon Discord)
        opts = []
        for idx, item in enumerate(items[:25]):
            role = guild.get_role(item.get('role_id', 0))
            price = item.get('price', 0)
            duration = item.get('duration', 3600)
            dur_txt = format_duration(duration)
            can_afford = coins >= price
            label = f"{role.name if role else '?'} - {price} 🪙"
            desc = f"Durée: {dur_txt}" + (" (pas assez)" if not can_afford else "")
            opts.append(discord.SelectOption(
                label=label[:100],
                value=str(idx),
                description=desc[:100],
                emoji="✅" if can_afford else "❌",
            ))

        # Construction du Container
        children = [
            v2_title("🛒 Boutique"),
            v2_subtitle(f"💰 Vos pièces : {coins:,} 🪙"),
            v2_divider(),
            v2_body("\n".join(item_lines) if item_lines else "_Aucun article disponible_"),
        ]
        if opts:
            children.append(v2_divider())
            children.append(v2_subtitle("Sélectionnez un article ci-dessous pour l'acheter"))
            sel = Select(placeholder="Choisir un article...", options=opts)
            sel.callback = self.purchase_callback
            children.append(discord.ui.ActionRow(sel))

        self.add_item(v2_container(*children, color=Palette.PREMIUM))

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        if interaction.user.id != self.user.id:
            await interaction.response.send_message("❌ Ce n'est pas votre boutique", ephemeral=True)
            return False
        return True

    async def purchase_callback(self, interaction: discord.Interaction):
        idx = int(interaction.data['values'][0])
        if idx >= len(self.items):
            return await interaction.response.send_message("❌ Article invalide", ephemeral=True)

        item = self.items[idx]
        price = item.get('price', 0)
        duration = item.get('duration', 3600)
        role_id = item.get('role_id', 0)

        # Vérifier les pièces
        eco = await get_user_economy(self.guild.id, interaction.user.id)
        if eco['coins'] < price:
            return await interaction.response.send_message(
                f"❌ Vous n'avez pas assez de pièces ({eco['coins']}/{price})", ephemeral=True
            )

        role = self.guild.get_role(role_id)
        if not role:
            return await interaction.response.send_message("❌ Rôle introuvable", ephemeral=True)

        # Retirer les pièces
        await add_coins(self.guild.id, interaction.user.id, -price)

        # Donner le rôle (rembourser si échec)
        try:
            await interaction.user.add_roles(role, reason=f"Achat boutique - {price} pièces")
        except discord.Forbidden:
            await add_coins(self.guild.id, interaction.user.id, price)
            return await interaction.response.send_message(
                "❌ Le bot n'a pas la permission d'attribuer ce rôle", ephemeral=True
            )
        except Exception as ex:
            await add_coins(self.guild.id, interaction.user.id, price)
            print(f"[SHOP] Erreur ajout rôle: {ex}")
            return await interaction.response.send_message("❌ Impossible d'ajouter le rôle", ephemeral=True)

        # Enregistrer l'achat pour retrait automatique
        expires_at = now() + timedelta(seconds=duration)
        async with get_db() as db:
            await db.execute(
                'INSERT INTO shop_purchases (guild_id, user_id, role_id, expires_at) VALUES (?, ?, ?, ?)',
                (self.guild.id, interaction.user.id, role_id, expires_at.isoformat())
            )
            await db.commit()

        dur_txt = format_duration(duration)

        # Vue de confirmation V2 (statique, sans interaction)
        success_view = LayoutView(timeout=None)
        success_view.add_item(v2_container(
            v2_title("Achat réussi !", level=2),
            v2_body(f"Tu as acheté {role.mention} pour **{price:,}** 🪙"),
            v2_divider(),
            v2_subtitle(f"⏱️ Ce rôle expirera dans {dur_txt}"),
            color=Palette.SUCCESS,
        ))
        await interaction.response.edit_message(view=success_view)

# Tâche pour retirer les rôles expirés
@tasks.loop(minutes=1)
async def check_expired_roles():
    try:
        async with get_db() as db:
            now_str = now().isoformat()
            
            # Récupérer les achats expirés
            async with db.execute(
                'SELECT id, guild_id, user_id, role_id FROM shop_purchases WHERE expires_at < ?',
                (now_str,)
            ) as cursor:
                expired = await cursor.fetchall()
            
            for purchase_id, guild_id, user_id, role_id in expired:
                try:
                    guild = bot.get_guild(guild_id)
                    if guild:
                        member = guild.get_member(user_id)
                        role = guild.get_role(role_id)
                        
                        if member and role and role in member.roles:
                            await member.remove_roles(role, reason="Rôle boutique expiré")
                except:
                    pass
                
                # Supprimer l'entrée
                await db.execute('DELETE FROM shop_purchases WHERE id=?', (purchase_id,))
            
            await db.commit()
    except:
        pass

@check_expired_roles.before_loop
async def before_check_expired():
    await bot.wait_until_ready()

# ─── Tâche pour lever les directions expirées ───
@tasks.loop(minutes=1)
async def check_expired_restrictions():
    try:
        import json
        async with get_db() as db:
            async with db.execute(
                'SELECT guild_id, user_id, roles_backup, restricted_at, duration FROM restricted_members WHERE duration > 0'
            ) as cur:
                rows = await cur.fetchall()

            for guild_id, user_id, roles_json, restricted_at, duration in rows:
                try:
                    from datetime import datetime
                    restricted_dt = datetime.fromisoformat(restricted_at)
                    elapsed = (now() - restricted_dt).total_seconds() / 60
                    if elapsed >= duration:
                        guild = bot.get_guild(guild_id)
                        if not guild:
                            continue
                        member = guild.get_member(user_id)
                        if not member:
                            # Membre parti → supprimer l'entrée
                            await db.execute('DELETE FROM restricted_members WHERE guild_id=? AND user_id=?', (guild_id, user_id))
                            continue

                        # Retirer le rôle Restricted
                        restricted_role = discord.utils.get(guild.roles, name="🔒 Restricted")
                        if restricted_role and restricted_role in member.roles:
                            await member.remove_roles(restricted_role, reason="Restriction expirée")

                        # Restaurer les rôles
                        saved_roles = json.loads(roles_json) if roles_json else []
                        for role_id in saved_roles:
                            role = guild.get_role(role_id)
                            if role and role.is_assignable():
                                try:
                                    await member.add_roles(role, reason="Restauration auto - restriction expirée")
                                except:
                                    pass

                        # Retirer timeout
                        try:
                            await member.timeout(None, reason="Restriction expirée")
                        except:
                            pass

                        await db.execute('DELETE FROM restricted_members WHERE guild_id=? AND user_id=?', (guild_id, user_id))
                        print(f"[DIRECTION] ✅ Restriction expirée pour {user_id} dans {guild_id}")
                except Exception as ex:
                    print(f"[DIRECTION] Erreur vérification: {ex}")
                    continue

            await db.commit()
    except Exception as ex:
        print(f"[DIRECTION] Erreur task: {ex}")

@check_expired_restrictions.before_loop
async def before_check_restrictions():
    await bot.wait_until_ready()

@bot.tree.command(name="leaderboard", description="🏆 Classement du serveur (pièces, messages, vocal)")
async def leaderboard_cmd(i: discord.Interaction):
    """Phase 26.4 : leaderboard à onglets (pièces / messages / vocal).
    Accessible à tout le monde sur le serveur.
    """
    v = LeaderboardTabsView(i.guild, i.user, tab='coins')
    await v.render(i, edit=False)


class LeaderboardTabsView(LayoutView):
    """Phase 26.4 : leaderboard à 3 onglets — pièces / messages / vocal."""

    def __init__(self, guild, user, *, tab='coins'):
        super().__init__(timeout=300)
        self.guild = guild
        self.user = user
        self.tab = tab  # 'coins' | 'messages' | 'voice'

    async def interaction_check(self, i):
        # Tout le monde peut interagir avec son propre leaderboard (mais on ne
        # restreint pas — si quelqu'un veut le voir, il en lance un nouveau)
        return True

    async def render(self, i, *, edit: bool = False):
        # Fetch data selon onglet
        title_map = {
            'coins':    ("🪙 Plus riches",    "Classement par pièces (coins + banque)"),
            'messages': ("💬 Plus actifs",     "Classement par nombre de messages"),
            'voice':    ("🎤 Rois du vocal",   "Classement par temps en vocal"),
        }
        title, subtitle = title_map.get(self.tab, title_map['coins'])

        rows = await self._fetch_top()

        # ── Lignes du classement ──
        medals = ["🥇", "🥈", "🥉"]
        podium_lines, rest_lines = [], []
        for idx, row in enumerate(rows):
            user_id = row['user_id']
            member = self.guild.get_member(user_id)
            name = member.display_name if member else f"User {user_id}"
            value_str = row['value_str']
            extra_str = row.get('extra', '')
            line = f"**{name}** · {value_str}" + (f" · {extra_str}" if extra_str else '')
            if idx < 3:
                podium_lines.append(f"{medals[idx]} {line}")
            else:
                rest_lines.append(f"`{idx + 1:>2}.` {line}")

        # ── Boutons d'onglet ──
        self.clear_items()
        b_coins = Button(
            label="🪙 Pièces",
            style=(discord.ButtonStyle.primary if self.tab == 'coins' else discord.ButtonStyle.secondary),
            disabled=(self.tab == 'coins'),
            custom_id="lb_coins",
        )
        b_coins.callback = lambda ix: self._switch_tab(ix, 'coins')
        b_msg = Button(
            label="💬 Messages",
            style=(discord.ButtonStyle.primary if self.tab == 'messages' else discord.ButtonStyle.secondary),
            disabled=(self.tab == 'messages'),
            custom_id="lb_msgs",
        )
        b_msg.callback = lambda ix: self._switch_tab(ix, 'messages')
        b_voice = Button(
            label="🎤 Vocal",
            style=(discord.ButtonStyle.primary if self.tab == 'voice' else discord.ButtonStyle.secondary),
            disabled=(self.tab == 'voice'),
            custom_id="lb_voice",
        )
        b_voice.callback = lambda ix: self._switch_tab(ix, 'voice')

        # ── Construction ──
        items = []
        if self.guild.icon:
            items.append(v2_section(
                v2_title(f"🏆 {title}"),
                v2_subtitle(subtitle),
                accessory=v2_thumb(self.guild.icon.url),
            ))
        else:
            items.append(v2_title(f"🏆 {title}"))
            items.append(v2_subtitle(subtitle))

        items.append(v2_divider())
        if podium_lines:
            items.append(v2_title("🏅 Podium", level=2))
            items.append(v2_body("\n".join(podium_lines)))
        else:
            items.append(v2_body("_Aucune donnée pour ce classement._"))

        if rest_lines:
            items.append(v2_divider())
            items.append(v2_title("Suite", level=3))
            items.append(v2_body("\n".join(rest_lines)))

        items.append(v2_divider())
        items.append(discord.ui.ActionRow(b_coins, b_msg, b_voice))

        self.add_item(v2_container(*items, color=Palette.PREMIUM))

        if edit:
            await i.response.edit_message(content=None, view=self, embed=None, attachments=[])
        else:
            await i.response.send_message(view=self)

    async def _fetch_top(self):
        """Retourne la liste [ {user_id, value_str, extra}, ... ] selon l'onglet."""
        rows_out = []
        try:
            async with get_db() as db:
                if self.tab == 'coins':
                    async with db.execute(
                        'SELECT user_id, coins, bank, level FROM economy '
                        'WHERE guild_id=? ORDER BY (coins + bank) DESC LIMIT 10',
                        (self.guild.id,),
                    ) as cur:
                        for user_id, coins, bank, level in await cur.fetchall():
                            total = (coins or 0) + (bank or 0)
                            rows_out.append({
                                'user_id': user_id,
                                'value_str': f"`{total:,}` 🪙",
                                'extra': f"Niveau **{level or 1}**",
                            })
                elif self.tab == 'messages':
                    async with db.execute(
                        'SELECT user_id, total_messages FROM activity_tracking '
                        'WHERE guild_id=? AND total_messages > 0 '
                        'ORDER BY total_messages DESC LIMIT 10',
                        (self.guild.id,),
                    ) as cur:
                        for user_id, total_messages in await cur.fetchall():
                            rows_out.append({
                                'user_id': user_id,
                                'value_str': f"`{(total_messages or 0):,}` messages",
                                'extra': '',
                            })
                elif self.tab == 'voice':
                    async with db.execute(
                        'SELECT user_id, total_vocal_time FROM activity_tracking '
                        'WHERE guild_id=? AND total_vocal_time > 0 '
                        'ORDER BY total_vocal_time DESC LIMIT 10',
                        (self.guild.id,),
                    ) as cur:
                        for user_id, vt in await cur.fetchall():
                            secs = int(vt or 0)
                            hours = secs // 3600
                            mins = (secs % 3600) // 60
                            if hours > 0:
                                vstr = f"`{hours}h {mins}min`"
                            else:
                                vstr = f"`{mins}min`"
                            rows_out.append({
                                'user_id': user_id,
                                'value_str': vstr,
                                'extra': '',
                            })
        except Exception as ex:
            print(f"[LeaderboardTabsView _fetch_top] {ex}")
        return rows_out

    async def _switch_tab(self, i, tab):
        self.tab = tab
        await self.render(i, edit=True)


# Phase 120 : retiré (debug inutilisé, ex-/testdeals)
async def testdeals_cmd(i: discord.Interaction):
    """Force la vérification des promotions de jeux (Owner-only)"""
    # Phase 3.8 : owner-only même si admin
    if i.user.id != i.guild.owner_id and i.user.id != SUPER_OWNER_ID:
        return await i.response.send_message(
            "⛔ Réservé au propriétaire du serveur.", ephemeral=True,
        )
    await i.response.defer(ephemeral=True)
    
    c = await cfg(i.guild.id)
    
    deals_enabled = c.get('ads_deals_enabled', False)
    deals_channel_id = c.get('ads_deals_channel', 0)
    min_discount = c.get('ads_deals_min_discount', 50)
    
    if not deals_enabled:
        return await i.followup.send("❌ Les réductions ne sont pas activées.\n➡️ Utilisez `/configure` > Publicité > 🎯 Réductions > ✅ Activer")
    
    deals_channel = i.guild.get_channel(deals_channel_id)
    if not deals_channel:
        return await i.followup.send("❌ Aucun salon configuré pour les réductions.\n➡️ Utilisez `/configure` > Publicité > 🎯 Réductions > 📍 Salon")
    
    # Compter les deals déjà postés en DB
    posted_count = 0
    try:
        async with get_db() as db:
            async with db.execute('SELECT COUNT(*) FROM posted_deals WHERE guild_id=? AND expired=0', (i.guild.id,)) as cur:
                row = await cur.fetchone()
                posted_count = row[0] if row else 0
    except:
        pass
    
    await i.followup.send(
        f"🔄 **Test du système de deals en cours...**\n"
        f"📍 Salon: {deals_channel.mention}\n"
        f"🔻 Réduction minimum: **-{min_discount}%**\n"
        f"📦 Deals déjà postés (actifs): **{posted_count}**\n\n"
        f"*Seuls les **nouveaux** deals seront publiés — les doublons sont bloqués en DB.*"
    )
    
    # Réinitialiser le throttle pour forcer la vérification
    cache_key = f"deals_{i.guild.id}"
    if cache_key in _deals_last_check:
        del _deals_last_check[cache_key]
    
    # Exécuter le check
    try:
        async with aiohttp.ClientSession() as session:
            await check_game_deals(session, i.guild, c)
        
        # Compter les nouveaux deals postés
        new_count = 0
        try:
            async with get_db() as db:
                async with db.execute('SELECT COUNT(*) FROM posted_deals WHERE guild_id=? AND expired=0', (i.guild.id,)) as cur:
                    row = await cur.fetchone()
                    new_count = row[0] if row else 0
        except:
            pass
        
        added = new_count - posted_count
        await i.followup.send(
            f"✅ **Vérification terminée !**\n"
            f"📊 **{added}** nouveau(x) deal(s) publié(s)\n"
            f"📦 Total deals actifs: **{new_count}**\n\n"
            f"*Les deals expirés seront automatiquement supprimés du salon.*"
        )
    except Exception as ex:
        await i.followup.send(f"❌ Erreur lors de la vérification: {str(ex)}")

@owner_group.command(name="clear_deals", description="🗑️ [Owner] Supprimer tous les deals postés et réinitialiser")
@app_commands.default_permissions(administrator=True)
async def cleardeals_cmd(i: discord.Interaction):
    """Supprime tous les deals postés et leurs messages (Owner-only - destructif)"""
    # Phase 3.8 : owner-only car opération destructive (supprime DB + messages Discord)
    if i.user.id != i.guild.owner_id and i.user.id != SUPER_OWNER_ID:
        return await i.response.send_message(
            "⛔ Réservé au propriétaire du serveur (opération destructive).", ephemeral=True,
        )
    await i.response.defer(ephemeral=True)
    
    deleted = 0
    try:
        async with get_db() as db:
            # Récupérer tous les deals actifs
            async with db.execute(
                'SELECT message_id, channel_id, game_name FROM posted_deals WHERE guild_id=? AND expired=0',
                (i.guild.id,)
            ) as cur:
                deals = await cur.fetchall()
            
            # Supprimer les messages Discord
            for msg_id, ch_id, name in deals:
                try:
                    ch = i.guild.get_channel(ch_id)
                    if ch and msg_id:
                        msg = await ch.fetch_message(msg_id)
                        await msg.delete()
                        deleted += 1
                except:
                    pass
            
            # Marquer tout comme expiré en DB
            await db.execute('UPDATE posted_deals SET expired=1 WHERE guild_id=?', (i.guild.id,))
            await db.commit()
    except Exception as ex:
        return await i.followup.send(f"❌ Erreur: {ex}")
    
    await i.followup.send(f"✅ **{deleted}** message(s) de deal supprimé(s) et base de données réinitialisée.\n*Les prochaines promos seront re-publiées.*")


