# ═══════════════════════════════════════════════════════════════════════════════
#  Phase 41.1 — HUB D'ENGAGEMENT (zéro commande à mémoriser)
#  Un seul panneau avec 5 boutons → tous les systèmes accessibles en 1 clic
# ═══════════════════════════════════════════════════════════════════════════════


async def _safe_defer(i: discord.Interaction, ephemeral: bool = True) -> bool:
    """Defer une interaction si pas déjà fait. Retourne True si OK, False si déjà mort."""
    try:
        if not i.response.is_done():
            await i.response.defer(ephemeral=ephemeral)
        return True
    except discord.InteractionResponded:
        return True
    except (discord.NotFound, discord.HTTPException):
        return False
    except Exception as ex:
        print(f"[_safe_defer] {ex}")
        return False


async def _safe_followup(i: discord.Interaction, **kwargs) -> bool:
    """Envoie un followup safe. Retourne True si OK."""
    try:
        kwargs.setdefault('ephemeral', True)
        await i.followup.send(**kwargs)
        return True
    except (discord.NotFound, discord.HTTPException) as ex:
        print(f"[_safe_followup] {ex}")
        return False
    except Exception as ex:
        print(f"[_safe_followup] {ex}")
        return False


# ─── Phase 48.3 : Cache TTL 60s pour hot path (alliance + pet + stats) ───────
# Réduit le load DB d'un facteur 10x sur les fonctions appelées à chaque message.

import time as _time_p48

_HOT_CACHE_TTL = 60.0
_cache_user_alliance: dict = {}   # (gid, uid) → (timestamp, dict|None)
_cache_active_pet: dict = {}      # (gid, uid) → (timestamp, dict|None)
_cache_user_stats: dict = {}      # (gid, uid) → (timestamp, dict)


def _invalidate_alliance_cache(guild_id: int, user_id: int = None):
    """Appelé quand on modifie une alliance (add/leave/dissolve)."""
    if user_id is not None:
        _cache_user_alliance.pop((guild_id, user_id), None)
    else:
        # Invalidate all entries for this guild
        for key in list(_cache_user_alliance.keys()):
            if key[0] == guild_id:
                _cache_user_alliance.pop(key, None)


def _invalidate_pet_cache(guild_id: int, user_id: int):
    _cache_active_pet.pop((guild_id, user_id), None)


def _invalidate_stats_cache(guild_id: int, user_id: int):
    _cache_user_stats.pop((guild_id, user_id), None)


# ─── Phase 45.1 : helpers anti-pollution (auto-delete + chrono visuel) ───────


def _chrono_footer(seconds: int, prefix: str = "⏱️ Se supprime") -> str:
    """Construit un footer chrono dynamique Discord.

    Utilise <t:UNIX:R> qui s'affiche 'in 10 minutes' et se rafraîchit côté client.
    Ex retour : '⏱️ Se supprime <t:1716738000:R>'
    """
    try:
        target_ts = int(datetime.now(timezone.utc).timestamp()) + max(1, int(seconds))
        return f"{prefix} <t:{target_ts}:R>"
    except Exception:
        return prefix


def _claim_chrono(seconds: int) -> str:
    """Chrono spécifique pour les claims : 'Claim avant <t:X:R>'."""
    try:
        target_ts = int(datetime.now(timezone.utc).timestamp()) + max(1, int(seconds))
        return f"⏰ Claim avant <t:{target_ts}:R>"
    except Exception:
        return "⏰ Claim limité"


async def _schedule_msg_delete(message, delay_seconds: int):
    """Supprime un message après N secondes. Silent sur erreur (déjà delete / pas droits)."""
    try:
        await asyncio.sleep(max(1, int(delay_seconds)))
        try:
            await message.delete()
        except (discord.NotFound, discord.Forbidden, AttributeError):
            pass
        except Exception as ex:
            print(f"[_schedule_msg_delete] {ex}")
    except asyncio.CancelledError:
        raise
    except Exception as ex:
        print(f"[_schedule_msg_delete outer] {ex}")


def _schedule_delete(message, delay_seconds: int):
    """Helper sync : fire-and-forget asyncio.create_task pour delete."""
    if message is None:
        return
    try:
        asyncio.create_task(_schedule_msg_delete(message, delay_seconds))
    except Exception as ex:
        print(f"[_schedule_delete] {ex}")


# ─── Phase 47.3 : delete persistant (survit aux redémarrages bot) ─────────────


async def _register_for_cleanup(message, delay_seconds: int, reason: str = 'event'):
    """Enregistre un message en DB pour suppression différée GARANTIE.

    À utiliser EN PLUS du delete_after natif Discord. Si le bot redémarre
    pendant l'attente, le loop persistent_msg_cleaner prend le relais.

    À appeler systématiquement après chaque send() avec delete_after sur
    un message d'event (> 1h surtout).

    Phase 55 : retry x3 avec backoff si INSERT échoue. Log explicite.
    """
    if message is None:
        return False
    delay_seconds = max(60, int(delay_seconds))  # min 60s pour éviter spam DB
    expires_at = (datetime.now(timezone.utc) + timedelta(seconds=delay_seconds)).isoformat()
    guild_id = message.guild.id if message.guild else 0
    last_err = None
    for attempt in range(3):
        try:
            async with get_db() as db:
                await db.execute(
                    "INSERT INTO event_message_cleanup(guild_id, channel_id, message_id, expires_at, reason) "
                    "VALUES(?,?,?,?,?)",
                    (guild_id, message.channel.id, message.id, expires_at, reason),
                )
                await db.commit()
            return True
        except Exception as ex:
            last_err = ex
            await asyncio.sleep(0.5 * (attempt + 1))
    print(f"[_register_for_cleanup FAILED 3x reason={reason} msg={message.id}] {last_err}")
    return False


async def _send_and_register(channel, delay_seconds: int, reason: str = 'event', **send_kwargs):
    """Send + delete_after + register en DB. Helper one-shot pour les events.

    Usage : msg = await _send_and_register(channel, 3600, 'daily_riddle', embed=e, view=v)
    """
    try:
        # Forcer delete_after natif aussi (rapide si bot reste up)
        send_kwargs['delete_after'] = delay_seconds
        msg = await channel.send(**send_kwargs)
        # Backup persistant DB
        await _register_for_cleanup(msg, delay_seconds, reason)
        return msg
    except Exception as ex:
        print(f"[_send_and_register reason={reason}] {ex}")
        return None


async def _run_persistent_cleanup_once() -> dict:
    """Scan tous les messages expirés et tente la suppression. Appelé au boot
    et toutes les 2 min via persistent_msg_cleaner.

    Retourne {'scanned': N, 'deleted': N, 'gone': N, 'forbidden': N, 'errors': N}.
    Phase 55 : LIMIT 500 (batch plus large), retry sur les rate limits, logs détaillés.
    """
    stats = {"scanned": 0, "deleted": 0, "gone": 0, "forbidden": 0, "errors": 0}
    try:
        now_iso = datetime.now(timezone.utc).isoformat()
        async with get_db() as db:
            async with db.execute(
                "SELECT id, guild_id, channel_id, message_id, reason FROM event_message_cleanup "
                "WHERE deleted=0 AND expires_at < ? ORDER BY expires_at ASC LIMIT 500",
                (now_iso,),
            ) as cur:
                rows = await cur.fetchall()
        if not rows:
            return stats
        stats["scanned"] = len(rows)
        for rid, gid, ch_id, msg_id, reason in rows:
            try:
                guild = bot.get_guild(int(gid)) if gid else None
                ch = guild.get_channel(int(ch_id)) if guild else None
                if ch and msg_id:
                    try:
                        msg = await ch.fetch_message(int(msg_id))
                        if msg:
                            await msg.delete()
                            stats["deleted"] += 1
                    except discord.NotFound:
                        stats["gone"] += 1
                    except discord.Forbidden:
                        stats["forbidden"] += 1
                    except discord.HTTPException as ex:
                        if ex.status == 429:
                            # Rate limit : on attend un peu et on continue (sera retry next loop)
                            await asyncio.sleep(2)
                            stats["errors"] += 1
                            continue
                        stats["errors"] += 1
                        print(f"[cleanup msg={msg_id} reason={reason}] HTTP {ex.status}: {ex}")
                    except Exception as ex:
                        stats["errors"] += 1
                        print(f"[cleanup msg={msg_id} reason={reason}] {ex}")
                else:
                    # Channel ou guild introuvable → marker quand même
                    stats["gone"] += 1
            except Exception as ex:
                stats["errors"] += 1
                print(f"[cleanup outer] {ex}")
            # Marker deleted=1 (sinon boucle infinie)
            try:
                async with get_db() as db:
                    await db.execute(
                        "UPDATE event_message_cleanup SET deleted=1 WHERE id=?",
                        (rid,),
                    )
                    await db.commit()
            except Exception:
                pass
        # Log si activité (toujours, pour visibility)
        if stats["scanned"]:
            print(f"[PERSIST CLEANUP] {stats}")
    except Exception as ex:
        print(f"[_run_persistent_cleanup_once] {ex}")
    return stats


@tasks.loop(minutes=2)
async def persistent_msg_cleaner():
    """Loop persistente : nettoie les messages d'events expirés toutes les 2 min.

    Phase 55 : passé de 5min à 2min pour réduire la dérive max post-restart.
    """
    await _run_persistent_cleanup_once()


# ─── Phase 55 : SAFETY NET — purge messages bot vieux dans hub (orphelins) ───


@tasks.loop(hours=6)
async def hub_orphan_cleaner_task():
    """Toutes les 6h, purge les messages du bot >48h dans le hub_channel
    qui n'ont PAS été épinglés et qui ne sont PLUS attachés à event actif.

    Filet de sécurité : capture les messages dont l'entrée DB de cleanup a été
    perdue (rare mais possible). Skip pinned + skip messages avec components
    actifs (views persistantes type EngagementHubView).
    """
    try:
        cutoff_48h = datetime.now(timezone.utc) - timedelta(hours=48)
        for guild in bot.guilds:
            try:
                c = await cfg(guild.id)
                if not c.get('event_enabled', False):
                    continue
                hub_id = int(c.get('hub_channel', 0) or 0)
                if not hub_id:
                    continue
                hub_ch = guild.get_channel(hub_id)
                if not hub_ch:
                    continue
                # Trouver les pinned IDs pour les exclure
                # Phase 151 : utilise l'iterator async (l'API .pins() awaitable
                # est deprecated en discord.py 2.7+)
                pinned_ids = set()
                try:
                    async for p in hub_ch.pins():
                        pinned_ids.add(p.id)
                except Exception:
                    pass
                deleted = 0
                # Scanner historique 48h+ (limit 100 pour pas trop charger)
                try:
                    async for msg in hub_ch.history(limit=100, before=cutoff_48h):
                        if msg.author.id != bot.user.id:
                            continue
                        if msg.id in pinned_ids:
                            continue
                        # Skip si message contient un composant persistent (= View attachée)
                        # Reconnaissance via embeds.footer text contenant "Hub d'engagement"
                        if msg.embeds and any(
                            "Hub d'engagement" in (e.footer.text or "") if e.footer else False
                            for e in msg.embeds
                        ):
                            continue
                        try:
                            await msg.delete()
                            deleted += 1
                            await asyncio.sleep(0.5)  # rate-limit
                        except (discord.NotFound, discord.Forbidden):
                            pass
                        except Exception:
                            pass
                except Exception as ex:
                    print(f"[hub_orphan_cleaner guild={guild.id} history] {ex}")
                if deleted:
                    print(f"[HUB ORPHAN CLEAN] guild={guild.id} deleted={deleted}")
            except Exception as ex:
                print(f"[hub_orphan_cleaner guild={guild.id}] {ex}")
    except Exception as ex:
        print(f"[hub_orphan_cleaner_task] {ex}")


@hub_orphan_cleaner_task.before_loop
async def _hub_orphan_wait():
    await bot.wait_until_ready()


@persistent_msg_cleaner.before_loop
async def _persistent_cleanup_wait():
    await bot.wait_until_ready()


