# WORLD BOSS HEBDO
# ═══════════════════════════════════════════════════════════════════════════════


class WorldBossAttackView(View):
    """View persistante pour attaquer un World Boss. Plusieurs membres en
    parallèle. Custom IDs stables — survie aux restarts.
    """

    def __init__(self):
        super().__init__(timeout=None)
        b = Button(
            label="⚔️ Attaquer le World Boss",
            style=discord.ButtonStyle.danger,
            custom_id="wb_attack",
        )
        b.callback = self._on_attack
        self.add_item(b)
        b2 = Button(
            label="📊 Voir le top des attaquants",
            style=discord.ButtonStyle.secondary,
            custom_id="wb_top",
        )
        b2.callback = self._on_top
        self.add_item(b2)

    async def _on_attack(self, i: discord.Interaction):
        if not await _safe_defer(i):
            return
        try:
            if not i.guild:
                return await _safe_followup(i, content="❌ Serveur uniquement.")
            # Récupérer le world boss actif
            async with get_db() as db:
                async with db.execute(
                    'SELECT id, boss_id, hp, max_hp FROM world_bosses '
                    'WHERE guild_id=? AND ended=0 ORDER BY started_at DESC LIMIT 1',
                    (i.guild.id,),
                ) as cur:
                    row = await cur.fetchone()
            if not row:
                return await _safe_followup(i, content="ℹ️ Aucun World Boss actif.")
            wb_id, boss_id, hp, max_hp = row
            boss = ev42.get_world_boss(boss_id)
            if not boss:
                return await _safe_followup(i, content="❌ Boss inconnu.")
            if hp <= 0:
                return await _safe_followup(i, content="✅ Le boss est déjà mort !")

            # Cooldown 10s par user pour éviter le spam
            async with get_db() as db:
                async with db.execute(
                    'SELECT last_attack_at FROM world_boss_attackers '
                    'WHERE world_boss_id=? AND user_id=?',
                    (wb_id, i.user.id),
                ) as cur:
                    arow = await cur.fetchone()
            if arow and arow[0]:
                try:
                    last_dt = datetime.fromisoformat(arow[0]) if 'T' in str(arow[0]) else \
                              datetime.strptime(arow[0], '%Y-%m-%d %H:%M:%S').replace(tzinfo=timezone.utc)
                    elapsed = (datetime.now(timezone.utc) - last_dt).total_seconds()
                    if elapsed < 10:
                        return await _safe_followup(
                            i,
                            content=f"⏱️ Trop rapide ! Attends `{int(10 - elapsed)}`s.",
                        )
                except Exception:
                    pass

            # Calcul dégâts : 80-180 + bonus classe + bonus pet
            base = random.randint(80, 180)
            # Bonus pet dragon
            try:
                pet_bonus = await _apply_pet_bonus(i.guild.id, i.user.id, 'boss_damage')
            except Exception:
                pet_bonus = 0.0
            damage = int(base * (1.0 + pet_bonus))

            # Apply phase buff : double damage if low HP
            hp_ratio = hp / max(1, max_hp)
            if hp_ratio < 0.33:
                damage = int(damage * 1.5)  # phase finale = +50% damage taken par le boss

            new_hp = max(0, hp - damage)
            async with get_db() as db:
                await db.execute(
                    'UPDATE world_bosses SET hp=? WHERE id=?',
                    (new_hp, wb_id),
                )
                await db.execute(
                    'INSERT INTO world_boss_attackers(world_boss_id, user_id, damage_dealt, attacks_count, last_attack_at) '
                    'VALUES(?,?,?,1,CURRENT_TIMESTAMP) '
                    'ON CONFLICT(world_boss_id, user_id) DO UPDATE SET '
                    'damage_dealt=damage_dealt+?, attacks_count=attacks_count+1, last_attack_at=CURRENT_TIMESTAMP',
                    (wb_id, i.user.id, damage, damage),
                )
                await db.commit()

            # Track stats Phase 41 : événement participé + pet XP
            try:
                await _incr_stat_p41(i.guild.id, i.user.id, 'events_participated', 1)
                await _give_pet_xp(i.guild.id, i.user.id, 5)
            except Exception:
                pass

            # Si HP = 0 : victoire collective
            if new_hp <= 0:
                await _end_world_boss(i.guild, wb_id, victory=True)
                return await _safe_followup(
                    i,
                    content=(
                        f"⚡ **COUP FATAL !** Tu as infligé `{damage}` dégâts.\n"
                        f"💀 **{boss['title']}** est vaincu — le serveur a triomphé !"
                    ),
                )

            phase_msg = ""
            if new_hp < max_hp * 0.33:
                phase_msg = "\n🔥 _Phase finale ! Le boss enrage._"
            elif new_hp < max_hp * 0.66:
                phase_msg = "\n⚡ _Le boss change de phase._"

            await _safe_followup(
                i,
                content=(
                    f"⚔️ Tu infliges `{damage}` dégâts à **{boss['title']}** !\n"
                    f"🩸 HP : `{new_hp}/{max_hp}` ({(new_hp/max_hp*100):.0f}%){phase_msg}"
                ),
            )

            # Update arena message embed (HP bar)
            try:
                await _refresh_world_boss_message(i.guild, wb_id)
            except Exception as ex:
                print(f"[_refresh_world_boss_message] {ex}")
        except Exception as ex:
            print(f"[WorldBossAttackView _on_attack] {ex}")
            await _safe_followup(i, content=f"❌ Erreur : `{ex}`")

    async def _on_top(self, i: discord.Interaction):
        if not await _safe_defer(i):
            return
        try:
            if not i.guild:
                return await _safe_followup(i, content="❌ Serveur uniquement.")
            async with get_db() as db:
                async with db.execute(
                    'SELECT id, boss_id FROM world_bosses '
                    'WHERE guild_id=? AND ended=0 ORDER BY started_at DESC LIMIT 1',
                    (i.guild.id,),
                ) as cur:
                    row = await cur.fetchone()
            if not row:
                return await _safe_followup(i, content="ℹ️ Aucun World Boss actif.")
            wb_id, boss_id = row
            async with get_db() as db:
                async with db.execute(
                    'SELECT user_id, damage_dealt, attacks_count FROM world_boss_attackers '
                    'WHERE world_boss_id=? ORDER BY damage_dealt DESC LIMIT 10',
                    (wb_id,),
                ) as cur:
                    rows = await cur.fetchall()
            if not rows:
                return await _safe_followup(i, content="ℹ️ Aucun attaquant pour le moment.")
            lines = ["🏆 **Top 10 des attaquants :**", ""]
            medals = ["🥇", "🥈", "🥉"] + ["🔹"] * 7
            for idx, (uid, dmg, atks) in enumerate(rows):
                member = i.guild.get_member(uid)
                name = member.display_name if member else f"ID:{uid}"
                lines.append(f"{medals[idx]} **{name}** — `{dmg}` dégâts ({atks} attaques)")
            await _safe_followup(i, content="\n".join(lines))
        except Exception as ex:
            print(f"[WorldBossAttackView _on_top] {ex}")


# ═══════════════════════════════════════════════════════════════════════════════
#  Phase 78 — World Boss Arena en LayoutView V2
# ═══════════════════════════════════════════════════════════════════════════════
class WorldBossArenaLayoutV2(LayoutView):
    """Phase 78 : Arena World Boss en LayoutView V2 (Components V2 modern).

    Persistant — re-rendu à chaque update HP / nouvelle attaque. Les boutons
    ATTAQUER (wb_attack) et TOP (wb_top) utilisent les custom_ids stables, ce
    qui permet à bot.add_view(WorldBossAttackView()) au boot de continuer à
    capter les clics même si le message est créé via LayoutView V2.

    Pattern identique à BossArenaLayoutV2 (Phase 74) pour les Boss Raid.
    """

    def __init__(self, boss: dict, hp: int, max_hp: int, top_attackers: list,
                  ends_at_dt: Optional[datetime], guild, wb_id: int):
        super().__init__(timeout=None)
        self.boss = boss
        self.hp = hp
        self.max_hp = max_hp
        self.top_attackers = top_attackers or []
        self.ends_at_dt = ends_at_dt
        self.guild = guild
        self.wb_id = wb_id
        self._build()

    def _build(self):
        boss = self.boss
        hp = max(0, int(self.hp))
        max_hp = max(1, int(self.max_hp))
        ratio = hp / max_hp
        bar_len = 24
        filled = int(ratio * bar_len)
        bar = "█" * filled + "░" * (bar_len - filled)

        # Phase label dynamique
        phase_label = "🌟 Éveil cosmique"
        if ratio <= 0:
            phase_label = "💀 Vaincu"
        elif ratio < 0.33:
            phase_label = "💀 Dernier souffle"
        elif ratio < 0.66:
            phase_label = "⚡ Fureur stellaire"

        color = boss.get('color', 0x9B59B6) if hp > 0 else 0x95A5A6

        items = []
        # Header : titre du boss + description lore
        items.append(v2_title(
            f"{boss.get('image_emoji', '🌍')} {boss.get('title', 'World Boss')}"
        ))
        if boss.get('description'):
            items.append(v2_subtitle(_escape_md(boss.get('description', ''), 200)))
        items.append(v2_divider())

        # Section HP avec bouton ATTAQUER en accessory (toujours visible mobile)
        # Phase 88 : buttons INDÉPENDANTS avec callbacks délégués (pas extraction
        # depuis WorldBossAttackView qui causait double-parenting et cassait send).
        if hp > 0:
            attack_btn = Button(
                label="⚔️ Attaquer",
                style=discord.ButtonStyle.danger,
                custom_id="wb_attack",
            )
            attack_btn.callback = _v2_delegate_to(WorldBossAttackView, '_on_attack')
            items.append(_section_with_button(
                f"❤️ HP — {phase_label}",
                f"`{bar}` `{hp:,}/{max_hp:,}` ({ratio * 100:.0f}%)",
                attack_btn,
            ))
        else:
            items.append(v2_body(
                f"**❤️ HP** — {phase_label}\n"
                f"`{bar}` `{hp:,}/{max_hp:,}` — 💀 VAINCU"
            ))

        # Chrono + count attaquants
        info_line = ""
        if self.ends_at_dt and hp > 0:
            info_line += f"⏰ Termine : <t:{int(self.ends_at_dt.timestamp())}:R>"
        nb_top = len(self.top_attackers)
        if nb_top:
            total_dmg = sum(int(p[1]) for p in self.top_attackers)
            if info_line:
                info_line += "  ·  "
            info_line += f"⚔️ `{nb_top}` attaquant(s) — `{total_dmg:,}` dégâts au total"
        if info_line:
            items.append(v2_body(info_line))

        items.append(v2_divider())

        # Top 3 attackers
        if self.top_attackers:
            medals = ["🥇", "🥈", "🥉"]
            lines = []
            for idx, row in enumerate(self.top_attackers[:3]):
                uid, dmg = int(row[0]), int(row[1])
                member = self.guild.get_member(uid) if self.guild else None
                name = _escape_md(member.display_name if member else f"ID:{uid}", 60)
                lines.append(f"{medals[idx]} **{name}** — `{dmg:,}` dégâts")
            items.append(v2_body("**🏆 Top 3 attaquants**\n" + "\n".join(lines)))
        else:
            items.append(v2_body("_⚔️ Personne n'a encore attaqué._"))

        items.append(v2_divider())

        # Bouton TOP 10 en ActionRow (en bas) — Phase 88 : independent + delegate
        top_btn = Button(
            label="📊 Voir le top 10",
            style=discord.ButtonStyle.secondary,
            custom_id="wb_top",
        )
        top_btn.callback = _v2_delegate_to(WorldBossAttackView, '_on_top')
        items.append(discord.ui.ActionRow(top_btn))

        self.add_item(v2_container(*items, color=color))


async def _build_world_boss_layout(guild, wb_id: int):
    """Phase 78 : construit le LayoutView V2 status du world boss.

    Retourne None si introuvable — le caller fera fallback embed legacy.
    """
    try:
        async with get_db() as db:
            async with db.execute(
                'SELECT boss_id, hp, max_hp, ends_at FROM world_bosses WHERE id=?',
                (wb_id,),
            ) as cur:
                row = await cur.fetchone()
        if not row:
            return None
        boss_id, hp, max_hp, ends_at = row
        boss = ev42.get_world_boss(boss_id)
        if not boss:
            return None
        async with get_db() as db:
            async with db.execute(
                'SELECT user_id, damage_dealt FROM world_boss_attackers '
                'WHERE world_boss_id=? ORDER BY damage_dealt DESC LIMIT 10',
                (wb_id,),
            ) as cur:
                top = await cur.fetchall()
        ends_at_dt = None
        try:
            if ends_at:
                ends_at_dt = (
                    datetime.fromisoformat(ends_at)
                    if 'T' in str(ends_at)
                    else datetime.strptime(ends_at, '%Y-%m-%d %H:%M:%S').replace(tzinfo=timezone.utc)
                )
        except Exception:
            ends_at_dt = None
        return WorldBossArenaLayoutV2(
            boss=boss, hp=int(hp), max_hp=int(max_hp), top_attackers=list(top),
            ends_at_dt=ends_at_dt, guild=guild, wb_id=wb_id,
        )
    except Exception as ex:
        print(f"[_build_world_boss_layout] {ex}")
        return None


async def _build_world_boss_embed(guild, wb_id: int) -> Optional[discord.Embed]:
    """LEGACY (Phase 78) : embed fallback si LayoutView V2 échoue.
    Préservé pour compat et au cas où _build_world_boss_layout retourne None."""
    try:
        async with get_db() as db:
            async with db.execute(
                'SELECT boss_id, hp, max_hp, started_at, ends_at FROM world_bosses WHERE id=?',
                (wb_id,),
            ) as cur:
                row = await cur.fetchone()
        if not row:
            return None
        boss_id, hp, max_hp, started_at, ends_at = row
        boss = ev42.get_world_boss(boss_id)
        if not boss:
            return None
        # Top 3 attackers
        async with get_db() as db:
            async with db.execute(
                'SELECT user_id, damage_dealt FROM world_boss_attackers '
                'WHERE world_boss_id=? ORDER BY damage_dealt DESC LIMIT 3',
                (wb_id,),
            ) as cur:
                top = await cur.fetchall()
        top_str = "\n".join(
            f"{['🥇','🥈','🥉'][i]} <@{uid}> — `{dmg}`"
            for i, (uid, dmg) in enumerate(top)
        ) or "_Personne n'a encore attaqué._"
        ratio = hp / max(1, max_hp)
        bar_len = 20
        filled = int(ratio * bar_len)
        bar = "█" * filled + "░" * (bar_len - filled)
        phase_label = "Éveil cosmique"
        if ratio < 0.33:
            phase_label = "💀 Dernier souffle"
        elif ratio < 0.66:
            phase_label = "⚡ Fureur stellaire"

        e = discord.Embed(
            title=f"{boss['image_emoji']} {boss['title']}",
            description=(
                f"_{boss['description']}_\n\n"
                f"**Phase :** {phase_label}\n"
                f"**HP :** `{hp}` / `{max_hp}`\n"
                f"`{bar}` {ratio*100:.0f}%\n\n"
                f"**Top 3 attaquants :**\n{top_str}"
            ),
            color=boss['color'],
            timestamp=datetime.now(timezone.utc),
        )
        e.set_footer(text="World Boss — clique '⚔️ Attaquer' pour participer ! Cooldown 10s/attaque")
        return e
    except Exception as ex:
        print(f"[_build_world_boss_embed] {ex}")
        return None


async def _refresh_world_boss_message(guild, wb_id: int):
    """Update le message d'arène avec le nouvel HP.

    Phase 78 : tente d'abord LayoutView V2 (WorldBossArenaLayoutV2), fallback
    embed legacy si la construction échoue ou si Discord rejette la V2.
    """
    try:
        async with get_db() as db:
            async with db.execute(
                'SELECT arena_channel_id, arena_message_id FROM world_bosses WHERE id=?',
                (wb_id,),
            ) as cur:
                row = await cur.fetchone()
        if not row:
            return
        ch_id, msg_id = row
        if not ch_id or not msg_id:
            return
        ch = guild.get_channel(int(ch_id))
        if not ch:
            return
        try:
            msg = await ch.fetch_message(int(msg_id))
        except Exception:
            return
        # Phase 78 : tenter LayoutView V2 d'abord
        try:
            layout = await _build_world_boss_layout(guild, wb_id)
            if layout:
                await msg.edit(view=layout)
                return
        except Exception as ex:
            print(f"[_refresh_world_boss_message V2 fallback] {ex}")
        # Fallback embed legacy
        embed = await _build_world_boss_embed(guild, wb_id)
        if embed:
            try:
                await msg.edit(embed=embed)
            except Exception:
                pass
    except Exception as ex:
        print(f"[_refresh_world_boss_message] {ex}")


async def _start_world_boss(guild) -> dict:
    """Démarre un World Boss dans le serveur.

    Conditions :
    - event_enabled = True (cfg)
    - PAS d'event majeur en cours
    - Heures actives respectées
    - Catégorie events_category configurée

    Retourne {'ok': bool, 'error': str?, 'wb_id': int?}.
    """
    try:
        c = await cfg(guild.id)
        if not c.get('event_enabled', False):
            return {'ok': False, 'error': 'events désactivés'}
        if await _has_any_major_event_running(guild.id):
            return {'ok': False, 'error': 'un event majeur est déjà en cours'}

        # Trouver le salon où poster : on utilise event_arena_category si dispo,
        # sinon on crée un salon dédié temporaire dans la catégorie events.
        cat_id = int(c.get('event_arena_category', 0) or 0)
        category = guild.get_channel(cat_id) if cat_id else None
        if not isinstance(category, discord.CategoryChannel):
            category = None

        # Choisir un boss
        boss = ev42.random_world_boss()

        # Créer le salon arena (visible et écrivable par @everyone)
        try:
            arena_ch = await guild.create_text_channel(
                name=f"🌍-world-boss-{boss['id']}"[:90],
                category=category,
                reason="World Boss event",
                overwrites={
                    guild.default_role: discord.PermissionOverwrite(
                        view_channel=True, send_messages=True, read_message_history=True,
                    ),
                    guild.me: discord.PermissionOverwrite(
                        view_channel=True, send_messages=True, manage_messages=True,
                        manage_channels=True, embed_links=True,
                    ),
                },
            )
        except discord.Forbidden:
            return {'ok': False, 'error': 'permission manage_channels refusée'}
        except Exception as ex:
            return {'ok': False, 'error': f'erreur création salon : {ex}'}

        ends_at = datetime.now(timezone.utc) + timedelta(minutes=90)
        # Insérer en DB
        async with get_db() as db:
            cur = await db.execute(
                'INSERT INTO world_bosses(guild_id, boss_id, hp, max_hp, arena_channel_id, ends_at) '
                'VALUES(?,?,?,?,?,?)',
                (guild.id, boss['id'], boss['max_hp'], boss['max_hp'], arena_ch.id, ends_at.isoformat()),
            )
            wb_id = cur.lastrowid
            await db.commit()

        # Phase 78 : construire et envoyer LayoutView V2 (avec fallback embed legacy)
        ping_str = await _get_event_mention(guild, 'boss_raid')  # réutilise le role notif boss_raid
        # Phase 48.4.A : smart mention pour wake-up dormants spécifiquement intéressés
        try:
            wakeup_line = await _build_wakeup_mention_line_smart(guild, 'world_boss', max_count=3)
        except Exception:
            wakeup_line = ""
        send_content = (
            f"🌍 **UN WORLD BOSS APPARAÎT !**\n"
            f"Coordonnez vos attaques — il faut **plusieurs joueurs** pour le vaincre.\n"
            + (f"{ping_str}\n" if ping_str else "")
            + wakeup_line
            + "\n_Pas envie d'être ping ? `/notifs` pour choisir précisément quoi recevoir._"
        )
        try:
            layout = await _build_world_boss_layout(guild, wb_id)
            if layout:
                msg = await arena_ch.send(
                    content=send_content,
                    view=layout,
                    allowed_mentions=discord.AllowedMentions(roles=True, users=True, everyone=False),
                )
            else:
                # Fallback embed legacy si build échoue
                embed = await _build_world_boss_embed(guild, wb_id)
                view = WorldBossAttackView()
                msg = await arena_ch.send(
                    content=send_content,
                    embed=embed,
                    view=view,
                    allowed_mentions=discord.AllowedMentions(roles=True, users=True, everyone=False),
                )
            async with get_db() as db:
                await db.execute(
                    'UPDATE world_bosses SET arena_message_id=? WHERE id=?',
                    (msg.id, wb_id),
                )
                await db.commit()
        except Exception as ex:
            print(f"[_start_world_boss send arena] {ex}")
            return {'ok': False, 'error': f'erreur envoi : {ex}'}

        try: await _track_event_engagement(guild.id, 'world_boss', 'start')
        except Exception: pass
        print(f"[WORLD BOSS] guild={guild.id} boss={boss['id']} wb_id={wb_id}")
        return {'ok': True, 'wb_id': wb_id, 'boss_id': boss['id']}
    except Exception as ex:
        print(f"[_start_world_boss] {ex}")
        return {'ok': False, 'error': str(ex)}


async def _end_world_boss(guild, wb_id: int, victory: bool, reason: str = ""):
    """Termine un world boss : distribue les récompenses, supprime le salon."""
    try:
        async with get_db() as db:
            async with db.execute(
                'SELECT boss_id, arena_channel_id FROM world_bosses WHERE id=? AND ended=0',
                (wb_id,),
            ) as cur:
                row = await cur.fetchone()
        if not row:
            return
        boss_id, ch_id = row
        boss = ev42.get_world_boss(boss_id)
        if not boss:
            return

        # Récupérer les attaquants triés
        async with get_db() as db:
            async with db.execute(
                'SELECT user_id, damage_dealt FROM world_boss_attackers '
                'WHERE world_boss_id=? ORDER BY damage_dealt DESC',
                (wb_id,),
            ) as cur:
                attackers = await cur.fetchall()

        # Distribuer les récompenses
        if victory:
            for idx, (uid, dmg) in enumerate(attackers):
                reward = boss['victory_reward_coins'] if idx < 3 else boss['participation_reward_coins']
                try:
                    await add_coins(guild.id, uid, reward)
                except Exception:
                    pass
            # Achievement worldboss_kill pour le top 1
            if attackers:
                try:
                    await _unlock_achievement(guild.id, attackers[0][0], 'worldboss_kill')
                except Exception:
                    pass
                # Phase 48.3 : célébration publique pour le top 1 attaquant
                try:
                    top_member = guild.get_member(int(attackers[0][0]))
                    c = await cfg(guild.id)
                    hub_id = int(c.get('hub_channel', 0) or 0)
                    celebrate_ch = guild.get_channel(hub_id) if hub_id else None
                    if not celebrate_ch or not await _is_chatty_channel(celebrate_ch):
                        for cand in guild.text_channels:
                            if await _is_chatty_channel(cand):
                                celebrate_ch = cand
                                break
                    if celebrate_ch and top_member:
                        await _celebrate_rare_drop(
                            celebrate_ch, top_member,
                            f"🌍 Slayer du {boss['title']} — Top Damage",
                            'legendary',
                        )
                except Exception as ex:
                    print(f"[world_boss celebrate top] {ex}")
        else:
            # Défaite : consolation pour tous les attaquants
            for uid, dmg in attackers:
                try:
                    await add_coins(guild.id, uid, boss['participation_reward_coins'] // 2)
                except Exception:
                    pass

        # Marquer ended
        async with get_db() as db:
            await db.execute(
                'UPDATE world_bosses SET ended=1, victory=? WHERE id=?',
                (1 if victory else 0, wb_id),
            )
            await db.commit()

        # Phase 49 : NPC réactions + avancer le lore + tracking mission
        try:
            await _post_npc_world_boss_reaction(guild, victory)
        except Exception as ex:
            print(f"[world_boss npc reaction] {ex}")
        try:
            participants_ids = [int(a[0]) for a in attackers] if attackers else []
            await _track_event_completion_for_missions(
                guild.id, 'world_boss', victory, participants_ids,
            )
        except Exception as ex:
            print(f"[world_boss mission track] {ex}")

        # Phase 57 : lore memory + 50% chance narrative choice après victoire
        try:
            if victory:
                # Mémoire : first_kill du top damager
                if attackers:
                    top_uid = int(attackers[0][0])
                    top_member = guild.get_member(top_uid)
                    top_name = top_member.display_name if top_member else f"User {top_uid}"
                    await _add_lore_memory(
                        guild.id, "first_kill",
                        f"{boss['title']} (top damage : {top_name})"
                    )
                # 50% chance narrative choice
                if random.random() < 0.50:
                    await asyncio.sleep(30)  # léger délai pour pas spammer
                    await _start_narrative_choice(guild)
            else:
                # Défaite : memory pour que les NPCs en parlent
                await _add_lore_memory(
                    guild.id, "boss_defeat",
                    f"la chute contre {boss['title']}"
                )
        except Exception as ex:
            print(f"[world_boss phase57 hook] {ex}")

        # Phase 60 : drop unique loot pour le top damager (1% chance)
        try:
            if victory and attackers:
                top_uid = int(attackers[0][0])
                loot = await _maybe_drop_unique_loot(guild.id, top_uid, 'world_boss', drop_chance=0.10)
                if loot:
                    top_member = guild.get_member(top_uid)
                    c = await cfg(guild.id)
                    hub_id = int(c.get('hub_channel', 0) or 0)
                    hub_ch = guild.get_channel(hub_id) if hub_id else None
                    if hub_ch and top_member:
                        action = "vole" if loot.get("stolen_from") else "obtient"
                        LIFETIME = 6 * 3600
                        e = discord.Embed(
                            title=f"💎 LOOT UNIQUE OBTENU !",
                            description=(
                                f"**{top_member.mention}** {action} :\n\n"
                                f"# {loot['name']}\n\n"
                                f"_{loot['desc']}_\n\n"
                                f"_1 seul exemplaire au monde. Visible dans `/loots`._"
                            ),
                            color=0xFFD700,
                            timestamp=datetime.now(timezone.utc),
                        )
                        try:
                            msg = await hub_ch.send(
                                embed=e,
                                allowed_mentions=discord.AllowedMentions.none(),
                                delete_after=LIFETIME,
                            )
                            await _register_for_cleanup(msg, LIFETIME, 'unique_loot_drop')
                        except Exception:
                            pass
        except Exception as ex:
            print(f"[world_boss phase60 loot] {ex}")
        # Phase 51 : Faction war scoring
        try:
            if victory:
                for uid in participants_ids:
                    await _bump_faction_war_score(guild.id, uid, 'events_won', 1)
                # Damage tracking
                for a in (attackers or []):
                    try:
                        await _bump_faction_war_score(guild.id, int(a[0]), 'boss_damage', int(a[1] or 0))
                    except Exception:
                        pass
        except Exception as ex:
            print(f"[world_boss faction war] {ex}")

        # Annoncer la fin + supprimer le salon dans 5 min
        ch = guild.get_channel(int(ch_id))
        if ch:
            try:
                final_msg = (
                    f"🎉 **VICTOIRE !** Le **{boss['title']}** a été vaincu par votre coordination !\n"
                    f"💰 Récompenses distribuées (top 3 : `{boss['victory_reward_coins']}` 🪙, "
                    f"autres : `{boss['participation_reward_coins']}` 🪙).\n"
                    f"🗑️ Ce salon sera supprimé dans 5 minutes."
                ) if victory else (
                    f"💀 **DÉFAITE.** Le **{boss['title']}** s'enfuit dans les ombres.\n"
                    f"📜 Vous recevez tous une petite consolation.\n"
                    f"_Réessayez la semaine prochaine !_\n"
                    f"🗑️ Salon supprimé dans 5 minutes."
                )
                await ch.send(final_msg)

                async def _cleanup_arena():
                    await asyncio.sleep(300)
                    try:
                        await ch.delete(reason="World Boss event ended")
                    except Exception:
                        pass
                asyncio.create_task(_cleanup_arena())
            except Exception as ex:
                print(f"[_end_world_boss send final] {ex}")
        print(f"[WORLD BOSS END] guild={guild.id} wb_id={wb_id} victory={victory}")
    except Exception as ex:
        print(f"[_end_world_boss] {ex}")


@tasks.loop(minutes=30)
async def world_boss_scheduler():
    """Phase 42 + Phase 95 AMPLIFY : World Boss samedi 21h FR avec pre-hype 30 min avant.

    Tourne toutes les 30 min :
    - 20h30 samedi → broadcast pre-hype "Le World Boss arrive dans 30 min !"
    - 21h00 samedi → lance le World Boss
    """
    try:
        from zoneinfo import ZoneInfo as _ZI
        tz = _ZI('Europe/Paris')
    except Exception:
        tz = timezone.utc
    now_local = datetime.now(tz)
    # Samedi (weekday=5) uniquement
    if now_local.weekday() != 5:
        return
    # Plage 20h-21h pour gérer hype + start
    if now_local.hour not in (20, 21):
        return
    try:
        week_start = (now_local - timedelta(days=now_local.weekday())).strftime('%Y-%m-%d')
        for guild in bot.guilds:
            try:
                c = await cfg(guild.id)
                if not c.get('event_enabled', False):
                    continue
                if not c.get('world_boss_enabled', True):
                    continue
                # Pas 2× la même semaine
                async with get_db() as db:
                    async with db.execute(
                        'SELECT 1 FROM world_bosses WHERE guild_id=? AND DATE(started_at) >= ? LIMIT 1',
                        (guild.id, week_start),
                    ) as cur:
                        already_started = bool(await cur.fetchone())
                if already_started:
                    continue  # already done this week

                # Phase 95 AMPLIFY : Pre-hype broadcast à 20h30
                if now_local.hour == 20 and now_local.minute >= 30:
                    # Anti-doublon : cfg flag par semaine
                    last_hype = c.get('world_boss_last_hype_week', '')
                    if last_hype == week_start:
                        continue  # déjà hypé cette semaine
                    try:
                        hub_id = int(c.get('hub_channel', 0) or 0)
                        hub_ch = guild.get_channel(hub_id) if hub_id else None
                        if hub_ch and await _is_chatty_channel(hub_ch):
                            ping_str = await _get_event_mention(guild, 'world_boss')
                            try:
                                wakeup_line = await _build_wakeup_mention_line_smart(
                                    guild, 'world_boss', max_count=3,
                                )
                            except Exception:
                                wakeup_line = ""
                            # Calc target ts (21h ce soir)
                            target_dt = now_local.replace(hour=21, minute=0, second=0, microsecond=0)
                            target_ts = int(target_dt.timestamp())
                            hype_msg = (
                                f"🌍 ⚠️ **WORLD BOSS HEBDOMADAIRE — DANS 30 MINUTES** ⚠️\n"
                                + (f"{ping_str}\n" if ping_str else "")
                                + wakeup_line
                                + f"\n⏰ Apparition : <t:{target_ts}:R>\n"
                                f"💪 Préparez votre équipement, votre vocal et votre classe RP !\n"
                                f"🏆 Top 3 attaquants : récompense légendaire\n"
                                f"💎 1% chance loot unique pour le top damager\n"
                                f"⏱️ Durée : **90 minutes** — coordination collective requise\n\n"
                                f"_Pas envie d'être ping ? `/notifs` pour gérer._"
                            )
                            LIFETIME_HYPE = 3600  # 1h (cover 20h30 → 21h30)
                            try:
                                hm = await hub_ch.send(
                                    hype_msg,
                                    allowed_mentions=discord.AllowedMentions(
                                        roles=True, users=True, everyone=False,
                                    ),
                                    delete_after=LIFETIME_HYPE,
                                )
                                try:
                                    await _register_for_cleanup(hm, LIFETIME_HYPE, 'world_boss_hype')
                                except Exception:
                                    pass
                            except Exception as ex:
                                print(f"[world_boss pre-hype send] {ex}")
                            # Marquer hype envoyé cette semaine
                            await db_set(guild.id, 'world_boss_last_hype_week', week_start)
                            print(f"[world_boss_scheduler] guild={guild.id} pre-hype 20h30 envoyé")
                    except Exception as ex:
                        print(f"[world_boss pre-hype] {ex}")
                    continue  # skip start cycle for this 20h30 tick

                # 21h : start le World Boss
                if now_local.hour == 21:
                    # Pas si un autre event majeur en cours
                    if await _has_any_major_event_running(guild.id):
                        continue
                    result = await _start_world_boss(guild)
                    if result.get('ok'):
                        print(f"[world_boss_scheduler] guild={guild.id} lancé à 21h")
            except Exception as ex:
                print(f"[world_boss_scheduler guild={guild.id}] {ex}")
    except Exception as ex:
        print(f"[world_boss_scheduler] {ex}")


@world_boss_scheduler.before_loop
async def _world_boss_wait():
    await bot.wait_until_ready()


@tasks.loop(minutes=5)
async def world_boss_timeout_checker():
    """Termine les world boss expirés (90 min)."""
    try:
        now_iso = datetime.now(timezone.utc).isoformat()
        async with get_db() as db:
            async with db.execute(
                'SELECT id, guild_id FROM world_bosses WHERE ended=0 AND ends_at < ?',
                (now_iso,),
            ) as cur:
                rows = await cur.fetchall()
        for wb_id, gid in rows:
            guild = bot.get_guild(int(gid))
            if guild:
                await _end_world_boss(guild, wb_id, victory=False, reason="timeout")
    except Exception as ex:
        print(f"[world_boss_timeout_checker] {ex}")


@world_boss_timeout_checker.before_loop
async def _wb_timeout_wait():
    await bot.wait_until_ready()


# ═══════════════════════════════════════════════════════════════════════════════
# VOICE CHAOS — perturbation aléatoire des vocaux en soirée
# ═══════════════════════════════════════════════════════════════════════════════


async def _apply_voice_chaos(guild) -> bool:
    """Applique une action de chaos à un vocal aléatoire du serveur.

    Garanties :
    - Skip les vocaux protégés (cfg voice_protected_channels)
    - Skip les vocaux vides (au moins 1 membre humain dedans)
    - Skip les vocaux déjà touchés dans les dernières 2h
    - Effet temporaire et toujours réversible
    """
    try:
        c = await cfg(guild.id)
        if not c.get('voice_chaos_enabled', True):
            return False

        protected = await _get_protected_voice_channels(guild.id)

        # Trouver les vocaux candidats : non protégés, avec >=1 humain dedans
        candidates = []
        for vc in guild.voice_channels:
            if vc.id in protected:
                continue
            # Skip les vocaux temporaires hubs (créés par le bot)
            name_low = (vc.name or '').lower()
            if any(kw in name_low for kw in ('staff', 'admin', 'mod-', 'fondateur', 'founder', 'private', 'privé')):
                continue
            # Au moins 1 membre humain
            humans = [m for m in vc.members if not m.bot]
            if not humans:
                continue
            # Le bot doit pouvoir manage_channels (pour rename)
            try:
                perms = vc.permissions_for(guild.me)
                if not perms.manage_channels:
                    continue
            except Exception:
                continue
            candidates.append(vc)

        if not candidates:
            return False

        # Skip les vocaux déjà chaos < 2h
        async with get_db() as db:
            async with db.execute(
                'SELECT voice_channel_id FROM voice_chaos_log '
                'WHERE guild_id=? AND applied_at > datetime("now", "-2 hours")',
                (guild.id,),
            ) as cur:
                recent_chaos = {int(r[0]) for r in await cur.fetchall()}
        candidates = [vc for vc in candidates if vc.id not in recent_chaos]
        if not candidates:
            return False

        vc = random.choice(candidates)
        allow_aggressive = bool(c.get('voice_chaos_aggressive', False))
        action = ev42.random_voice_chaos(allow_aggressive=allow_aggressive)

        original_name = vc.name

        if action['kind'] == 'rename':
            new_name = action['rename_pattern'].format(original=original_name[:60])
            try:
                await vc.edit(name=new_name[:100], reason=f"Voice Chaos: {action['name']}")
            except Exception as ex:
                print(f"[voice_chaos rename] {ex}")
                return False

            # Log + programmation du revert
            async with get_db() as db:
                cur = await db.execute(
                    'INSERT INTO voice_chaos_log(guild_id, voice_channel_id, action_id, original_name) '
                    'VALUES(?,?,?,?)',
                    (guild.id, vc.id, action['id'], original_name),
                )
                log_id = cur.lastrowid
                await db.commit()

            duration = int(action.get('duration_seconds', 300) or 300)

            async def _revert():
                await asyncio.sleep(duration)
                try:
                    vc2 = guild.get_channel(vc.id)
                    if vc2:
                        try:
                            await vc2.edit(name=original_name[:100], reason="Voice Chaos revert")
                        except Exception:
                            pass
                except Exception:
                    pass
                try:
                    async with get_db() as db:
                        await db.execute(
                            'UPDATE voice_chaos_log SET reverted=1 WHERE id=?',
                            (log_id,),
                        )
                        await db.commit()
                except Exception:
                    pass

            asyncio.create_task(_revert())
            print(f"[VOICE CHAOS] guild={guild.id} vc={vc.id} action={action['id']} -> {new_name}")

            # Phase 93 AMPLIFY : annonce dans le hub channel pour que tout le monde voie
            # le chaos (les users hors vocal ne comprennent pas pourquoi le nom a changé sinon)
            try:
                hub_id = int(c.get('hub_channel', 0) or 0)
                hub_ch = guild.get_channel(hub_id) if hub_id else None
                if hub_ch and await _is_chatty_channel(hub_ch):
                    minutes_left = max(1, duration // 60)
                    chaos_msg = (
                        f"🎭 **Voice Chaos !**\n"
                        f"_{action.get('name', 'Effet mystère')}_\n\n"
                        f"📍 Vocal touché : `{original_name}` → `{new_name}`\n"
                        f"⏱️ Revient à la normale dans **{minutes_left} min**\n"
                        f"_Restez dans le vocal pour voir l'effet !_"
                    )
                    try:
                        announce_msg = await hub_ch.send(
                            chaos_msg,
                            allowed_mentions=discord.AllowedMentions.none(),
                            delete_after=duration + 60,
                        )
                        try:
                            await _register_for_cleanup(announce_msg, duration + 60, 'voice_chaos')
                        except Exception:
                            pass
                    except Exception:
                        pass
            except Exception as ex:
                print(f"[voice_chaos hub announce] {ex}")

            return True

        # 'shuffle' kind : non implémenté pour éviter de déranger
        return False
    except Exception as ex:
        print(f"[_apply_voice_chaos] {ex}")
        return False


@tasks.loop(minutes=45)
async def voice_chaos_dispatcher():
    """Phase 42 : chaque 45min entre 19h-23h FR, ~40% de chance de chaos vocal.

    Concrètement : 1-2 chaos par soirée en moyenne.
    """
    try:
        from zoneinfo import ZoneInfo as _ZI
        tz = _ZI('Europe/Paris')
    except Exception:
        tz = timezone.utc
    h = datetime.now(tz).hour
    if not (19 <= h < 23):
        return
    if random.random() > 0.4:
        return
    try:
        for guild in bot.guilds:
            try:
                await _apply_voice_chaos(guild)
            except Exception as ex:
                print(f"[voice_chaos_dispatcher guild={guild.id}] {ex}")
    except Exception as ex:
        print(f"[voice_chaos_dispatcher] {ex}")


@voice_chaos_dispatcher.before_loop
async def _voice_chaos_wait():
    await bot.wait_until_ready()


