class RiddleAnswerView(View):
    """View persistante pour répondre à l'énigme du jour. 4 boutons options."""

    def __init__(self):
        super().__init__(timeout=None)
        for idx in range(4):
            b = Button(
                label=f"Option {chr(65 + idx)}",
                style=discord.ButtonStyle.secondary,
                custom_id=f"riddle_ans_{idx}",
            )
            b.callback = self._make_callback(idx)
            self.add_item(b)

    def _make_callback(self, idx: int):
        async def _cb(i: discord.Interaction):
            if not await _safe_defer(i):
                return
            try:
                if not i.guild:
                    return await _safe_followup(i, content="❌ Serveur uniquement.")
                # Récupérer le riddle du jour
                day = _today_str_p41()
                async with get_db() as db:
                    async with db.execute(
                        'SELECT riddle_id, first_winner_id, answered_count FROM daily_riddles_log '
                        'WHERE guild_id=? AND day=?',
                        (i.guild.id, day),
                    ) as cur:
                        row = await cur.fetchone()
                if not row:
                    return await _safe_followup(i, content="❌ Pas d'énigme active aujourd'hui.")
                riddle_id, first_winner, answered = row
                riddle = ev42.get_riddle(riddle_id)
                if not riddle:
                    return await _safe_followup(i, content="❌ Énigme inconnue.")

                if first_winner and first_winner == i.user.id:
                    return await _safe_followup(i, content="✅ Tu as déjà gagné aujourd'hui !")

                is_correct = (idx == riddle['answer_idx'])

                # Marquer la réponse
                async with get_db() as db:
                    if is_correct and not first_winner:
                        # Premier à trouver !
                        await db.execute(
                            'UPDATE daily_riddles_log SET first_winner_id=?, winner_at=CURRENT_TIMESTAMP, '
                            'answered_count=answered_count+1 WHERE guild_id=? AND day=?',
                            (i.user.id, i.guild.id, day),
                        )
                        await db.commit()

                        # Phase 95 AMPLIFY : Streak system
                        # Compter combien de jours CONSÉCUTIFS user a gagné (avant aujourd'hui)
                        streak_count = 1  # aujourd'hui compte
                        try:
                            async with get_db() as db_s:
                                async with db_s.execute(
                                    'SELECT day, first_winner_id FROM daily_riddles_log '
                                    'WHERE guild_id=? AND day<? ORDER BY day DESC LIMIT 30',
                                    (i.guild.id, day),
                                ) as cur_s:
                                    past_rows = await cur_s.fetchall()
                            # Vérifier streak en remontant chronologiquement
                            from datetime import date as _date
                            cur_day = _date.fromisoformat(day)
                            for past_day, past_winner in past_rows:
                                if not past_day:
                                    break
                                try:
                                    past_d = _date.fromisoformat(past_day)
                                except Exception:
                                    break
                                # Doit être le jour précédent
                                if (cur_day - past_d).days != 1:
                                    break
                                if past_winner and int(past_winner) == i.user.id:
                                    streak_count += 1
                                    cur_day = past_d
                                else:
                                    break
                        except Exception as ex:
                            print(f"[riddle streak calc] {ex}")
                            streak_count = 1

                        # Reward base 500 🪙 + bonus streak
                        base_reward = 500
                        streak_bonus = 0
                        if streak_count >= 7:
                            streak_bonus = 1000  # bonus hebdo
                        elif streak_count >= 3:
                            streak_bonus = 300  # bonus mini
                        total_reward = base_reward + streak_bonus

                        try:
                            await add_coins(i.guild.id, i.user.id, total_reward)
                        except Exception:
                            pass
                        # Achievement quiz_correct
                        try:
                            await _incr_stat_p41(i.guild.id, i.user.id, 'quiz_correct', 1)
                        except Exception:
                            pass
                        # Phase 49 : tracking mission active (event_kind='daily_riddle')
                        try:
                            await _track_event_completion_for_missions(
                                i.guild.id, 'daily_riddle', True, [i.user.id],
                            )
                        except Exception as ex:
                            print(f"[riddle mission track] {ex}")

                        # Message de victoire avec streak
                        streak_msg = ""
                        if streak_count >= 7:
                            streak_msg = (
                                f"\n🔥 **STREAK ÉPIQUE ×{streak_count} !** "
                                f"+`{streak_bonus}` 🪙 bonus hebdo !"
                            )
                        elif streak_count >= 3:
                            streak_msg = (
                                f"\n🔥 **Streak ×{streak_count}** "
                                f"(+`{streak_bonus}` 🪙 bonus)"
                            )
                        elif streak_count >= 2:
                            streak_msg = f"\n🔥 Streak ×{streak_count} (continue demain pour +bonus !)"
                        await _safe_followup(
                            i,
                            content=(
                                f"🎉 **BRAVO !** Tu es le premier à trouver !\n"
                                f"💰 **+{total_reward}** 🪙{streak_msg}\n\n"
                                f"_Explication :_ {riddle['explanation']}"
                            ),
                        )
                        # Phase 150.2 : track style solo + saga contribution
                        try:
                            await profile_module.track_action(
                                i.guild.id, i.user.id, "riddle_solve",
                                weight=2,
                            )
                            await saga_module.add_contribution(
                                i.guild.id, i.user.id, 2,
                            )
                        except Exception as ex:
                            print(f"[riddle profile/saga] {ex}")
                        # Phase 153 : reputation + mentor
                        try:
                            await reputation_module.add_points(
                                i.guild.id, i.user.id, "riddle_first",
                            )
                            await mentor_bonus_module.on_apprenti_event(
                                i.guild.id, i.user.id, "riddle_first",
                            )
                        except Exception as ex:
                            print(f"[riddle phase153] {ex}")
                        # Phase 146 : boutons de suivi (zéro commande à mémoriser)
                        try:
                            fview = followup_module.build_followup_view(
                                i.user.id, "quiz_win"
                            )
                            if fview is not None:
                                await i.followup.send(
                                    content="_💡 Continue ton aventure :_",
                                    view=fview,
                                    ephemeral=True,
                                )
                        except Exception as ex:
                            print(f"[quiz_win followup_view] {ex}")
                        return
                    else:
                        await db.execute(
                            'UPDATE daily_riddles_log SET answered_count=answered_count+1 '
                            'WHERE guild_id=? AND day=?',
                            (i.guild.id, day),
                        )
                        await db.commit()

                if is_correct:
                    # Bonne réponse mais trop tard
                    try:
                        await add_coins(i.guild.id, i.user.id, 50)
                    except Exception:
                        pass
                    try:
                        await _incr_stat_p41(i.guild.id, i.user.id, 'quiz_correct', 1)
                    except Exception:
                        pass
                    return await _safe_followup(
                        i,
                        content=(
                            f"✅ Bonne réponse ! Mais quelqu'un a été plus rapide.\n"
                            f"💰 **+50** 🪙 (consolation)\n\n"
                            f"_Explication :_ {riddle['explanation']}"
                        ),
                    )
                else:
                    return await _safe_followup(
                        i,
                        content=f"❌ Mauvaise réponse. Réfléchis bien — tu peux re-tenter !",
                    )
            except Exception as ex:
                print(f"[RiddleAnswerView idx={idx}] {ex}")
                await _safe_followup(i, content=f"❌ Erreur : `{ex}`")

        return _cb


async def _post_daily_riddle(guild) -> bool:
    """Poste l'énigme du jour dans le salon hub (ou un salon chatty)."""
    try:
        c = await cfg(guild.id)
        if not c.get('event_enabled', False):
            return False
        if not c.get('daily_riddle_enabled', True):
            return False

        day = _today_str_p41()
        # Déjà posté aujourd'hui ?
        async with get_db() as db:
            async with db.execute(
                'SELECT 1 FROM daily_riddles_log WHERE guild_id=? AND day=?',
                (guild.id, day),
            ) as cur:
                if await cur.fetchone():
                    return False

        # Trouver un salon : hub_channel > 1er salon chatty
        hub_id = int(c.get('hub_channel', 0) or 0)
        ch = guild.get_channel(hub_id) if hub_id else None
        if ch and not await _is_chatty_channel(ch):
            ch = None
        if not ch:
            # Fallback : 1er salon chatty avec "general" ou "chat" dans le nom
            for cand in guild.text_channels:
                if not await _is_chatty_channel(cand):
                    continue
                name_low = (cand.name or '').lower()
                if any(kw in name_low for kw in ('general', 'général', 'chat', 'discussion')):
                    ch = cand
                    break
            if not ch:
                for cand in guild.text_channels:
                    if await _is_chatty_channel(cand):
                        ch = cand
                        break
        if not ch:
            return False

        riddle = ev42.random_riddle()
        options_str = "\n".join(
            f"{chr(65 + idx)}. {opt}" for idx, opt in enumerate(riddle['options'])
        )
        # Durée de vie : 22h (le message reste presque toute la journée puis se purge)
        LIFETIME = 22 * 3600
        e = discord.Embed(
            title="🧠 Énigme du jour",
            description=(
                f"{riddle['question']}\n\n"
                f"**Choix :**\n{options_str}\n\n"
                f"🎁 **Premier à trouver : +500 🪙**\n"
                f"_Les bonnes réponses suivantes : +50 🪙 chacune._\n\n"
                f"{_chrono_footer(LIFETIME)}"
            ),
            color=0x9B59B6,
            timestamp=datetime.now(timezone.utc),
        )
        e.set_footer(text=f"Énigme du {day}")

        view = RiddleAnswerView()
        try:
            msg = await ch.send(
                embed=e, view=view,
                allowed_mentions=discord.AllowedMentions.none(),
                delete_after=LIFETIME,
            )
            # Phase 47.3 : backup persistant DB
            await _register_for_cleanup(msg, LIFETIME, 'daily_riddle')
        except Exception as ex:
            print(f"[_post_daily_riddle send] {ex}")
            return False

        # Logger en DB
        try:
            async with get_db() as db:
                await db.execute(
                    'INSERT INTO daily_riddles_log(guild_id, day, riddle_id, channel_id, message_id) '
                    'VALUES(?,?,?,?,?)',
                    (guild.id, day, riddle['id'], ch.id, msg.id),
                )
                await db.commit()
        except Exception as ex:
            print(f"[_post_daily_riddle db log] {ex}")

        try: await _track_event_engagement(guild.id, 'daily_riddle', 'start')
        except Exception: pass
        print(f"[DAILY RIDDLE] guild={guild.id} riddle={riddle['id']} ch={ch.id}")
        return True
    except Exception as ex:
        print(f"[_post_daily_riddle] {ex}")
        return False


