# ─── LOOTS UNIQUES (drop random pendant events) ──────────────────────────────


async def _maybe_drop_unique_loot(guild_id: int, user_id: int, event_kind: str, drop_chance: float = 0.01):
    """Pendant un event, X% chance qu'un user drop un loot unique."""
    if random.random() > drop_chance:
        return None
    # Pool de loots uniques possibles (par event_kind)
    loot_pool = {
        "world_boss": [
            ("⚔️ L'Épée Brisée du Premier Colosse", "Une lame qui a vu trois siècles. Légendaire."),
            ("🛡️ Le Bouclier du Gardien", "Aucune flèche ne l'a jamais traversé."),
            ("💎 Le Cristal de l'Arc Ancien", "Brille même dans l'obscurité totale."),
        ],
        "boss_raid": [
            ("🗡️ La Dague d'Ombre", "Trouvée dans le sang du Boss tombé."),
            ("📜 Le Parchemin Maudit", "Personne n'ose le lire."),
        ],
        "treasure": [
            ("🏆 La Couronne Oubliée", "Belle. Trop belle."),
            ("💍 L'Anneau du Mendiant", "Plus précieux qu'il n'en a l'air."),
        ],
    }
    pool = loot_pool.get(event_kind, [])
    if not pool:
        return None
    name, desc = random.choice(pool)
    # Insert (1 seul exemplaire au monde par name)
    try:
        async with get_db() as db:
            # Check si ce loot existe déjà
            async with db.execute(
                "SELECT id, current_owner_id FROM unique_loots WHERE guild_id=? AND name=?",
                (guild_id, name),
            ) as cur:
                existing = await cur.fetchone()
        if existing:
            # Loot existe déjà → transfer (l'ancien owner perd, le nouveau gagne)
            loot_id, old_owner = int(existing[0]), int(existing[1] or 0)
            if old_owner == user_id:
                return None  # Déjà à toi
            async with get_db() as db:
                await db.execute(
                    "UPDATE unique_loot_history SET released_at=CURRENT_TIMESTAMP "
                    "WHERE loot_id=? AND owner_id=? AND released_at IS NULL",
                    (loot_id, old_owner),
                )
                await db.execute(
                    "INSERT INTO unique_loot_history(loot_id, owner_id) VALUES(?, ?)",
                    (loot_id, user_id),
                )
                await db.execute(
                    "UPDATE unique_loots SET current_owner_id=?, obtained_at=CURRENT_TIMESTAMP "
                    "WHERE id=?",
                    (user_id, loot_id),
                )
                await db.commit()
            return {"id": loot_id, "name": name, "desc": desc, "stolen_from": old_owner, "new": False}
        else:
            # Nouveau loot
            async with get_db() as db:
                cur = await db.execute(
                    "INSERT INTO unique_loots(guild_id, name, description, current_owner_id, event_kind) "
                    "VALUES(?, ?, ?, ?, ?)",
                    (guild_id, name, desc, user_id, event_kind),
                )
                loot_id = cur.lastrowid
                await db.execute(
                    "INSERT INTO unique_loot_history(loot_id, owner_id) VALUES(?, ?)",
                    (loot_id, user_id),
                )
                await db.commit()
            return {"id": int(loot_id), "name": name, "desc": desc, "stolen_from": None, "new": True}
    except Exception as ex:
        print(f"[_maybe_drop_unique_loot] {ex}")
        return None


@bot.tree.command(
    name="loots",
    description="💎 Voir tes loots uniques (1 exemplaire au monde chacun)",
)
async def loots_cmd(i: discord.Interaction):
    """Phase 95 AMPLIFY : Loots uniques en LayoutView V2 magnifique."""
    if not i.guild:
        return await i.response.send_message("❌ Serveur uniquement.", ephemeral=True)
    if not await _safe_defer(i):
        return
    try:
        async with get_db() as db:
            async with db.execute(
                "SELECT id, name, description, rarity, event_kind, obtained_at FROM unique_loots "
                "WHERE guild_id=? AND current_owner_id=? ORDER BY obtained_at DESC",
                (i.guild.id, i.user.id),
            ) as cur:
                rows = await cur.fetchall()

        _user_name = i.user.display_name

        if not rows:
            class _LootsEmptyLayout(LayoutView):
                def __init__(self):
                    super().__init__(timeout=600)
                    items = [
                        v2_title(f"💎  LOOTS UNIQUES  ·  {_user_name}"),
                        v2_subtitle("Items 1 exemplaire au monde · Drop ultra rare"),
                        v2_divider(),
                        v2_body(
                            "**╔═══ 🪙  AUCUN LOOT  ═══╗**\n"
                            "_Tu ne possèdes aucun loot unique pour l'instant._"
                        ),
                        v2_divider(),
                        v2_body(
                            "**╔═══ ℹ️  COMMENT EN OBTENIR  ═══╗**\n"
                            "💀 **World Boss** : ~10% pour le Top Damager\n"
                            "⚔️ **Boss Raid** : drop chance variable\n"
                            "💎 **Treasure Hunt** : items mythiques rares\n\n"
                            "_**1 seul exemplaire au monde** par item._\n"
                            "_Si quelqu'un d'autre le re-drop, il te le vole._"
                        ),
                    ]
                    self.add_item(v2_container(*items, color=0x95A5A6))
            return await _safe_followup(i, view=_LootsEmptyLayout())

        # Build loot lines grouped by rarity
        rarity_order = {'mythique': 0, 'légendaire': 1, 'epique': 2, 'épique': 2, 'rare': 3, 'commune': 4}
        rarity_emojis = {
            'mythique': '🌌', 'légendaire': '⭐', 'epique': '💜',
            'épique': '💜', 'rare': '💎', 'commune': '⚪',
        }
        loot_groups: dict = {}
        for r in rows:
            lid, lname, ldesc, lrarity, levent_kind, lobt = r
            rar = (lrarity or 'commune').lower()
            loot_groups.setdefault(rar, []).append((lid, lname, ldesc, levent_kind, lobt))

        sorted_rarities = sorted(loot_groups.keys(), key=lambda r: rarity_order.get(r, 99))

        class _LootsLayout(LayoutView):
            def __init__(self):
                super().__init__(timeout=600)
                items = []
                items.append(v2_title(f"💎  LOOTS UNIQUES  ·  {_user_name}"))
                items.append(v2_subtitle(f"`{len(rows)}` items uniques au monde"))
                items.append(v2_divider())

                for rar in sorted_rarities:
                    rar_emoji = rarity_emojis.get(rar, '⚪')
                    group_items = loot_groups[rar]
                    items.append(v2_body(
                        f"**╔═══ {rar_emoji}  {rar.upper()} ({len(group_items)})  ═══╗**"
                    ))
                    lines = []
                    for lid, lname, ldesc, levent_kind, lobt in group_items[:8]:
                        ev_tag = f" · _via {levent_kind}_" if levent_kind else ""
                        lines.append(f"`#{lid}` **{lname}**\n   _{ldesc[:120]}_{ev_tag}")
                    items.append(v2_body("\n\n".join(lines)))
                    if len(group_items) > 8:
                        items.append(v2_body(f"_… + {len(group_items) - 8} autre(s) {rar}_"))
                    items.append(v2_divider())

                items.append(v2_body(
                    "_💡 1 exemplaire au monde par item. "
                    "Si quelqu'un re-drop le même → tu te le fais voler._"
                ))

                # Color based on highest rarity
                top_color = 0xFFD700 if 'mythique' in loot_groups else (
                    0xFFA500 if 'légendaire' in loot_groups else 0x5865F2
                )
                self.add_item(v2_container(*items, color=top_color))

        await _safe_followup(i, view=_LootsLayout())
    except Exception as ex:
        print(f"[/loots V2] {ex}")
        await _safe_followup(i, content=f"❌ Erreur : `{ex}`")


