@bot.tree.command(
    name="duel_report",
    description="⚔️ Reporter le gagnant d'un duel actif (perdant valide)",
)
@app_commands.describe(duel_id="ID du duel", gagnant="Membre qui a gagné")
async def duel_report_cmd(i: discord.Interaction, duel_id: int, gagnant: discord.Member):
    if not i.guild:
        return await i.response.send_message("❌ Serveur uniquement.", ephemeral=True)
    if not await _safe_defer(i):
        return
    try:
        async with get_db() as db:
            async with db.execute(
                "SELECT challenger_id, challenged_id, stake_amount, status FROM pvp_duels WHERE id=?",
                (duel_id,),
            ) as cur:
                row = await cur.fetchone()
        if not row or row[3] != 'active':
            return await _safe_followup(i, content="⏱️ Duel inexistant ou pas actif.")
        ch_id, cd_id, stake = int(row[0]), int(row[1]), int(row[2])
        # Le reporter doit être le PERDANT (par fair-play) ou owner/staff
        is_staff = (i.user.id == i.guild.owner_id or i.user.id == SUPER_OWNER_ID)
        if not is_staff:
            try:
                perms = i.channel.permissions_for(i.user)
                is_staff = perms.manage_messages
            except Exception:
                pass
        # Valid reporter : un des 2 participants ou staff
        if i.user.id not in (ch_id, cd_id) and not is_staff:
            return await _safe_followup(i, content="🔒 Seuls les participants ou le staff peuvent reporter.")
        if gagnant.id not in (ch_id, cd_id):
            return await _safe_followup(i, content="❌ Le gagnant doit être un des participants.")
        loser_id = cd_id if gagnant.id == ch_id else ch_id
        # Payout : winner reçoit 2 * stake
        try:
            await add_coins(i.guild.id, gagnant.id, stake * 2)
        except Exception:
            pass
        # Apply Elo
        elo_result = await _apply_duel_result(i.guild.id, gagnant.id, loser_id)
        async with get_db() as db:
            await db.execute(
                "UPDATE pvp_duels SET status='resolved', winner_id=?, "
                "resolved_at=CURRENT_TIMESTAMP WHERE id=?",
                (gagnant.id, duel_id),
            )
            await db.commit()
        _winner = gagnant
        _loser_member = i.guild.get_member(loser_id)
        _loser_name = _loser_member.display_name if _loser_member else f"User {loser_id}"
        _payout = stake * 2 if stake > 0 else 0
        _elo = elo_result

        class _DuelReportLayout(LayoutView):
            def __init__(self):
                super().__init__(timeout=300)
                items = []
                items.append(v2_title("⚔️  DUEL RÉSOLU"))
                items.append(v2_subtitle(f"**{_winner.display_name}** remporte le duel **#{duel_id}**"))
                items.append(v2_divider())
                items.append(v2_body("**╔═══ 🏆  VAINQUEUR  ═══╗**"))
                items.append(v2_body(
                    f"**Gagnant :** {_winner.mention}\n"
                    f"**Perdant :** {_loser_name}\n"
                    f"**Duel ID :** `#{duel_id}`"
                ))
                if _payout > 0:
                    items.append(v2_divider())
                    items.append(v2_body("**╔═══ 💰  RÉCOMPENSE  ═══╗**"))
                    items.append(v2_body(
                        f"**+{_payout}** 🪙 versés à {_winner.display_name}\n"
                        f"_(les 2 mises de `{stake}` 🪙 cumulées)_"
                    ))
                if _elo:
                    delta_w = _elo['new_w'] - _elo['old_w']
                    delta_l = _elo['new_l'] - _elo['old_l']
                    items.append(v2_divider())
                    items.append(v2_body("**╔═══ 📊  ELO LADDER  ═══╗**"))
                    items.append(v2_body(
                        f"📈 **{_winner.display_name}** : `{_elo['old_w']}` → `{_elo['new_w']}` (+{delta_w})\n"
                        f"📉 **{_loser_name}** : `{_elo['old_l']}` → `{_elo['new_l']}` ({delta_l})"
                    ))
                items.append(v2_divider())
                items.append(v2_body("_Consulte le classement avec `/pvp_top` ou défie quelqu'un avec `/duel`._"))
                self.add_item(v2_container(*items, color=0xE74C3C))

        await _safe_followup(i, view=_DuelReportLayout())

        # Phase 150.2 : track style PvP + saga contribution pour le winner
        try:
            await profile_module.track_action(
                i.guild.id, gagnant.id, "duel_win", weight=3,
            )
            await profile_module.track_action(
                i.guild.id, loser_id, "duel_loss", weight=1,
            )
            await saga_module.add_contribution(
                i.guild.id, gagnant.id, 3,
            )
        except Exception as ex:
            print(f"[duel profile/saga] {ex}")

        # Phase 153 : reputation + mentor (gagnant uniquement)
        try:
            await reputation_module.add_points(
                i.guild.id, gagnant.id, "duel_win",
            )
            await mentor_bonus_module.on_apprenti_event(
                i.guild.id, gagnant.id, "duel_win",
            )
        except Exception as ex:
            print(f"[duel phase153] {ex}")

        # Phase 146 : boutons de suivi pour le winner (zéro commande à mémoriser)
        try:
            winner_member = i.guild.get_member(gagnant.id)
            if winner_member and i.channel:
                summary = (
                    f"✅ Tu as remporté le duel **#{duel_id}** "
                    f"contre **{_loser_name}** !"
                )
                if _payout > 0:
                    summary += f"\n💰 +`{_payout}` 🪙 dans ta cagnotte."
                await followup_module.followup_send(
                    i.channel, winner_member, "duel_win", summary,
                    title="⚔️  VICTOIRE DUEL",
                    color=0xE74C3C,
                    delete_after=180,
                )
        except Exception as ex:
            print(f"[duel_report followup_send] {ex}")
    except Exception as ex:
        await _safe_followup(i, content=f"❌ Erreur : `{ex}`")


@bot.tree.command(
    name="pvp_top",
    description="📊 Voir le top 10 du Ladder Elo PvP",
)
async def pvp_top_cmd(i: discord.Interaction):
    if not i.guild:
        return await i.response.send_message("❌ Serveur uniquement.", ephemeral=True)
    if not await _safe_defer(i):
        return
    try:
        async with get_db() as db:
            async with db.execute(
                "SELECT user_id, rating, wins, losses FROM ladder_ratings "
                "WHERE guild_id=? AND (wins+losses)>0 ORDER BY rating DESC LIMIT 10",
                (i.guild.id,),
            ) as cur:
                rows = await cur.fetchall()
        if not rows:
            return await _safe_followup(i, content="_Personne n'a encore fait de duel._")
        lines = []
        medals = ["🥇", "🥈", "🥉"]
        for idx, r in enumerate(rows):
            m = i.guild.get_member(int(r[0]))
            mname = m.display_name if m else f"User {r[0]}"
            mark = medals[idx] if idx < 3 else f"`{idx+1:02d}`"
            wr = (int(r[2]) / max(1, int(r[2]) + int(r[3]))) * 100
            lines.append(
                f"{mark} **{mname}** — {_rating_division(int(r[1]))} `{int(r[1])}` "
                f"(W:{int(r[2])} L:{int(r[3])} · {wr:.0f}% WR)"
            )
        my = await _get_ladder_rating(i.guild.id, i.user.id)
        _ranking_text = "\n".join(lines)
        _my_text = (
            f"{_rating_division(my['rating'])} `{my['rating']}` "
            f"(W:{my['wins']} L:{my['losses']})"
        )

        class _PvpTopLayout(LayoutView):
            def __init__(self):
                super().__init__(timeout=300)
                items = []
                items.append(v2_title("📊  LADDER ELO PVP — TOP 10"))
                items.append(v2_subtitle("Les meilleurs duellistes du serveur — saison en cours."))
                items.append(v2_divider())
                items.append(v2_body("**╔═══ 🏆  TOP 10  ═══╗**"))
                items.append(v2_body(_ranking_text[:3500]))
                items.append(v2_divider())
                items.append(v2_body("**╔═══ 👤  TON RANG  ═══╗**"))
                items.append(v2_body(_my_text))
                items.append(v2_divider())
                items.append(v2_body("_Lance un duel via `/duel @membre mise:50` pour grimper._"))
                self.add_item(v2_container(*items, color=0xE91E63))

        await _safe_followup(i, view=_PvpTopLayout())
    except Exception as ex:
        await _safe_followup(i, content=f"❌ Erreur : `{ex}`")


